  1→# @logseal/node
  2→
  3→Official Node.js SDK for [LogSeal](https://logseal.io) — Audit logging for B2B SaaS.
  4→
  5→## Installation
  6→
  7→```bash
  8→npm install @logseal/node
  9→# or
 10→pnpm add @logseal/node
 11→# or
 12→yarn add @logseal/node
 13→```
 14→
 15→## Quick Start
 16→
 17→```typescript
 18→import { LogSeal } from '@logseal/node';
 19→
 20→const logseal = new LogSeal({
 21→  apiKey: 'sk_test_...',
 22→});
 23→
 24→// Emit an event (batched, async)
 25→await logseal.emit({
 26→  action: 'document.published',
 27→  organizationId: 'org_acme',
 28→  actor: {
 29→    id: 'user_123',
 30→    name: 'Jane Smith',
 31→    email: 'jane@acme.com',
 32→  },
 33→  targets: [{
 34→    type: 'document',
 35→    id: 'doc_456',
 36→    name: 'Q3 Report',
 37→  }],
 38→  metadata: {
 39→    previousStatus: 'draft',
 40→  },
 41→});
 42→
 43→// Emit and wait for confirmation
 44→const event = await logseal.emitSync({
 45→  action: 'user.deleted',
 46→  organizationId: 'org_acme',
 47→  actor: { id: 'admin_1' },
 48→  targets: [{ type: 'user', id: 'user_123' }],
 49→});
 50→console.log('Event ID:', event.id);
 51→
 52→// Query events
 53→const events = await logseal.events.list({
 54→  organizationId: 'org_acme',
 55→  action: 'document.published',
 56→  limit: 50,
 57→});
 58→
 59→// Auto-paginate through all events
 60→for await (const event of logseal.events.listAll({
 61→  organizationId: 'org_acme',
 62→})) {
 63→  console.log(event.action, event.actor.name);
 64→}
 65→
 66→// Graceful shutdown (flushes remaining events)
 67→process.on('SIGTERM', async () => {
 68→  await logseal.shutdown();
 69→  process.exit(0);
 70→});
 71→```
 72→
 73→## Configuration
 74→
 75→```typescript
 76→const logseal = new LogSeal({
 77→  apiKey: 'sk_live_...', // Required
 78→  baseUrl: 'https://api.logseal.io', // Optional, default
 79→  batchSize: 100, // Events to batch before sending
 80→  flushIntervalMs: 5000, // Max time to wait before flushing
 81→  maxRetries: 3, // Retry attempts for failed requests
 82→});
 83→```
 84→
 85→## API Reference
 86→
 87→### Events
 88→
 89→```typescript
 90→// Emit (batched)
 91→await logseal.emit({ action, organizationId, actor, ... });
 92→
 93→// Emit (sync)
 94→const event = await logseal.emitSync({ action, organizationId, actor, ... });
 95→
 96→// List events
 97→const events = await logseal.events.list({ organizationId, action?, limit? });
 98→
 99→// Get single event
100→const event = await logseal.events.get('evt_123');
101→
102→// Verify hash chain integrity
103→const result = await logseal.events.verify({ organizationId });
104→```
105→
106→### Organizations
107→
108→```typescript
109→const orgs = await logseal.organizations.list();
110→const org = await logseal.organizations.create({ externalId: 'acme', name: 'Acme Corp' });
111→const org = await logseal.organizations.get('org_123');
112→```
113→
114→### Schemas
115→
116→```typescript
117→const schemas = await logseal.schemas.list();
118→const schema = await logseal.schemas.create({ action: 'document.updated', ... });
119→const schema = await logseal.schemas.update('sch_123', { description: '...' });
120→await logseal.schemas.delete('sch_123');
121→```
122→
123→### Viewer Tokens
124→
125→```typescript
126→const token = await logseal.viewerTokens.create({
127→  organizationId: 'org_acme',
128→  expiresIn: 3600, // 1 hour
129→});
130→// Pass token.token to your frontend for the embeddable viewer
131→```
132→
133→### Webhooks
134→
135→```typescript
136→const webhooks = await logseal.webhooks.list();
137→const webhook = await logseal.webhooks.create({ url: 'https://...', events: ['*'] });
138→await logseal.webhooks.update('whk_123', { enabled: false });
139→await logseal.webhooks.delete('whk_123');
140→```
141→
142→### Exports
143→
144→```typescript
145→const exportJob = await logseal.exports.create({
146→  organizationId: 'org_acme',
147→  format: 'csv',
148→  filters: { after: '2024-01-01' },
149→});
150→
151→// Poll until complete
152→const completed = await logseal.exports.poll(exportJob.id);
153→console.log('Download URL:', completed.download_url);
154→```
155→
156→## Error Handling
157→
158→```typescript
159→import { LogSeal, LogSealError } from '@logseal/node';
160→
161→try {
162→  await logseal.emitSync({ ... });
163→} catch (error) {
164→  if (error instanceof LogSealError) {
165→    console.error('LogSeal error:', error.code, error.message);
166→    console.error('Status:', error.statusCode);
167→  }
168→}
169→```
