 1→import { pgTable, text, timestamp, boolean, integer, jsonb, uniqueIndex } from 'drizzle-orm/pg-core';
 2→import { createPlanId } from '@logseal/utils';
 3→
 4→export interface PlanEntitlements {
 5→  eventsPerMonth: number; // -1 = unlimited
 6→  organizations: number;
 7→  apiKeys: number;
 8→  webhooks: number;
 9→  exports: number;
10→  retentionDays: number;
11→  features: string[]; // e.g. ["hash_verification", "custom_schemas"]
12→}
13→
14→export const plans = pgTable(
15→  'plans',
16→  {
17→    id: text('id').primaryKey().$defaultFn(createPlanId),
18→    name: text('name').notNull(),
19→    slug: text('slug').notNull().unique(),
20→    stripePriceId: text('stripe_price_id'),
21→    stripeProductId: text('stripe_product_id'),
22→    isDefault: boolean('is_default').notNull().default(false),
23→    sortOrder: integer('sort_order').notNull().default(0),
24→    entitlements: jsonb('entitlements').$type<PlanEntitlements>().notNull(),
25→    active: boolean('active').notNull().default(true),
26→    createdAt: timestamp('created_at', { withTimezone: true }).notNull().defaultNow(),
27→    updatedAt: timestamp('updated_at', { withTimezone: true }).notNull().defaultNow(),
28→  },
29→  (table) => [uniqueIndex('idx_plans_slug').on(table.slug)]
30→);
31→
32→export type Plan = typeof plans.$inferSelect;
33→export type NewPlan = typeof plans.$inferInsert;
