  1→/**
  2→ * Seed script for local development
  3→ * Creates test accounts with API keys, organizations, events, webhooks, schemas, and usage records
  4→ *
  5→ * Run with: pnpm tsx scripts/seed.ts
  6→ */
  7→
  8→import {
  9→  accounts,
 10→  apiKeys,
 11→  auditEvents,
 12→  createDb,
 13→  eq,
 14→  eventSchemas,
 15→  organizations,
 16→  plans,
 17→  subscriptions,
 18→  usageRecords,
 19→  webhooks,
 20→} from '@logseal/database';
 21→import {
 22→  computeEventHash,
 23→  createPlanId,
 24→  createSubscriptionId,
 25→  createUsageRecordId,
 26→  generateApiKey,
 27→  getKeyLastFour,
 28→  getKeyPrefix,
 29→  sha256,
 30→} from '@logseal/utils';
 31→import * as argon2 from 'argon2';
 32→import 'dotenv/config';
 33→
 34→// ─── Types ─────────────────────────────────────────────────────────────────
 35→
 36→interface OrgDef {
 37→  externalId: string;
 38→  name: string;
 39→}
 40→
 41→interface SchemaDef {
 42→  action: string;
 43→  description: string;
 44→  targetTypes: string[];
 45→}
 46→
 47→interface AccountSeed {
 48→  email: string;
 49→  password: string;
 50→  companyName: string;
 51→  planSlug: 'free' | 'pro' | 'business';
 52→  orgs: { test: OrgDef[]; live: OrgDef[] };
 53→  apiKeysPerEnv: number;
 54→  webhookCount: number;
 55→  schemas: SchemaDef[];
 56→  eventsPerOrg: number;
 57→}
 58→
 59→// ─── Constants ─────────────────────────────────────────────────────────────
 60→
 61→const DEV_PASSWORD = 'password123';
 62→const E2E_PASSWORD = 'testpassword123';
 63→
 64→const EVENT_TEMPLATES = [
 65→  { action: 'user.created', actorType: 'user', targetType: 'user' },
 66→  { action: 'user.updated', actorType: 'user', targetType: 'user' },
 67→  { action: 'user.deleted', actorType: 'admin', targetType: 'user' },
 68→  { action: 'document.created', actorType: 'user', targetType: 'document' },
 69→  { action: 'document.updated', actorType: 'user', targetType: 'document' },
