  41→  action: z.string().min(1).max(256),
  42→  organization_id: z.string().min(1).max(256).optional(),
  43→  actor: actorSchema,
  44→  targets: z.array(targetSchema).optional().default([]),
  45→  metadata: z.record(z.unknown()).optional().default({}).refine(
  46→    (val) => JSON.stringify(val).length <= 65536,
  47→    { message: 'Metadata must not exceed 64KB when serialized' }
  48→  ),
  49→  context: contextSchema.optional(),
  50→  occurred_at: z.string().datetime().optional(),
  51→  idempotency_key: z.string().max(256).optional(),
  52→});
  53→
  54→const batchEmitSchema = z.object({
  55→  events: z.array(z.unknown()).min(1).max(1000),
  56→});
  57→
  58→const listEventsSchema = z.object({
  59→  organization_id: z.string().min(1).optional(),
  60→  action: z.string().optional(),
  61→  action_prefix: z.string().optional(),
  62→  actor_id: z.string().optional(),
  63→  target_type: z.string().optional(),
  64→  target_id: z.string().optional(),
  65→  after: z.string().datetime().optional(),
  66→  before: z.string().datetime().optional(),
  67→  search: z.string().optional(),
  68→  limit: z.coerce.number().min(1).max(100).optional().default(25),
  69→  starting_after: z.string().optional(),  // Cursor for next page
  70→  ending_before: z.string().optional(),   // Cursor for previous page
  71→});
