 696→    if (!predecessor) {
 697→      return reply.send({
 698→        status: 'unverifiable',
 699→        event_id: event.id,
 700→        sequence_number: event.sequenceNumber,
 701→        reason: 'Predecessor event not found',
 702→        verified_at: new Date().toISOString(),
 703→      });
 704→    }
 705→
 706→    const isValid = event.previousHash === predecessor.eventHash;
 707→
 708→    return reply.send({
 709→      status: isValid ? 'valid' : 'tampered',
 710→      event_id: event.id,
 711→      sequence_number: event.sequenceNumber,
 712→      verified_at: new Date().toISOString(),
 713→    });
 714→  });
 715→
 716→  // GET /v1/events/actions - List distinct action types
 717→  fastify.get('/events/actions', async (request, reply) => {
 718→    const account = request.account;
 719→    if (!account) {
 720→      throw errors.missingApiKey();
 721→    }
 722→
 723→    if (account.accountStatus === 'defaulted') {
 724→      throw errors.accountDefaulted();
 725→    }
 726→
 727→    const ds = await getDS(account.accountId);
 728→    const actions = await ds.getDistinctActions(account.accountId, account.environment);
 729→
 730→    return reply.send({
 731→      data: actions,
 732→      object: 'list',
 733→    });
 734→  });
 735→
 736→  // POST /v1/events/verify-range - Verify a range of events using skip-list hashes
 737→  fastify.post('/events/verify-range', async (request, reply) => {
 738→    const account = request.account;
 739→    if (!account) {
 740→      throw errors.missingApiKey();
 741→    }
 742→
 743→    if (account.accountStatus === 'defaulted') {
 744→      throw errors.accountDefaulted();
 745→    }
 746→
 747→    const verifyRangeSchema = z.object({
 748→      organization_id: z.string().min(1).optional(),
 749→      from_sequence: z.number().int().min(1),
 750→      to_sequence: z.number().int().min(1),
 751→    });
 752→
 753→    const { organization_id, from_sequence, to_sequence } = verifyRangeSchema.parse(request.body);
 754→    const rangeOrgExternalId = organization_id || DEFAULT_ORG_EXTERNAL_ID;
 755→
 756→    if (from_sequence > to_sequence) {
 757→      throw errors.invalidFieldValue('from_sequence', 'from_sequence must be less than or equal to to_sequence');
 758→    }
 759→
 760→    // Get organization
 761→    const ds = await getDS(account.accountId);
 762→    const org = await ds.getOrganizationByExternalId(account.accountId, rangeOrgExternalId, account.environment);
 763→
 764→    if (!org) {
 765→      throw errors.notFound('organization');
 766→    }
 767→
 768→    // Fetch the from and to events
 769→    const fromEvent = await ds.getEventBySequenceNumber(org.id, account.accountId, from_sequence);
 770→    const toEvent = await ds.getEventBySequenceNumber(org.id, account.accountId, to_sequence);
 771→
 772→    if (!fromEvent || !toEvent) {
 773→      throw errors.notFound('event');
 774→    }
 775→
 776→    // Check if skip hashes are available for skip-list verification
 777→    if (toEvent.skipHashes && toEvent.skipHashes.length > 0) {
 778→      // Use skip-list path for O(log n) verification
 779→      const { computeSkipVerificationPath } = await import('@logseal/utils');
 780→      const path = computeSkipVerificationPath(from_sequence, to_sequence);
 781→
 782→      // Fetch all events in the path via DataStore
 783→      const pathEventsList = await Promise.all(
 784→        path.map((seq) => ds.getEventBySequenceNumber(org.id, account.accountId, seq))
 785→      );
 786→      const pathEvents = pathEventsList.filter((e): e is NonNullable<typeof e> => e !== null);
 787→
 788→      const eventBySeq = new Map(pathEvents.map((e) => [e.sequenceNumber, e]));
 789→
 790→      // Verify each link in the skip path
 791→      for (let i = 1; i < path.length; i++) {
 792→        const currentSeq = path[i];
 793→        const prevSeq = path[i - 1];
 794→        const currentEvent = eventBySeq.get(currentSeq);
 795→        const prevEvent = eventBySeq.get(prevSeq);
 796→
 797→        if (!currentEvent || !prevEvent) {
 798→          return reply.send({
 799→            status: 'unverifiable',
 800→            reason: `Event at sequence ${!currentEvent ? currentSeq : prevSeq} not found`,
 801→            events_checked: i,
 802→            verified_at: new Date().toISOString(),
 803→          });
 804→        }
 805→
 806→        // Check if currentEvent has a skip hash pointing to prevEvent
 807→        const offset = currentSeq - prevSeq;
 808→        const skipEntry = currentEvent.skipHashes?.find(
 809→          (s) => s.offset === offset && s.seq === prevSeq
 810→        );
 811→
 812→        if (skipEntry) {
 813→          if (skipEntry.hash !== prevEvent.eventHash) {
 814→            return reply.send({
 815→              status: 'broken',
 816→              broken_at_sequence: currentSeq,
 817→              expected_hash: prevEvent.eventHash,
 818→              skip_hash: skipEntry.hash,
 819→              events_checked: path.length,
 820→              verified_at: new Date().toISOString(),
 821→            });
 822→          }
 823→        } else {
 824→          // Fall back to checking direct chain linkage if skip hash not available
 825→          if (offset === 1 && currentEvent.previousHash !== prevEvent.eventHash) {
 826→            return reply.send({
 827→              status: 'broken',
 828→              broken_at_sequence: currentSeq,
 829→              expected_hash: prevEvent.eventHash,
 830→              actual_hash: currentEvent.previousHash,
 831→              events_checked: path.length,
 832→              verified_at: new Date().toISOString(),
 833→            });
 834→          }
 835→        }
 836→      }
 837→
 838→      return reply.send({
 839→        status: 'valid',
 840→        events_checked: path.length,
 841→        verification_method: 'skip_list',
 842→        path_length: path.length,
 843→        range: { from: from_sequence, to: to_sequence },
 844→        verified_at: new Date().toISOString(),
 845→      });
 846→    }
 847→
 848→    // Fallback: sequential walk for pre-migration events without skipHashes
 849→    const BATCH_SIZE = 10_000;
 850→    let expectedPreviousHash: string | null = fromEvent.previousHash;
 851→    let eventsChecked = 0;
 852→    let lastSequence = from_sequence - 1;
 853→
 854→    while (lastSequence < to_sequence) {
 855→      const batch = await ds.getChainBatch(org.id, account.accountId, lastSequence, BATCH_SIZE, undefined, to_sequence);
 856→
 857→      if (batch.length === 0) break;
 858→
 859→      for (const event of batch) {
 860→        if (event.previousHash !== expectedPreviousHash) {
 861→          return reply.send({
 862→            status: 'broken',
 863→            broken_at: event.id,
 864→            broken_at_sequence: event.sequenceNumber,
 865→            expected_hash: expectedPreviousHash,
 866→            actual_hash: event.previousHash,
 867→            events_checked: eventsChecked,
 868→            verified_at: new Date().toISOString(),
 869→          });
 870→        }
 871→        expectedPreviousHash = event.eventHash;
 872→        eventsChecked++;
 873→      }
 874→
 875→      lastSequence = batch[batch.length - 1].sequenceNumber;
 876→    }
 877→
 878→    return reply.send({
 879→      status: 'valid',
 880→      events_checked: eventsChecked,
 881→      verification_method: 'sequential',
 882→      range: { from: from_sequence, to: to_sequence },
 883→      verified_at: new Date().toISOString(),
 884→    });
 885→  });
 886→
 887→  // POST /v1/events/verify - Verify hash chain integrity with deep content verification
 888→  fastify.post('/events/verify', async (request, reply) => {
 889→    const account = request.account;
 890→    if (!account) {
 891→      throw errors.missingApiKey();
 892→    }
 893→
 894→    const verifyBodySchema = z.object({
 895→      organization_id: z.string().min(1).optional(),
 896→      after: z.string().datetime().optional(),
 897→      before: z.string().datetime().optional(),
 898→    });
 899→
 900→    const { organization_id, after, before } = verifyBodySchema.parse(request.body);
 901→    const verifyOrgExternalId = organization_id || DEFAULT_ORG_EXTERNAL_ID;
 902→
 903→    // Get organization
 904→    const ds = await getDS(account.accountId);
 905→    const org = await ds.getOrganizationByExternalId(account.accountId, verifyOrgExternalId, account.environment);
 906→
 907→    if (!org) {
 908→      throw errors.notFound('organization');
 909→    }
 910→
 911→    // Verify chain in batches to avoid loading all events into memory
 912→    const VERIFY_BATCH_SIZE = 10_000;
 913→    let expectedPreviousHash: string | null = null;
 914→    let eventsChecked = 0;
 915→    let chainStart: string | null = null;
 916→    let chainEnd: string | null = null;
 917→    let lastSequence = 0;
 918→    let isFirstBatch = true;
 919→
 920→    while (true) {
 921→      const dateRange = {
 922→        ...(after && { after: new Date(after) }),
 923→        ...(before && { before: new Date(before) }),
 924→      };
 925→
 926→      // Fetch full event data for deep content verification
 927→      const batch = await ds.getFullEventBatch(
 928→        org.id,
 929→        account.accountId,
 930→        lastSequence,
 931→        VERIFY_BATCH_SIZE,
 932→        Object.keys(dateRange).length > 0 ? dateRange : undefined
 933→      );
 934→
 935→      if (batch.length === 0) break;
 936→
 937→      // On first batch with a date filter, trust the first event's previousHash
 938→      if (isFirstBatch && after) {
 939→        expectedPreviousHash = batch[0].previousHash;
 940→      }
 941→      isFirstBatch = false;
 942→
 943→      if (!chainStart) {
 944→        chainStart = batch[0].id;
 945→      }
 946→
 947→      for (let i = 0; i < batch.length; i++) {
 948→        const event = batch[i];
 949→
 950→        // Chain linkage check
 951→        if (event.previousHash !== expectedPreviousHash) {
 952→          return reply.send({
 953→            status: 'broken',
 954→            events_checked: eventsChecked + i,
 955→            broken_at: event.id,
 956→            expected_hash: expectedPreviousHash,
 957→            actual_hash: event.previousHash,
 958→            verified_at: new Date().toISOString(),
 959→          });
 960→        }
 961→
 962→        // Deep content verification: recompute hash from stored event fields
 963→        // Convert null → undefined so JSON serialization matches the original hash input
 964→        const eventData: EventForHashing = {
 965→          action: event.action,
 966→          actor: {
 967→            id: event.actorId,
 968→            type: event.actorType,
 969→            ...(event.actorName != null && { name: event.actorName }),
 970→            ...(event.actorEmail != null && { email: event.actorEmail }),
 971→            metadata: event.actorMetadata || {},
 972→          },
 973→          targets: event.targets || [],
 974→          metadata: event.metadata || {},
 975→          occurred_at: event.occurredAt.toISOString(),
 976→          organization_id: event.organizationId,
 977→          sequence_number: event.sequenceNumber,
 978→        };
 979→
 980→        const recomputedHash = computeEventHash(event.previousHash, eventData);
 981→        if (recomputedHash !== event.eventHash) {
 982→          return reply.send({
 983→            status: 'content_tampered',
 984→            events_checked: eventsChecked + i,
 985→            tampered_event_id: event.id,
 986→            expected_hash: recomputedHash,
 987→            stored_hash: event.eventHash,
 988→            verified_at: new Date().toISOString(),
 989→          });
 990→        }
 991→
 992→        expectedPreviousHash = event.eventHash;
 993→      }
 994→
 995→      eventsChecked += batch.length;
 996→      chainEnd = batch[batch.length - 1].id;
 997→      lastSequence = batch[batch.length - 1].sequenceNumber;
 998→
 999→      // If we got fewer than VERIFY_BATCH_SIZE, we're done
1000→      if (batch.length < VERIFY_BATCH_SIZE) break;
1001→    }
1002→
1003→    if (eventsChecked === 0) {
1004→      return reply.send({
1005→        status: 'valid',
1006→        content_verified: true,
1007→        events_checked: 0,
1008→        verified_at: new Date().toISOString(),
1009→      });
1010→    }
1011→
1012→    return reply.send({
1013→      status: 'valid',
1014→      content_verified: true,
1015→      events_checked: eventsChecked,
1016→      chain_start: chainStart,
1017→      chain_end: chainEnd,
1018→      verified_at: new Date().toISOString(),
1019→    });
1020→  });
1021→};
