 19→async function main() {
 20→  const databaseUrl = process.env.DATABASE_URL;
 21→  if (!databaseUrl) {
 22→    throw new Error('DATABASE_URL environment variable is required');
 23→  }
 24→
 25→  const redisUrl = process.env.REDIS_URL || 'redis://localhost:6379';
 26→  const concurrency = parseInt(process.env.WORKER_CONCURRENCY || '10', 10);
 27→
 28→  const db = createDb(databaseUrl);
 29→  const dataStoreManager = new DataStoreManager(db, decrypt);
 30→  dataStoreManager.startHealthChecks();
 31→  const redis = new Redis(redisUrl, { maxRetriesPerRequest: null });
 32→
 33→  console.log('🚀 LogSeal Worker starting...');
 34→  console.log(`📊 Concurrency: ${concurrency}`);
 35→
 36→  // Webhook delivery queue
 37→  const webhookQueue = new Queue('webhooks', { connection: redis });
 38→
 39→  // Retention cleanup queue (daily schedule)
 40→  const retentionQueue = new Queue('retention', { connection: redis });
 41→  await retentionQueue.add(
 42→    'retention-cleanup',
 43→    {},
 44→    {
 45→      repeat: {
 46→        pattern: '0 2 * * *', // Run daily at 2 AM
 47→      },
 48→      jobId: 'retention-cleanup-daily',
 49→    },
 50→  );
 51→
 52→  // Merkle tree queue
 53→  const merkleQueue = new Queue('merkle-trees', { connection: redis });
 54→
 55→  // Transparency log anchoring queue
 56→  const transparencyQueue = new Queue('transparency', { connection: redis });
 57→
 58→  // Main event processing worker
 59→  // Note: BullMQ processes jobs in order per queue by default
 60→  // For strict ordering per organization, you could use separate queues
 61→  const eventWorker = new Worker(
 62→    'audit-events',
 63→    async (job) => {
 64→      if (job.name === 'process-event') {
 65→        const dataStore = await dataStoreManager.getDataStore(job.data.accountId);
 66→        return processEventJob(job.data, db, dataStore, webhookQueue, redis, merkleQueue);
 67→      }
 68→      if (job.name === 'process-export') {
 69→        return processExportJob(job.data, db);
 70→      }
 71→      console.warn(`Unknown job type: ${job.name}`);
 72→    },
 73→    {
 74→      connection: redis,
 75→      concurrency,
 76→    }
 77→  );
 78→
 79→  // Retention cleanup worker
 80→  const retentionWorker = new Worker(
 81→    'retention',
 82→    async () => {
 83→      return processRetentionCleanup(db, redis);
 84→    },
 85→    {
 86→      connection: redis,
 87→      concurrency: 1,
 88→    }
 89→  );
 90→
 91→  // Webhook delivery worker
 92→  const webhookWorker = new Worker(
 93→    'webhooks',
 94→    async (job) => {
 95→      return processWebhookJob(job.data, db);
 96→    },
 97→    {
 98→      connection: redis,
 99→      concurrency: 20,
100→    }
101→  );
102→
103→  // Merkle tree construction worker
104→  const merkleWorker = new Worker(
105→    'merkle-trees',
106→    async (job) => {
107→      if (job.name === 'build-merkle-tree') {
108→        return processMerkleJob(job.data, db, transparencyQueue);
109→      }
110→      console.warn(`Unknown merkle job type: ${job.name}`);
111→    },
112→    {
113→      connection: redis,
114→      concurrency: 5,
115→    }
116→  );
117→
118→  // Transparency log anchoring worker
119→  const transparencyWorker = new Worker(
120→    'transparency',
121→    async (job) => {
122→      if (job.name === 'anchor-to-transparency') {
123→        return processTransparencyJob(job.data, db);
124→      }
125→      console.warn(`Unknown transparency job type: ${job.name}`);
126→    },
127→    {
128→      connection: redis,
129→      concurrency: 3,
130→    }
131→  );
132→
133→  // Event handlers
134→  eventWorker.on('completed', (job) => {
135→    console.log(`✅ Event ${job.id} processed`);
136→  });
137→
138→  eventWorker.on('failed', (job, err) => {
139→    console.error(`❌ Event ${job?.id} failed:`, err.message);
140→  });
141→
142→  webhookWorker.on('completed', (job) => {
143→    console.log(`✅ Webhook delivery ${job.id} completed`);
144→  });
145→
146→  webhookWorker.on('failed', (job, err) => {
147→    console.error(`❌ Webhook delivery ${job?.id} failed:`, err.message);
148→  });
149→
150→  retentionWorker.on('completed', (job) => {
151→    console.log(`✅ Retention cleanup ${job.id} completed`);
152→  });
153→
154→  retentionWorker.on('failed', (job, err) => {
155→    console.error(`❌ Retention cleanup ${job?.id} failed:`, err.message);
156→  });
157→
158→  merkleWorker.on('completed', (job) => {
159→    console.log(`✅ Merkle tree ${job.id} built`);
160→  });
161→
162→  merkleWorker.on('failed', (job, err) => {
163→    console.error(`❌ Merkle tree ${job?.id} failed:`, err.message);
164→  });
165→
166→  transparencyWorker.on('completed', (job) => {
167→    console.log(`✅ Transparency anchoring ${job.id} completed`);
168→  });
169→
170→  transparencyWorker.on('failed', (job, err) => {
171→    console.error(`❌ Transparency anchoring ${job?.id} failed:`, err.message);
172→  });
173→
174→  console.log('✅ Workers started');
175→
176→  // Graceful shutdown
177→  const shutdown = async () => {
178→    console.log('Shutting down workers...');
179→    await eventWorker.close();
180→    await webhookWorker.close();
181→    await retentionWorker.close();
182→    await merkleWorker.close();
183→    await transparencyWorker.close();
184→    await dataStoreManager.close();
185→    await webhookQueue.close();
186→    await retentionQueue.close();
187→    await merkleQueue.close();
188→    await transparencyQueue.close();
189→    await redis.quit();
190→    process.exit(0);
191→  };
192→
193→  process.on('SIGTERM', shutdown);
194→  process.on('SIGINT', shutdown);
195→}
196→
197→main().catch((err) => {
198→  console.error('Worker failed to start:', err);
199→  process.exit(1);
200→});
