 1→import { randomBytes } from 'crypto';
 2→
 3→/**
 4→ * Minimal Redis client interface for lock operations.
 5→ * Compatible with ioredis without requiring it as a dependency.
 6→ */
 7→export interface RedisLockClient {
 8→  set(
 9→    key: string,
10→    value: string,
11→    expiryMode: 'PX',
12→    time: number,
13→    setMode: 'NX',
14→  ): Promise<'OK' | null>;
15→  eval(script: string, numkeys: number, ...args: string[]): Promise<unknown>;
16→}
17→
18→interface AcquireResult {
19→  acquired: boolean;
20→  token: string;
21→}
22→
23→const RELEASE_SCRIPT = `
24→if redis.call("get", KEYS[1]) == ARGV[1] then
25→  return redis.call("del", KEYS[1])
26→else
27→  return 0
28→end
29→`;
30→
31→/**
32→ * Acquire a distributed lock using Redis SETNX.
33→ * Returns a token that must be passed to releaseLock.
34→ */
35→export async function acquireLock(
36→  redis: RedisLockClient,
37→  key: string,
38→  ttlMs: number,
39→): Promise<AcquireResult> {
40→  const token = randomBytes(16).toString('hex');
41→  const result = await redis.set(key, token, 'PX', ttlMs, 'NX');
42→  return { acquired: result === 'OK', token };
43→}
44→
45→/**
46→ * Release a distributed lock, but only if we still own it (token matches).
47→ * Uses a Lua script for atomicity.
48→ */
49→export async function releaseLock(
50→  redis: RedisLockClient,
51→  key: string,
52→  token: string,
53→): Promise<boolean> {
54→  const result = await redis.eval(RELEASE_SCRIPT, 1, key, token);
55→  return result === 1;
56→}
57→
58→/**
59→ * Acquire a lock with retry and exponential backoff.
60→ */
61→export async function acquireLockWithRetry(
62→  redis: RedisLockClient,
63→  key: string,
64→  ttlMs: number,
65→  maxAttempts = 3,
66→  baseDelayMs = 100,
67→): Promise<AcquireResult> {
68→  for (let attempt = 0; attempt < maxAttempts; attempt++) {
69→    const result = await acquireLock(redis, key, ttlMs);
70→    if (result.acquired) {
71→      return result;
72→    }
73→    if (attempt < maxAttempts - 1) {
74→      const delay = baseDelayMs * Math.pow(2, attempt);
75→      await new Promise((resolve) => setTimeout(resolve, delay));
76→    }
77→  }
78→  return { acquired: false, token: '' };
79→}
