299→class EventsAPI {
300→  constructor(private client: LogSeal) {}
301→
302→  async list(params: ListEventsParams): Promise<PaginatedList<AuditEvent>> {
303→    const query = new URLSearchParams();
304→    query.set('organization_id', params.organizationId);
305→    if (params.action) query.set('action', params.action);
306→    if (params.actionPrefix) query.set('action_prefix', params.actionPrefix);
307→    if (params.actorId) query.set('actor_id', params.actorId);
308→    if (params.targetType) query.set('target_type', params.targetType);
309→    if (params.targetId) query.set('target_id', params.targetId);
310→    if (params.after) query.set('after', toISOString(params.after)!);
311→    if (params.before) query.set('before', toISOString(params.before)!);
312→    if (params.search) query.set('search', params.search);
313→    if (params.limit) query.set('limit', params.limit.toString());
314→    if (params.cursor) query.set('cursor', params.cursor);
315→
316→    return this.client.request('GET', `/v1/events?${query.toString()}`);
317→  }
318→
319→  async get(id: string): Promise<AuditEvent> {
320→    return this.client.request('GET', `/v1/events/${id}`);
321→  }
322→
323→  async verify(params: VerifyParams): Promise<VerifyResponse> {
324→    return this.client.request('POST', '/v1/events/verify', {
325→      organization_id: params.organizationId,
326→      after: toISOString(params.after),
327→      before: toISOString(params.before),
328→    });
329→  }
330→
331→  async verifyRange(params: VerifyRangeParams): Promise<VerifyRangeResponse> {
332→    return this.client.request('POST', '/v1/events/verify-range', {
333→      organization_id: params.organizationId,
334→      from_sequence: params.fromSequence,
335→      to_sequence: params.toSequence,
336→    });
337→  }
338→
339→  async getProof(eventId: string): Promise<MerkleProofResponse> {
340→    return this.client.request('GET', `/v1/events/${eventId}/proof`);
341→  }
342→
343→  async *listAll(params: Omit<ListEventsParams, 'cursor'>): AsyncGenerator<AuditEvent> {
344→    let cursor: string | undefined;
345→
346→    do {
347→      const response = await this.list({ ...params, cursor });
348→      for (const event of response.data) {
349→        yield event;
350→      }
351→      cursor = response.next_cursor;
352→    } while (cursor);
353→  }
354→}
