455→  async create(input: CreateExportInput): Promise<Export> {
456→    return this.client.request('POST', '/v1/exports', {
457→      organization_id: input.organizationId,
458→      format: input.format,
459→      filters: input.filters
460→        ? {
461→            after: toISOString(input.filters.after),
462→            before: toISOString(input.filters.before),
463→            action: input.filters.action,
464→            actor_id: input.filters.actorId,
465→          }
466→        : undefined,
467→    });
468→  }
469→
470→  async get(id: string): Promise<Export> {
471→    return this.client.request('GET', `/v1/exports/${id}`);
472→  }
473→
474→  async poll(id: string, intervalMs = 1000, maxWaitMs = 60000): Promise<Export> {
475→    const start = Date.now();
476→    while (Date.now() - start < maxWaitMs) {
477→      const exportJob = await this.get(id);
478→      if (exportJob.status === 'completed' || exportJob.status === 'failed') {
479→        return exportJob;
480→      }
481→      await sleep(intervalMs);
482→    }
483→    throw new LogSealError({
484→      type: 'internal_error',
485→      code: 'export_timeout',
486→      message: 'Export did not complete within the timeout period.',
487→    });
488→  }
489→}
