 1→export type ErrorType =
 2→  | 'invalid_request_error'
 3→  | 'authentication_error'
 4→  | 'authorization_error'
 5→  | 'not_found_error'
 6→  | 'rate_limit_error'
 7→  | 'idempotency_error'
 8→  | 'validation_error'
 9→  | 'internal_error';
10→
11→export interface LogSealErrorData {
12→  type: ErrorType;
13→  code: string;
14→  message: string;
15→  param?: string;
16→  doc_url?: string;
17→}
18→
19→export class LogSealError extends Error {
20→  public readonly type: ErrorType;
21→  public readonly code: string;
22→  public readonly param?: string;
23→  public readonly docUrl?: string;
24→  public readonly statusCode: number;
25→
26→  constructor(data: LogSealErrorData, statusCode: number = 400) {
27→    super(data.message);
28→    this.name = 'LogSealError';
29→    this.type = data.type;
30→    this.code = data.code;
31→    this.param = data.param;
32→    this.docUrl = data.doc_url;
33→    this.statusCode = statusCode;
34→
35→    // Maintains proper stack trace in V8 environments
36→    if (Error.captureStackTrace) {
37→      Error.captureStackTrace(this, LogSealError);
38→    }
39→  }
40→
41→  toJSON(): { error: LogSealErrorData } {
42→    return {
43→      error: {
44→        type: this.type,
45→        code: this.code,
46→        message: this.message,
47→        ...(this.param && { param: this.param }),
48→        ...(this.docUrl && { doc_url: this.docUrl }),
49→      },
50→    };
51→  }
52→}
