 1→import type { EmitEventInput } from '../types.js';
 2→import type { MiddlewareConfig, ResolvedRequestData } from './types.js';
 3→
 4→export function generateAction(method: string, routePattern: string): string {
 5→  const normalized = routePattern
 6→    .replace(/^\//, '')
 7→    .replace(/\/$/, '')
 8→    .replace(/\//g, '.');
 9→  return `${method.toLowerCase()}.${normalized || 'root'}`;
10→}
11→
12→export function isExcluded(path: string, exclude?: string[]): boolean {
13→  if (!exclude || exclude.length === 0) return false;
14→  for (const pattern of exclude) {
15→    if (pattern.endsWith('*')) {
16→      if (path.startsWith(pattern.slice(0, -1))) return true;
17→    } else {
18→      if (path === pattern) return true;
19→    }
20→  }
21→  return false;
22→}
23→
24→export function resolveAction(
25→  method: string,
26→  path: string,
27→  routePattern: string | null,
28→  actionMap?: Record<string, string>
29→): string {
30→  if (actionMap) {
31→    const key = `${method.toUpperCase()} ${path}`;
32→    if (actionMap[key]) return actionMap[key];
33→
34→    if (routePattern) {
35→      const routeKey = `${method.toUpperCase()} ${routePattern}`;
36→      if (actionMap[routeKey]) return actionMap[routeKey];
37→    }
38→  }
39→
40→  return generateAction(method, routePattern ?? path);
41→}
42→
43→export function buildEvent<TRequest>(
44→  config: MiddlewareConfig<TRequest>,
45→  request: TRequest,
46→  data: ResolvedRequestData
47→): EmitEventInput | null {
48→  const actor = config.actor(request);
49→  if (!actor?.id) return null;
50→
51→  const organizationId =
52→    typeof config.organizationId === 'function'
53→      ? config.organizationId(request)
54→      : config.organizationId;
55→  if (!organizationId) return null;
56→
57→  const action = resolveAction(
58→    data.method,
59→    data.path,
60→    data.routePattern,
61→    config.actionMap
62→  );
63→
64→  let metadata: Record<string, unknown> = {};
65→  if ((config.captureStatus ?? true) && data.statusCode) {
66→    metadata.statusCode = data.statusCode;
67→  }
68→  if (config.captureBody && data.body !== undefined) {
69→    metadata.requestBody = data.body;
70→  }
71→  if (config.enrichMetadata) {
72→    metadata = config.enrichMetadata(request, metadata);
73→  }
74→
75→  return {
76→    action,
77→    organizationId,
78→    actor,
79→    metadata: Object.keys(metadata).length > 0 ? metadata : undefined,
80→    context: {
81→      ipAddress: data.ipAddress,
82→      userAgent: data.userAgent,
83→      requestId: data.requestId,
84→    },
85→  };
86→}
