 50→export const authRoutes: FastifyPluginAsync = async (fastify) => {
 51→  // POST /auth/signup
 52→  fastify.post('/signup', async (request, reply) => {
 53→    const input = signupSchema.parse(request.body);
 54→
 55→    // Check if email already exists
 56→    const [existing] = await fastify.db
 57→      .select({ id: accounts.id })
 58→      .from(accounts)
 59→      .where(eq(accounts.email, input.email.toLowerCase()))
 60→      .limit(1);
 61→
 62→    if (existing) {
 63→      throw errors.emailAlreadyExists();
 64→    }
 65→
 66→    // Hash password
 67→    const passwordHash = await hashPassword(input.password);
 68→
 69→    // Create account
 70→    const [account] = await fastify.db
 71→      .insert(accounts)
 72→      .values({
 73→        email: input.email.toLowerCase(),
 74→        passwordHash,
 75→        companyName: input.company_name,
 76→      })
 77→      .returning();
 78→
 79→    // Create Stripe customer
 80→    let stripeCustomerId: string | null = null;
 81→    try {
 82→      stripeCustomerId = await createStripeCustomer(
 83→        account.email,
 84→        account.id,
 85→        account.companyName || undefined
 86→      );
 87→
 88→      // Update account with Stripe customer ID
 89→      await fastify.db
 90→        .update(accounts)
 91→        .set({ stripeCustomerId })
 92→        .where(eq(accounts.id, account.id));
 93→    } catch (err) {
 94→      fastify.log.error(err, 'Failed to create Stripe customer');
 95→    }
 96→
 97→    // Get default plan
 98→    const [defaultPlan] = await fastify.db
 99→      .select()
100→      .from(plans)
101→      .where(and(eq(plans.isDefault, true), eq(plans.active, true)))
102→      .limit(1);
103→
104→    if (defaultPlan) {
105→      // Create subscription to default plan
106→      const now = new Date();
107→      const periodEnd = new Date(now);
108→      periodEnd.setMonth(periodEnd.getMonth() + 1);
109→
110→      await fastify.db.insert(subscriptions).values({
111→        accountId: account.id,
112→        planId: defaultPlan.id,
113→        currentPeriodStart: now,
114→        currentPeriodEnd: periodEnd,
115→      });
116→
117→      // Create default orgs and usage records for both environments
118→      for (const env of ['test', 'live'] as const) {
119→        await getOrCreateDefaultOrg(fastify.db, account.id, env);
120→
121→        await fastify.db.insert(usageRecords).values({
122→          accountId: account.id,
123→          environment: env,
124→          periodStart: now,
125→          periodEnd: periodEnd,
126→          organizationsCount: 1,
127→        });
128→      }
129→    }
130→
131→    // Generate verification token
132→    const verificationToken = generateVerificationToken();
133→    const tokenHash = sha256(verificationToken);
134→    const expiresAt = new Date(Date.now() + 24 * 60 * 60 * 1000); // 24 hours
135→
136→    await fastify.db.insert(emailVerifications).values({
137→      accountId: account.id,
138→      tokenHash,
139→      expiresAt,
140→    });
141→
142→    // Send verification email
143→    try {
144→      await sendVerificationEmail(account.email, verificationToken);
145→    } catch (err) {
146→      fastify.log.error(err, 'Failed to send verification email');
147→    }
148→
149→    // Create session
150→    const { token, session } = await createSession(
151→      fastify.db,
152→      fastify.redis,
153→      account.id,
154→      request.ip,
155→      request.headers['user-agent']
156→    );
157→
158→    // Set session cookie
159→    const cookieOptions = getSessionCookieOptions(session.expiresAt);
160→    reply.setCookie(SESSION_COOKIE_NAME, token, cookieOptions);
161→
162→    return reply.status(201).send({
163→      id: account.id,
164→      email: account.email,
165→      company_name: account.companyName,
166→      email_verified: false,
167→      account_status: account.accountStatus,
168→      created_at: account.createdAt.toISOString(),
169→      object: 'auth_user',
170→    });
171→  });
172→
173→  // POST /auth/login
174→  fastify.post('/login', async (request, reply) => {
175→    const input = loginSchema.parse(request.body);
176→
177→    // Find account
178→    const [account] = await fastify.db
179→      .select()
180→      .from(accounts)
181→      .where(eq(accounts.email, input.email.toLowerCase()))
182→      .limit(1);
183→
184→    if (!account || !account.passwordHash) {
185→      throw errors.invalidCredentials();
186→    }
187→
188→    // Verify password
189→    const validPassword = await verifyPassword(account.passwordHash, input.password);
190→    if (!validPassword) {
191→      throw errors.invalidCredentials();
192→    }
193→
194→    // Check if email is verified
195→    if (!account.emailVerifiedAt) {
196→      throw errors.emailNotVerified();
197→    }
198→
199→    // Create session (mark as 2FA-pending if TOTP is enabled)
200→    const twoFactorPending = account.totpEnabled;
201→    const { token, session } = await createSession(
202→      fastify.db,
203→      fastify.redis,
204→      account.id,
205→      request.ip,
206→      request.headers['user-agent'],
207→      twoFactorPending
208→    );
209→
210→    // Set session cookie
211→    const cookieOptions = getSessionCookieOptions(session.expiresAt);
212→    reply.setCookie(SESSION_COOKIE_NAME, token, cookieOptions);
213→
214→    return reply.send({
215→      id: account.id,
216→      email: account.email,
217→      company_name: account.companyName,
218→      email_verified: true,
219→      account_status: account.accountStatus,
220→      created_at: account.createdAt.toISOString(),
221→      two_factor_required: twoFactorPending,
222→      object: 'auth_user',
223→    });
224→  });
225→
226→  // POST /auth/logout
227→  fastify.post('/logout', async (request, reply) => {
228→    const sessionToken = request.cookies?.[SESSION_COOKIE_NAME];
229→
230→    if (sessionToken) {
231→      await invalidateSession(fastify.db, fastify.redis, sessionToken);
232→    }
233→
234→    // Clear cookie
235→    const cookieOptions = getClearSessionCookieOptions();
236→    reply.setCookie(SESSION_COOKIE_NAME, '', cookieOptions);
237→
238→    return reply.status(204).send();
239→  });
240→
241→  // GET /auth/me
242→  fastify.get('/me', async (request, reply) => {
243→    if (!request.session) {
244→      throw errors.sessionExpired();
245→    }
246→
247→    // Get account details
248→    const [account] = await fastify.db
249→      .select()
250→      .from(accounts)
251→      .where(eq(accounts.id, request.session.accountId))
252→      .limit(1);
253→
254→    if (!account) {
255→      throw errors.sessionExpired();
256→    }
257→
258→    // Get subscription with plan
259→    const [subscription] = await fastify.db
