364→      throw errors.sessionExpired();
365→    }
366→
367→    await fastify.db
368→      .update(accounts)
369→      .set({ onboardingCompletedAt: new Date(), updatedAt: new Date() })
370→      .where(eq(accounts.id, request.session.accountId));
