375→  // POST /auth/verify-email
376→  fastify.post('/verify-email', async (request, reply) => {
377→    const input = verifyEmailSchema.parse(request.body);
378→    const tokenHash = sha256(input.token);
379→
380→    // Find valid verification token
381→    const [verification] = await fastify.db
382→      .select()
383→      .from(emailVerifications)
384→      .where(
385→        and(
386→          eq(emailVerifications.tokenHash, tokenHash),
387→          isNull(emailVerifications.usedAt),
388→          gt(emailVerifications.expiresAt, new Date())
389→        )
390→      )
391→      .limit(1);
392→
393→    if (!verification) {
394→      throw errors.invalidToken('verification');
395→    }
396→
397→    // Mark email as verified
398→    await fastify.db
399→      .update(accounts)
400→      .set({ emailVerifiedAt: new Date() })
401→      .where(eq(accounts.id, verification.accountId));
402→
403→    // Mark token as used
404→    await fastify.db
405→      .update(emailVerifications)
406→      .set({ usedAt: new Date() })
407→      .where(eq(emailVerifications.id, verification.id));
408→
409→    return reply.send({ success: true });
410→  });
411→
412→  // POST /auth/resend-verification
413→  fastify.post('/resend-verification', async (request, reply) => {
414→    if (!request.session) {
415→      throw errors.sessionExpired();
416→    }
417→
418→    // Get account
419→    const [account] = await fastify.db
420→      .select()
421→      .from(accounts)
422→      .where(eq(accounts.id, request.session.accountId))
423→      .limit(1);
424→
425→    if (!account) {
426→      throw errors.sessionExpired();
427→    }
428→
429→    if (account.emailVerifiedAt) {
430→      return reply.send({ success: true, message: 'Email already verified' });
431→    }
432→
433→    // Invalidate old verification tokens
434→    await fastify.db
435→      .update(emailVerifications)
436→      .set({ usedAt: new Date() })
437→      .where(
438→        and(eq(emailVerifications.accountId, account.id), isNull(emailVerifications.usedAt))
439→      );
440→
441→    // Generate new verification token
442→    const verificationToken = generateVerificationToken();
443→    const tokenHash = sha256(verificationToken);
444→    const expiresAt = new Date(Date.now() + 24 * 60 * 60 * 1000); // 24 hours
445→
446→    await fastify.db.insert(emailVerifications).values({
447→      accountId: account.id,
448→      tokenHash,
449→      expiresAt,
450→    });
451→
452→    // Send verification email
453→    await sendVerificationEmail(account.email, verificationToken);
454→
455→    return reply.send({ success: true });
