 1→import * as argon2 from 'argon2';
 2→
 3→/**
 4→ * Hash a password using argon2id (recommended by OWASP)
 5→ */
 6→export async function hashPassword(password: string): Promise<string> {
 7→  return argon2.hash(password, {
 8→    type: argon2.argon2id,
 9→    memoryCost: 65536, // 64 MiB
10→    timeCost: 3,
11→    parallelism: 4,
12→  });
13→}
14→
15→/**
16→ * Verify a password against a hash
17→ */
18→export async function verifyPassword(hash: string, password: string): Promise<boolean> {
19→  try {
20→    return await argon2.verify(hash, password);
21→  } catch {
22→    return false;
23→  }
24→}
