 1→import type { EmitEventInput } from '../types.js';
 2→import { isExcluded, buildEvent } from './core.js';
 3→import type {
 4→  ExpressRequest,
 5→  ExpressResponse,
 6→  ExpressNextFunction,
 7→  ExpressMiddlewareConfig,
 8→  ExpressMiddlewareReturn,
 9→} from './types.js';
10→
11→export function createExpressMiddleware(
12→  emit: (event: EmitEventInput) => Promise<unknown>,
13→  config: ExpressMiddlewareConfig
14→): ExpressMiddlewareReturn {
15→  const onError = config.onError ?? console.error;
16→
17→  return (req: ExpressRequest, res: ExpressResponse, next: ExpressNextFunction) => {
18→    try {
19→      if (isExcluded(req.path, config.exclude)) {
20→        next();
21→        return;
22→      }
23→
24→      res.on('finish', () => {
25→        try {
26→          const routePattern = req.route
27→            ? (req.baseUrl ?? '') + req.route.path
28→            : null;
29→
30→          const header = (name: string): string | undefined => {
31→            const val = req.headers[name.toLowerCase()];
32→            return Array.isArray(val) ? val[0] : val;
33→          };
34→
35→          const event = buildEvent(config, req, {
36→            method: req.method,
37→            path: req.originalUrl.split('?')[0],
38→            routePattern,
39→            statusCode: res.statusCode,
40→            ipAddress: req.ip ?? header('x-forwarded-for') ?? header('x-real-ip'),
41→            userAgent: header('user-agent'),
42→            requestId: header('x-request-id'),
43→            body: config.captureBody ? req.body : undefined,
44→          });
45→
46→          if (event) {
47→            emit(event).catch(onError);
48→          }
49→        } catch (err) {
50→          onError(err);
51→        }
52→      });
53→
54→      next();
55→    } catch (err) {
56→      onError(err);
57→      next();
58→    }
59→  };
60→}
