  1→import type { Redis } from 'ioredis';
  2→import { eq, and, gt } from 'drizzle-orm';
  3→import { sessions, type Database } from '@logseal/database';
  4→import { sha256, generateSessionToken, createSessionId } from '@logseal/utils';
  5→
  6→const SESSION_EXPIRY_DAYS = 30;
  7→const SESSION_CACHE_TTL_SECONDS = 300; // 5 minutes
  8→const SESSION_CACHE_PREFIX = 'session:';
  9→
 10→export interface SessionData {
 11→  sessionId: string;
 12→  accountId: string;
 13→  expiresAt: Date;
 14→  twoFactorPending: boolean;
 15→}
 16→
 17→export interface SessionCookieOptions {
 18→  httpOnly: boolean;
 19→  secure: boolean;
 20→  sameSite: 'lax' | 'strict' | 'none';
 21→  domain?: string;
 22→  path: string;
 23→  maxAge: number;
 24→}
 25→
 26→/**
 27→ * Create a new session for an account
 28→ * Returns the raw token (to be sent to client) and session data
 29→ */
 30→export async function createSession(
 31→  db: Database,
 32→  redis: Redis,
 33→  accountId: string,
 34→  ipAddress?: string,
 35→  userAgent?: string,
 36→  twoFactorPending: boolean = false
 37→): Promise<{ token: string; session: SessionData }> {
 38→  const token = generateSessionToken();
 39→  const tokenHash = sha256(token);
 40→  const expiresAt = new Date(Date.now() + SESSION_EXPIRY_DAYS * 24 * 60 * 60 * 1000);
 41→  const sessionId = createSessionId();
 42→
 43→  await db.insert(sessions).values({
 44→    id: sessionId,
 45→    accountId,
 46→    tokenHash,
 47→    ipAddress,
 48→    userAgent,
 49→    twoFactorPending,
 50→    expiresAt,
 51→  });
 52→
 53→  const sessionData: SessionData = {
 54→    sessionId,
 55→    accountId,
 56→    expiresAt,
 57→    twoFactorPending,
 58→  };
 59→
 60→  // Cache the session in Redis
 61→  await redis.setex(
 62→    SESSION_CACHE_PREFIX + tokenHash,
 63→    SESSION_CACHE_TTL_SECONDS,
 64→    JSON.stringify(sessionData)
 65→  );
 66→
 67→  return { token, session: sessionData };
 68→}
 69→
 70→/**
 71→ * Validate a session token
 72→ * Checks Redis cache first, then falls back to database
 73→ * Updates lastActiveAt for sliding expiration
 74→ */
 75→export async function validateSession(
 76→  db: Database,
 77→  redis: Redis,
 78→  token: string
 79→): Promise<SessionData | null> {
 80→  const tokenHash = sha256(token);
 81→  const cacheKey = SESSION_CACHE_PREFIX + tokenHash;
 82→
 83→  // Check Redis cache first
 84→  const cached = await redis.get(cacheKey);
 85→  if (cached) {
 86→    const sessionData = JSON.parse(cached) as SessionData;
 87→    sessionData.expiresAt = new Date(sessionData.expiresAt);
 88→
 89→    if (sessionData.expiresAt > new Date()) {
 90→      // Update lastActiveAt asynchronously (don't await)
 91→      updateLastActiveAt(db, sessionData.sessionId).catch(() => {});
 92→      return sessionData;
 93→    }
 94→  }
 95→
 96→  // Fall back to database
 97→  const [session] = await db
 98→    .select({
 99→      id: sessions.id,
100→      accountId: sessions.accountId,
101→      expiresAt: sessions.expiresAt,
102→      twoFactorPending: sessions.twoFactorPending,
103→    })
104→    .from(sessions)
105→    .where(and(eq(sessions.tokenHash, tokenHash), gt(sessions.expiresAt, new Date())))
106→    .limit(1);
107→
108→  if (!session) {
109→    return null;
110→  }
111→
112→  const sessionData: SessionData = {
113→    sessionId: session.id,
114→    accountId: session.accountId,
115→    expiresAt: session.expiresAt,
116→    twoFactorPending: session.twoFactorPending,
117→  };
118→
119→  // Cache the session
120→  await redis.setex(cacheKey, SESSION_CACHE_TTL_SECONDS, JSON.stringify(sessionData));
121→
122→  // Update lastActiveAt asynchronously
123→  updateLastActiveAt(db, session.id).catch(() => {});
124→
125→  return sessionData;
126→}
127→
128→/**
129→ * Invalidate a session (logout)
130→ */
131→export async function invalidateSession(
132→  db: Database,
133→  redis: Redis,
134→  token: string
135→): Promise<void> {
136→  const tokenHash = sha256(token);
137→  const cacheKey = SESSION_CACHE_PREFIX + tokenHash;
138→
139→  // Remove from Redis cache
140→  await redis.del(cacheKey);
141→
142→  // Delete from database
143→  await db.delete(sessions).where(eq(sessions.tokenHash, tokenHash));
144→}
145→
146→/**
147→ * Invalidate all sessions for an account (e.g., after password reset)
148→ */
149→export async function invalidateAllSessions(
150→  db: Database,
151→  redis: Redis,
152→  accountId: string
153→): Promise<void> {
154→  // Get all session token hashes for the account
155→  const accountSessions = await db
156→    .select({ tokenHash: sessions.tokenHash })
157→    .from(sessions)
158→    .where(eq(sessions.accountId, accountId));
159→
160→  // Delete from Redis cache
161→  const cacheKeys = accountSessions.map((s) => SESSION_CACHE_PREFIX + s.tokenHash);
162→  if (cacheKeys.length > 0) {
163→    await redis.del(...cacheKeys);
164→  }
165→
166→  // Delete from database
167→  await db.delete(sessions).where(eq(sessions.accountId, accountId));
168→}
169→
170→/**
171→ * Get cookie options for session cookie
172→ */
173→export function getSessionCookieOptions(expiresAt: Date): SessionCookieOptions {
174→  const domain = process.env.COOKIE_DOMAIN;
175→  const isProduction = process.env.NODE_ENV === 'production';
176→
177→  return {
178→    httpOnly: true,
179→    secure: isProduction,
180→    sameSite: 'lax',
181→    ...(domain && domain !== 'localhost' && { domain }),
182→    path: '/',
183→    maxAge: Math.floor((expiresAt.getTime() - Date.now()) / 1000),
184→  };
185→}
186→
187→/**
188→ * Get cookie options for clearing a session cookie
189→ */
190→export function getClearSessionCookieOptions(): SessionCookieOptions {
191→  const domain = process.env.COOKIE_DOMAIN;
192→  const isProduction = process.env.NODE_ENV === 'production';
193→
194→  return {
195→    httpOnly: true,
196→    secure: isProduction,
197→    sameSite: 'lax',
198→    ...(domain && domain !== 'localhost' && { domain }),
199→    path: '/',
200→    maxAge: 0,
201→  };
202→}
203→
204→/**
205→ * Update the lastActiveAt timestamp for sliding expiration
206→ */
207→async function updateLastActiveAt(
208→  db: Database,
209→  sessionId: string
210→): Promise<void> {
211→  await db
212→    .update(sessions)
213→    .set({ lastActiveAt: new Date() })
214→    .where(eq(sessions.id, sessionId));
215→}
216→
217→/**
218→ * Complete two-factor verification for a session
219→ * Sets twoFactorPending to false and invalidates Redis cache
220→ */
221→export async function completeTwoFactorVerification(
222→  db: Database,
223→  redis: Redis,
224→  sessionId: string,
225→  tokenHash: string
226→): Promise<void> {
227→  await db
228→    .update(sessions)
229→    .set({ twoFactorPending: false })
230→    .where(eq(sessions.id, sessionId));
231→
232→  // Invalidate Redis cache so next validation picks up the change
233→  const cacheKey = SESSION_CACHE_PREFIX + tokenHash;
234→  await redis.del(cacheKey);
235→}
236→
237→export const SESSION_COOKIE_NAME = 'logseal_session';
