 1→import type { EmitEventInput } from '../types.js';
 2→import { isExcluded, buildEvent } from './core.js';
 3→import type {
 4→  FastifyInstance,
 5→  FastifyRequest,
 6→  FastifyReply,
 7→  FastifyMiddlewareConfig,
 8→  FastifyPluginReturn,
 9→} from './types.js';
10→
11→export function createFastifyMiddleware(
12→  emit: (event: EmitEventInput) => Promise<unknown>,
13→  config: FastifyMiddlewareConfig
14→): FastifyPluginReturn {
15→  const onError = config.onError ?? console.error;
16→
17→  const plugin = function (
18→    instance: FastifyInstance,
19→    _opts: Record<string, unknown>,
20→    done: (err?: Error) => void
21→  ) {
22→    instance.addHook('onResponse', (request: FastifyRequest, reply: FastifyReply, hookDone: () => void) => {
23→      try {
24→        const urlPath = request.url.split('?')[0];
25→
26→        if (isExcluded(urlPath, config.exclude)) {
27→          hookDone();
28→          return;
29→        }
30→
31→        const routePattern =
32→          request.routeOptions?.url ?? request.routerPath ?? null;
33→
34→        const header = (name: string): string | undefined => {
35→          const val = request.headers[name.toLowerCase()];
36→          return Array.isArray(val) ? val[0] : val;
37→        };
38→
39→        const event = buildEvent(config, request, {
40→          method: request.method,
41→          path: urlPath,
42→          routePattern,
43→          statusCode: reply.statusCode,
44→          ipAddress: request.ip ?? header('x-forwarded-for') ?? header('x-real-ip'),
45→          userAgent: header('user-agent'),
46→          requestId: header('x-request-id'),
47→          body: config.captureBody ? request.body : undefined,
48→        });
49→
50→        if (event) {
51→          emit(event).catch(onError);
52→        }
53→      } catch (err) {
54→        onError(err);
55→      }
56→
57→      hookDone();
58→    });
59→
60→    done();
61→  } as FastifyPluginReturn;
62→
63→  // Equivalent to fastify-plugin: prevents Fastify encapsulation
64→  plugin[Symbol.for('skip-override')] = true;
65→
66→  return plugin;
67→}
