 1→import crypto from 'node:crypto';
 2→import { generateSecret, generateURI, verifySync } from 'otplib';
 3→import { hashPassword, verifyPassword } from './password.js';
 4→
 5→const ALGORITHM = 'aes-256-gcm';
 6→const IV_LENGTH = 12;
 7→
 8→function getEncryptionKey(): Buffer {
 9→  const key = process.env.TOTP_ENCRYPTION_KEY;
10→  if (!key || key.length !== 64) {
11→    throw new Error('TOTP_ENCRYPTION_KEY must be a 64-character hex string');
12→  }
13→  return Buffer.from(key, 'hex');
14→}
15→
16→export function encryptTotpSecret(secret: string): string {
17→  const key = getEncryptionKey();
18→  const iv = crypto.randomBytes(IV_LENGTH);
19→  const cipher = crypto.createCipheriv(ALGORITHM, key, iv);
20→  const encrypted = Buffer.concat([cipher.update(secret, 'utf8'), cipher.final()]);
21→  const tag = cipher.getAuthTag();
22→  // Format: iv:tag:ciphertext (all base64)
23→  return `${iv.toString('base64')}:${tag.toString('base64')}:${encrypted.toString('base64')}`;
24→}
25→
26→export function decryptTotpSecret(encrypted: string): string {
27→  const key = getEncryptionKey();
28→  const [ivB64, tagB64, dataB64] = encrypted.split(':');
29→  const iv = Buffer.from(ivB64, 'base64');
30→  const tag = Buffer.from(tagB64, 'base64');
31→  const data = Buffer.from(dataB64, 'base64');
32→  const decipher = crypto.createDecipheriv(ALGORITHM, key, iv);
33→  decipher.setAuthTag(tag);
34→  return decipher.update(data) + decipher.final('utf8');
35→}
36→
37→export function generateTotpSecret(): string {
38→  return generateSecret();
39→}
40→
41→export function generateOtpauthUri(secret: string, email: string): string {
42→  return generateURI({ secret, label: email, issuer: 'LogSeal' });
43→}
44→
45→export function verifyTotpCode(secret: string, code: string): boolean {
46→  const result = verifySync({ secret, token: code, epochTolerance: 30 });
47→  return result.valid;
48→}
49→
50→export function generateBackupCodes(count: number = 8): string[] {
51→  const codes: string[] = [];
52→  for (let i = 0; i < count; i++) {
53→    const part1 = crypto.randomBytes(2).toString('hex').toUpperCase();
54→    const part2 = crypto.randomBytes(2).toString('hex').toUpperCase();
55→    codes.push(`${part1}-${part2}`);
56→  }
57→  return codes;
58→}
59→
60→export async function hashBackupCodes(codes: string[]): Promise<string[]> {
61→  return Promise.all(codes.map((code) => hashPassword(code)));
62→}
63→
64→export async function verifyBackupCode(
65→  code: string,
66→  hashedCodes: string[]
67→): Promise<{ valid: boolean; index: number }> {
68→  for (let i = 0; i < hashedCodes.length; i++) {
69→    const match = await verifyPassword(hashedCodes[i], code);
70→    if (match) {
71→      return { valid: true, index: i };
72→    }
73→  }
74→  return { valid: false, index: -1 };
75→}
