 1→import type { EmitEventInput } from '../types.js';
 2→import { isExcluded, buildEvent } from './core.js';
 3→import type {
 4→  HonoContext,
 5→  HonoNextFunction,
 6→  HonoMiddlewareConfig,
 7→  HonoMiddlewareReturn,
 8→} from './types.js';
 9→
10→export function createHonoMiddleware(
11→  emit: (event: EmitEventInput) => Promise<unknown>,
12→  config: HonoMiddlewareConfig
13→): HonoMiddlewareReturn {
14→  const onError = config.onError ?? console.error;
15→
16→  return async (c: HonoContext, next: HonoNextFunction) => {
17→    const path = c.req.path;
18→
19→    if (isExcluded(path, config.exclude)) {
20→      await next();
21→      return;
22→    }
23→
24→    await next();
25→
26→    try {
27→      const event = buildEvent(config, c, {
28→        method: c.req.method,
29→        path,
30→        routePattern: c.req.routePath ?? null,
31→        statusCode: c.res.status,
32→        ipAddress: c.req.header('x-forwarded-for') ?? c.req.header('x-real-ip'),
33→        userAgent: c.req.header('user-agent'),
34→        requestId: c.req.header('x-request-id'),
35→        body: config.captureBody ? c.req.raw.body : undefined,
36→      });
37→
38→      if (event) {
39→        emit(event).catch(onError);
40→      }
41→    } catch (err) {
42→      onError(err);
43→    }
44→  };
45→}
