 1→import { createCipheriv, createDecipheriv, randomBytes } from 'crypto';
 2→
 3→const ALGORITHM = 'aes-256-gcm';
 4→const KEY_LENGTH = 32; // 256 bits
 5→
 6→function getEncryptionKey(): Buffer {
 7→  const key = process.env.BYOD_ENCRYPTION_KEY;
 8→  if (!key) {
 9→    throw new Error('BYOD_ENCRYPTION_KEY environment variable is required');
10→  }
11→  // Accept hex-encoded 32-byte key
12→  const keyBuffer = Buffer.from(key, 'hex');
13→  if (keyBuffer.length !== KEY_LENGTH) {
14→    throw new Error(`BYOD_ENCRYPTION_KEY must be ${KEY_LENGTH * 2} hex characters (${KEY_LENGTH} bytes)`);
15→  }
16→  return keyBuffer;
17→}
18→
19→export interface EncryptedData {
20→  ciphertext: string; // hex-encoded
21→  iv: string; // hex-encoded
22→  authTag: string; // hex-encoded
23→}
24→
25→export function encrypt(plaintext: string): EncryptedData {
26→  const key = getEncryptionKey();
27→  const iv = randomBytes(16);
28→  const cipher = createCipheriv(ALGORITHM, key, iv);
29→
30→  let ciphertext = cipher.update(plaintext, 'utf8', 'hex');
31→  ciphertext += cipher.final('hex');
32→  const authTag = cipher.getAuthTag().toString('hex');
33→
34→  return {
35→    ciphertext,
36→    iv: iv.toString('hex'),
37→    authTag,
38→  };
39→}
40→
41→export function decrypt(data: EncryptedData): string {
42→  const key = getEncryptionKey();
43→  const iv = Buffer.from(data.iv, 'hex');
44→  const decipher = createDecipheriv(ALGORITHM, key, iv);
45→  decipher.setAuthTag(Buffer.from(data.authTag, 'hex'));
46→
47→  let plaintext = decipher.update(data.ciphertext, 'hex', 'utf8');
48→  plaintext += decipher.final('utf8');
49→
50→  return plaintext;
51→}
