 55→  async getEvents(
 56→    accountId: string,
 57→    organizationId: string,
 58→    environment: 'test' | 'live',
 59→    options: {
 60→      action?: string;
 61→      actionPrefix?: string;
 62→      actorId?: string;
 63→      after?: Date;
 64→      before?: Date;
 65→      limit: number;
 66→      cursorBefore?: { id: string; t: string };
 67→      cursorAfter?: { id: string; t: string };
 68→    }
 69→  ): Promise<{ events: AuditEvent[]; hasMore: boolean }> {
 70→    const conditions = [
 71→      eq(auditEvents.organizationId, organizationId),
 72→      eq(auditEvents.accountId, accountId),
 73→      eq(auditEvents.environment, environment),
 74→    ];
 75→
 76→    if (options.action) {
 77→      conditions.push(eq(auditEvents.action, options.action));
 78→    }
 79→    if (options.actionPrefix) {
 80→      conditions.push(sql`${auditEvents.action} LIKE ${options.actionPrefix + '%'}`);
 81→    }
 82→    if (options.actorId) {
 83→      conditions.push(eq(auditEvents.actorId, options.actorId));
 84→    }
 85→    if (options.after) {
 86→      conditions.push(gte(auditEvents.occurredAt, options.after));
 87→    }
 88→    if (options.before) {
 89→      conditions.push(lte(auditEvents.occurredAt, options.before));
 90→    }
 91→    if (options.cursorAfter) {
 92→      conditions.push(
 93→        sql`(${auditEvents.occurredAt}, ${auditEvents.id}) < (${options.cursorAfter.t}::timestamptz, ${options.cursorAfter.id})`
 94→      );
 95→    } else if (options.cursorBefore) {
 96→      conditions.push(
 97→        sql`(${auditEvents.occurredAt}, ${auditEvents.id}) > (${options.cursorBefore.t}::timestamptz, ${options.cursorBefore.id})`
 98→      );
 99→    }
100→
101→    const events = await this.db
102→      .select()
103→      .from(auditEvents)
104→      .where(and(...conditions))
105→      .orderBy(desc(auditEvents.occurredAt), desc(auditEvents.id))
106→      .limit(options.limit + 1);
107→
108→    const hasMore = events.length > options.limit;
109→    return {
110→      events: hasMore ? events.slice(0, -1) : events,
111→      hasMore,
112→    };
113→  }
