411→        ON "audit_events" ("organization_id", "actor_id", "occurred_at");
412→      CREATE INDEX IF NOT EXISTS "idx_events_account_env"
413→        ON "audit_events" ("account_id", "environment", "received_at");
414→      CREATE INDEX IF NOT EXISTS "idx_events_idempotency"
415→        ON "audit_events" ("account_id", "idempotency_key");
416→      CREATE INDEX IF NOT EXISTS "idx_events_org_seq"
417→        ON "audit_events" ("organization_id", "sequence_number");
418→    `);
419→  }
