  1→import { FastifyPluginAsync } from 'fastify';
  2→import { z } from 'zod';
  3→import { eq, and, desc, lt, gt } from 'drizzle-orm';
  4→import { apiKeys } from '@logseal/database';
  5→import { errors, generateApiKey, getKeyPrefix, getKeyLastFour, sha256 } from '@logseal/utils';
  6→import { paginationSchema, decodeCursor } from '../utils/pagination.js';
  7→import { checkEntitlement } from '../services/entitlements.js';
  8→import { incrementUsage, decrementUsage } from '../services/usage.js';
  9→import { serializeApiKey, serializeList } from '../serializers/index.js';
 10→import { idParamSchema } from '../utils/params.js';
 11→
 12→const createApiKeySchema = z.object({
 13→  name: z.string().optional(),
 14→  environment: z.enum(['test', 'live']).optional(),
 15→});
 16→
 17→export const apiKeysRoutes: FastifyPluginAsync = async (fastify) => {
 18→  // GET /v1/api-keys - List API keys
 19→  fastify.get('/api-keys', async (request, reply) => {
 20→    const account = request.account;
 21→    if (!account) {
 22→      throw errors.missingApiKey();
 23→    }
 24→
 25→    const params = paginationSchema.parse(request.query);
 26→
 27→    const conditions = [
 28→      eq(apiKeys.accountId, account.accountId),
 29→      eq(apiKeys.environment, account.environment),
 30→    ];
 31→
 32→    // Handle cursor-based pagination
 33→    if (params.starting_after) {
 34→      const cursorId = decodeCursor(params.starting_after);
 35→      if (cursorId) {
 36→        const [cursorItem] = await fastify.db
 37→          .select({ createdAt: apiKeys.createdAt })
 38→          .from(apiKeys)
 39→          .where(eq(apiKeys.id, cursorId))
 40→          .limit(1);
 41→
 42→        if (cursorItem) {
 43→          conditions.push(lt(apiKeys.createdAt, cursorItem.createdAt));
 44→        }
 45→      }
 46→    } else if (params.ending_before) {
 47→      const cursorId = decodeCursor(params.ending_before);
 48→      if (cursorId) {
 49→        const [cursorItem] = await fastify.db
 50→          .select({ createdAt: apiKeys.createdAt })
 51→          .from(apiKeys)
 52→          .where(eq(apiKeys.id, cursorId))
 53→          .limit(1);
 54→
 55→        if (cursorItem) {
 56→          conditions.push(gt(apiKeys.createdAt, cursorItem.createdAt));
 57→        }
 58→      }
 59→    }
 60→
 61→    const keys = await fastify.db
 62→      .select({
 63→        id: apiKeys.id,
 64→        name: apiKeys.name,
 65→        environment: apiKeys.environment,
 66→        keyPrefix: apiKeys.keyPrefix,
 67→        lastFour: apiKeys.lastFour,
 68→        createdAt: apiKeys.createdAt,
 69→        lastUsedAt: apiKeys.lastUsedAt,
 70→        revokedAt: apiKeys.revokedAt,
 71→      })
 72→      .from(apiKeys)
 73→      .where(and(...conditions))
 74→      .orderBy(desc(apiKeys.createdAt))
 75→      .limit(params.limit + 1);
 76→
 77→    return reply.send(serializeList(keys, params.limit, serializeApiKey));
 78→  });
 79→
 80→  // POST /v1/api-keys - Create API key
 81→  fastify.post('/api-keys', async (request, reply) => {
 82→    const account = request.account;
 83→    if (!account) {
 84→      throw errors.missingApiKey();
 85→    }
 86→
 87→    const input = createApiKeySchema.parse(request.body);
 88→
 89→    // Check entitlement
 90→    const { allowed, limit } = await checkEntitlement(
 91→      fastify.db,
 92→      fastify.redis,
 93→      account.accountId,
 94→      account.environment,
 95→      'apiKeys'
 96→    );
 97→
 98→    if (!allowed) {
 99→      throw errors.entitlementExceeded('API keys', limit);
100→    }
101→
102→    // Use the current key's environment if not specified
103→    const environment = input.environment || account.environment;
104→
105→    // Generate the actual API key
106→    const key = generateApiKey(environment);
107→    const keyPrefix = getKeyPrefix(key);
108→    const lastFour = getKeyLastFour(key);
109→    const keyHash = sha256(key);
110→
111→    const [apiKey] = await fastify.db
112→      .insert(apiKeys)
113→      .values({
114→        accountId: account.accountId,
115→        environment,
116→        keyPrefix,
117→        keyHash,
118→        lastFour,
119→        name: input.name,
120→      })
121→      .returning();
122→
123→    // Increment usage (use the created key's environment, not the requesting key's)
124→    incrementUsage(fastify.db, fastify.redis, account.accountId, environment, 'apiKeysCount').catch((err) =>
125→      fastify.log.error(err, 'Failed to increment API keys usage')
126→    );
127→
128→    return reply.status(201).send({
129→      ...serializeApiKey(apiKey),
130→      key, // Only returned on creation!
131→    });
132→  });
133→
134→  // DELETE /v1/api-keys/:id - Revoke API key
135→  fastify.delete('/api-keys/:id', async (request, reply) => {
136→    const account = request.account;
137→    if (!account) {
138→      throw errors.missingApiKey();
139→    }
140→
141→    const { id } = idParamSchema.parse(request.params);
142→
143→    // Check if key exists and belongs to account
144→    const [existing] = await fastify.db
145→      .select()
146→      .from(apiKeys)
147→      .where(
148→        and(
149→          eq(apiKeys.id, id),
150→          eq(apiKeys.accountId, account.accountId)
151→        )
152→      )
153→      .limit(1);
154→
155→    if (!existing) {
156→      throw errors.notFound('api_key');
157→    }
158→
159→    // Don't allow revoking the key being used to make this request
160→    if (existing.id === account.keyId) {
161→      throw errors.invalidFieldValue('id', 'Cannot revoke the API key being used for this request');
162→    }
163→
164→    // Revoke the key (soft delete)
165→    await fastify.db
166→      .update(apiKeys)
167→      .set({ revokedAt: new Date() })
168→      .where(eq(apiKeys.id, id));
169→
170→    decrementUsage(fastify.db, fastify.redis, account.accountId, existing.environment, 'apiKeysCount').catch((err) =>
171→      fastify.log.error(err, 'Failed to decrement api keys usage')
172→    );
173→
174→    return reply.status(204).send();
175→  });
176→};
