  1→import { eq, and, asc, desc, gte, lte, gt, sql, inArray } from 'drizzle-orm';
  2→import type { Database } from '../index.js';
  3→import { auditEvents, organizations } from '../schema/index.js';
  4→import type { AuditEvent, Organization } from '../schema/index.js';
  5→import type { DataStore, EventInsert, ChainTip, OrganizationInsert } from './interface.js';
  6→
  7→/**
  8→ * PostgresDataStore — implements DataStore using Drizzle ORM.
  9→ * Works against any Postgres database (main DB or customer's BYOD DB).
 10→ */
 11→export class PostgresDataStore implements DataStore {
 12→  constructor(private db: Database) {}
 13→
 14→  async insertEvent(event: EventInsert): Promise<void> {
 15→    await this.db.insert(auditEvents).values({
 16→      id: event.id,
 17→      accountId: event.accountId,
 18→      organizationId: event.organizationId,
 19→      environment: event.environment,
 20→      action: event.action,
 21→      actorId: event.actorId,
 22→      actorType: event.actorType || 'user',
 23→      actorName: event.actorName,
 24→      actorEmail: event.actorEmail,
 25→      actorMetadata: event.actorMetadata || {},
 26→      targets: event.targets || [],
 27→      metadata: event.metadata || {},
 28→      ipAddress: event.ipAddress,
 29→      userAgent: event.userAgent,
 30→      requestId: event.requestId,
 31→      occurredAt: event.occurredAt,
 32→      previousHash: event.previousHash,
 33→      eventHash: event.eventHash,
 34→      sequenceNumber: event.sequenceNumber,
 35→      idempotencyKey: event.idempotencyKey,
 36→      skipHashes: event.skipHashes,
 37→    });
 38→  }
 39→
 40→  async getEventById(id: string, accountId: string, environment: 'test' | 'live'): Promise<AuditEvent | null> {
 41→    const [event] = await this.db
 42→      .select()
 43→      .from(auditEvents)
 44→      .where(
 45→        and(
 46→          eq(auditEvents.id, id),
 47→          eq(auditEvents.accountId, accountId),
 48→          eq(auditEvents.environment, environment)
 49→        )
 50→      )
 51→      .limit(1);
 52→    return event ?? null;
 53→  }
 54→
 55→  async getEvents(
 56→    accountId: string,
 57→    organizationId: string,
 58→    environment: 'test' | 'live',
 59→    options: {
 60→      action?: string;
 61→      actionPrefix?: string;
 62→      actorId?: string;
 63→      after?: Date;
 64→      before?: Date;
 65→      limit: number;
 66→      cursorBefore?: { id: string; t: string };
 67→      cursorAfter?: { id: string; t: string };
 68→    }
 69→  ): Promise<{ events: AuditEvent[]; hasMore: boolean }> {
 70→    const conditions = [
 71→      eq(auditEvents.organizationId, organizationId),
 72→      eq(auditEvents.accountId, accountId),
 73→      eq(auditEvents.environment, environment),
 74→    ];
 75→
 76→    if (options.action) {
 77→      conditions.push(eq(auditEvents.action, options.action));
 78→    }
 79→    if (options.actionPrefix) {
 80→      conditions.push(sql`${auditEvents.action} LIKE ${options.actionPrefix + '%'}`);
 81→    }
 82→    if (options.actorId) {
 83→      conditions.push(eq(auditEvents.actorId, options.actorId));
 84→    }
 85→    if (options.after) {
 86→      conditions.push(gte(auditEvents.occurredAt, options.after));
 87→    }
 88→    if (options.before) {
 89→      conditions.push(lte(auditEvents.occurredAt, options.before));
 90→    }
 91→    if (options.cursorAfter) {
 92→      conditions.push(
 93→        sql`(${auditEvents.occurredAt}, ${auditEvents.id}) < (${options.cursorAfter.t}::timestamptz, ${options.cursorAfter.id})`
 94→      );
 95→    } else if (options.cursorBefore) {
 96→      conditions.push(
 97→        sql`(${auditEvents.occurredAt}, ${auditEvents.id}) > (${options.cursorBefore.t}::timestamptz, ${options.cursorBefore.id})`
 98→      );
 99→    }
100→
101→    const events = await this.db
102→      .select()
103→      .from(auditEvents)
104→      .where(and(...conditions))
105→      .orderBy(desc(auditEvents.occurredAt), desc(auditEvents.id))
106→      .limit(options.limit + 1);
107→
108→    const hasMore = events.length > options.limit;
109→    return {
110→      events: hasMore ? events.slice(0, -1) : events,
111→      hasMore,
112→    };
113→  }
114→
115→  async getLastEventForChain(organizationId: string, environment: 'test' | 'live'): Promise<ChainTip | null> {
116→    const [last] = await this.db
117→      .select({
118→        eventHash: auditEvents.eventHash,
119→        sequenceNumber: auditEvents.sequenceNumber,
120→      })
121→      .from(auditEvents)
122→      .where(
123→        and(
124→          eq(auditEvents.organizationId, organizationId),
125→          eq(auditEvents.environment, environment)
126→        )
127→      )
128→      .orderBy(desc(auditEvents.sequenceNumber))
129→      .limit(1);
130→    return last ?? null;
131→  }
132→
133→  async getDistinctActions(accountId: string, environment: 'test' | 'live'): Promise<string[]> {
134→    const results = await this.db
135→      .selectDistinct({ action: auditEvents.action })
136→      .from(auditEvents)
137→      .where(
138→        and(
139→          eq(auditEvents.accountId, accountId),
140→          eq(auditEvents.environment, environment)
141→        )
142→      )
143→      .orderBy(asc(auditEvents.action));
144→    return results.map((r) => r.action);
145→  }
146→
147→  async getEventsByIdempotencyKey(accountId: string, key: string): Promise<{ id: string } | null> {
148→    const [existing] = await this.db
149→      .select({ id: auditEvents.id })
150→      .from(auditEvents)
151→      .where(
152→        and(
153→          eq(auditEvents.accountId, accountId),
154→          eq(auditEvents.idempotencyKey, key)
155→        )
156→      )
157→      .limit(1);
158→    return existing ?? null;
159→  }
160→
161→  async getChainBatch(
162→    organizationId: string,
163→    accountId: string,
164→    afterSequence: number,
165→    limit: number,
166→    dateRange?: { after?: Date; before?: Date },
167→    beforeSequence?: number
168→  ): Promise<Array<{ id: string; previousHash: string | null; eventHash: string; sequenceNumber: number }>> {
169→    const conditions = [
170→      eq(auditEvents.organizationId, organizationId),
171→      eq(auditEvents.accountId, accountId),
172→      gt(auditEvents.sequenceNumber, afterSequence),
173→    ];
174→
175→    if (beforeSequence !== undefined) {
176→      conditions.push(lte(auditEvents.sequenceNumber, beforeSequence));
177→    }
178→    if (dateRange?.after) {
179→      conditions.push(gte(auditEvents.occurredAt, dateRange.after));
180→    }
181→    if (dateRange?.before) {
182→      conditions.push(lte(auditEvents.occurredAt, dateRange.before));
183→    }
184→
185→    return this.db
186→      .select({
187→        id: auditEvents.id,
188→        previousHash: auditEvents.previousHash,
189→        eventHash: auditEvents.eventHash,
190→        sequenceNumber: auditEvents.sequenceNumber,
191→      })
192→      .from(auditEvents)
193→      .where(and(...conditions))
194→      .orderBy(asc(auditEvents.sequenceNumber))
195→      .limit(limit);
196→  }
197→
198→  async getEventBySequenceNumber(
199→    organizationId: string,
200→    accountId: string,
201→    sequenceNumber: number
202→  ): Promise<AuditEvent | null> {
203→    const [event] = await this.db
204→      .select()
205→      .from(auditEvents)
206→      .where(
