238→  async getFullEventBatch(
239→    organizationId: string,
240→    accountId: string,
241→    afterSequence: number,
242→    limit: number,
243→    dateRange?: { after?: Date; before?: Date }
244→  ): Promise<AuditEvent[]> {
245→    const conditions = [
246→      eq(auditEvents.organizationId, organizationId),
247→      eq(auditEvents.accountId, accountId),
248→      gt(auditEvents.sequenceNumber, afterSequence),
249→    ];
250→
251→    if (dateRange?.after) {
252→      conditions.push(gte(auditEvents.occurredAt, dateRange.after));
253→    }
254→    if (dateRange?.before) {
255→      conditions.push(lte(auditEvents.occurredAt, dateRange.before));
256→    }
257→
258→    return this.db
259→      .select()
260→      .from(auditEvents)
261→      .where(and(...conditions))
262→      .orderBy(asc(auditEvents.sequenceNumber))
263→      .limit(limit);
264→  }
