  3→// ============================================
  4→// Shared Middleware Config
  5→// ============================================
  6→
  7→export interface MiddlewareConfig<TRequest> {
  8→  actor: (req: TRequest) => ActorInput | null | undefined;
  9→  organizationId: string | ((req: TRequest) => string | null | undefined);
 10→  exclude?: string[];
 11→  actionMap?: Record<string, string>;
 12→  captureBody?: boolean;
 13→  captureStatus?: boolean;
 14→  enrichMetadata?: (
 15→    req: TRequest,
 16→    metadata: Record<string, unknown>
 17→  ) => Record<string, unknown>;
 18→  onError?: (error: unknown) => void;
 19→}
 20→
 21→export interface ResolvedRequestData {
 22→  method: string;
 23→  path: string;
 24→  routePattern: string | null;
 25→  statusCode: number;
 26→  ipAddress: string | undefined;
 27→  userAgent: string | undefined;
 28→  requestId: string | undefined;
 29→  body: unknown | undefined;
 30→}
 31→
 32→// ============================================
 33→// Express Types (duck-typed)
 34→// ============================================
 35→
 36→export interface ExpressRequest {
 37→  method: string;
 38→  url: string;
 39→  originalUrl: string;
 40→  path: string;
 41→  baseUrl?: string;
 42→  route?: { path: string };
 43→  ip?: string;
 44→  headers: Record<string, string | string[] | undefined>;
 45→  body?: unknown;
 46→}
 47→
 48→export interface ExpressResponse {
 49→  statusCode: number;
 50→  on(event: string, listener: () => void): void;
 51→}
 52→
 53→export type ExpressNextFunction = (err?: unknown) => void;
 54→
 55→export type ExpressMiddlewareConfig = MiddlewareConfig<ExpressRequest>;
 56→export type ExpressMiddlewareReturn = (
 57→  req: ExpressRequest,
 58→  res: ExpressResponse,
 59→  next: ExpressNextFunction
 60→) => void;
 61→
 62→// ============================================
 63→// Fastify Types (duck-typed)
 64→// ============================================
 65→
 66→export interface FastifyRequest {
 67→  method: string;
 68→  url: string;
 69→  routeOptions?: { url?: string };
 70→  routerPath?: string;
 71→  ip?: string;
 72→  headers: Record<string, string | string[] | undefined>;
 73→  body?: unknown;
 74→}
 75→
 76→export interface FastifyReply {
 77→  statusCode: number;
 78→}
 79→
 80→export interface FastifyInstance {
 81→  addHook(
 82→    name: 'onResponse',
 83→    handler: (
 84→      request: FastifyRequest,
 85→      reply: FastifyReply,
 86→      done: () => void
 87→    ) => void
 88→  ): void;
 89→}
 90→
 91→export type FastifyMiddlewareConfig = MiddlewareConfig<FastifyRequest>;
 92→export type FastifyPluginReturn = ((
 93→  instance: FastifyInstance,
 94→  opts: Record<string, unknown>,
 95→  done: (err?: Error) => void
 96→) => void) & { [key: symbol]: boolean };
 97→
 98→// ============================================
 99→// Hono Types (duck-typed)
100→// ============================================
101→
102→export interface HonoContext {
103→  req: {
104→    method: string;
105→    url: string;
106→    path: string;
107→    routePath: string;
108→    header(name: string): string | undefined;
109→    raw: { body?: unknown };
110→  };
111→  res: {
112→    status: number;
113→  };
114→}
115→
116→export type HonoNextFunction = () => Promise<void>;
117→
118→export type HonoMiddlewareConfig = MiddlewareConfig<HonoContext>;
119→export type HonoMiddlewareReturn = (
120→  c: HonoContext,
121→  next: HonoNextFunction
122→) => Promise<void>;
