 19→async function main() {
 20→  const databaseUrl = process.env.DATABASE_URL;
 21→  if (!databaseUrl) {
 22→    throw new Error('DATABASE_URL environment variable is required');
 23→  }
 24→
 25→  const redisUrl = process.env.REDIS_URL || 'redis://localhost:6379';
 26→  const concurrency = parseInt(process.env.WORKER_CONCURRENCY || '10', 10);
 27→
 28→  const db = createDb(databaseUrl);
 29→  const dataStoreManager = new DataStoreManager(db, decrypt);
 30→  dataStoreManager.startHealthChecks();
 31→  const redis = new Redis(redisUrl, { maxRetriesPerRequest: null });
 32→
 33→  console.log('🚀 LogSeal Worker starting...');
 34→  console.log(`📊 Concurrency: ${concurrency}`);
 35→
 36→  // Webhook delivery queue
 37→  const webhookQueue = new Queue('webhooks', { connection: redis });
 38→
 39→  // Retention cleanup queue (daily schedule)
 40→  const retentionQueue = new Queue('retention', { connection: redis });
 41→  await retentionQueue.add(
 42→    'retention-cleanup',
 43→    {},
 44→    {
 45→      repeat: {
 46→        pattern: '0 2 * * *', // Run daily at 2 AM
 47→      },
