 72→    },
 73→    {
 74→      connection: redis,
 75→      concurrency,
 76→    }
 77→  );
 78→
 79→  // Retention cleanup worker
 80→  const retentionWorker = new Worker(
 81→    'retention',
 82→    async () => {
 83→      return processRetentionCleanup(db, redis);
 84→    },
 85→    {
 86→      connection: redis,
 87→      concurrency: 1,
 88→    }
 89→  );
 90→
 91→  // Webhook delivery worker
 92→  const webhookWorker = new Worker(
 93→    'webhooks',
 94→    async (job) => {
 95→      return processWebhookJob(job.data, db);
 96→    },
 97→    {
 98→      connection: redis,
 99→      concurrency: 20,
100→    }
101→  );
102→
103→  // Merkle tree construction worker
104→  const merkleWorker = new Worker(
105→    'merkle-trees',
106→    async (job) => {
107→      if (job.name === 'build-merkle-tree') {
108→        return processMerkleJob(job.data, db, transparencyQueue);
109→      }
110→      console.warn(`Unknown merkle job type: ${job.name}`);
111→    },
