 36→export async function buildServer() {
 37→  const server = Fastify({
 38→    logger: {
 39→      level: process.env.LOG_LEVEL || 'info',
 40→      transport:
 41→        process.env.NODE_ENV === 'development'
 42→          ? {
 43→              target: 'pino-pretty',
 44→              options: {
 45→                translateTime: 'HH:MM:ss Z',
 46→                ignore: 'pid,hostname',
 47→              },
 48→            }
 49→          : undefined,
 50→    },
 51→  });
 52→
 53→  // Handle empty JSON bodies gracefully (e.g., POST with Content-Type: application/json but no body)
 54→  server.addContentTypeParser('application/json', { parseAs: 'string' }, (_req, body, done) => {
 55→    if (!body || (typeof body === 'string' && body.trim() === '')) {
 56→      done(null, undefined);
 57→      return;
 58→    }
 59→    try {
 60→      done(null, JSON.parse(body as string));
 61→    } catch (err) {
 62→      done(err as Error, undefined);
 63→    }
 64→  });
 65→
 66→  // Database connection
 67→  const databaseUrl = process.env.DATABASE_URL;
 68→  if (!databaseUrl) {
 69→    throw new Error('DATABASE_URL environment variable is required');
 70→  }
 71→  const db = createDb(databaseUrl);
 72→
 73→  // Redis connection
 74→  const redisUrl = process.env.REDIS_URL || 'redis://localhost:6379';
 75→  const redis = new Redis(redisUrl);
 76→
 77→  // Event queue for worker processing
 78→  const eventQueue = new Queue('audit-events', {
 79→    connection: redis,
 80→    defaultJobOptions: {
 81→      attempts: 3,
 82→      backoff: {
 83→        type: 'exponential',
 84→        delay: 1000,
 85→      },
 86→    },
 87→  });
 88→
 89→  // DataStore manager for BYOD
 90→  const dataStoreManager = new DataStoreManager(db, decrypt);
 91→
 92→  // Decorate fastify instance with shared resources
 93→  server.decorate('db', db);
 94→  server.decorate('redis', redis);
 95→  server.decorate('eventQueue', eventQueue);
 96→  server.decorate('dataStoreManager', dataStoreManager);
 97→
 98→  // Register plugins
 99→  await server.register(cors, {
100→    origin: [process.env.DASHBOARD_URL || 'http://localhost:3232'],
101→    credentials: true,
102→  });
103→
104→  await server.register(cookie);
105→
106→  // Raw body plugin for Stripe webhooks
107→  await server.register(rawBody, {
108→    field: 'rawBody',
109→    global: false,
110→    encoding: 'utf8',
111→    runFirst: true,
112→  });
113→
114→  await server.register(rateLimit, {
115→    max: 1000,
116→    timeWindow: '1 second',
117→    keyGenerator: (request) => {
118→      // Rate limit by account ID if authenticated, otherwise by IP
119→      return (request as any).account?.id || request.ip;
120→    },
121→  });
122→
123→  // Custom error handler
124→  server.setErrorHandler(errorHandler);
125→
126→  // Register auth plugin (decorates request with account info)
127→  await server.register(authPlugin);
128→
129→  // Register request logger (captures API requests for debugging)
130→  await server.register(requestLoggerPlugin);
131→
132→  // Register routes
133→  await server.register(healthRoutes);
134→  await server.register(authRoutes, { prefix: '/auth' });
135→  await server.register(twoFactorRoutes, { prefix: '/auth' });
136→  await server.register(billingRoutes, { prefix: '/billing' });
137→  await server.register(accountRoutes, { prefix: '/account' });
138→  await server.register(eventsRoutes, { prefix: '/v1' });
139→  await server.register(organizationsRoutes, { prefix: '/v1' });
140→  await server.register(schemasRoutes, { prefix: '/v1' });
141→  await server.register(viewerTokensRoutes, { prefix: '/v1' });
142→  await server.register(webhooksRoutes, { prefix: '/v1' });
143→  await server.register(exportsRoutes, { prefix: '/v1' });
144→  await server.register(apiKeysRoutes, { prefix: '/v1' });
145→  await server.register(requestLogsRoutes, { prefix: '/v1' });
146→  await server.register(actorsRoutes, { prefix: '/v1' });
147→  await server.register(merkleTreesRoutes, { prefix: '/v1' });
148→  await server.register(promoteRoutes, { prefix: '/v1' });
149→  await server.register(dataConnectionRoutes, { prefix: '/v1' });
150→  await server.register(adminRoutes, { prefix: '/admin' });
151→
152→  // Graceful shutdown
153→  server.addHook('onClose', async () => {
154→    await dataStoreManager.close();
155→    await eventQueue.close();
156→    await redis.quit();
157→  });
158→
159→  return server;
160→}
