107→      .limit(1);
108→
109→    const piiSeparationEnabled = accountRow?.piiConfig?.separate_pii === true;
110→
111→    // If PII separation is enabled, upsert actor profile and null out PII in event
112→    if (piiSeparationEnabled && (actor.name || actor.email)) {
113→      await db
114→        .insert(actorProfiles)
115→        .values({
116→          accountId,
117→          environment,
118→          actorId: actor.id,
119→          name: actor.name || null,
120→          email: actor.email || null,
121→          metadata: actor.metadata || {},
122→        })
123→        .onConflictDoUpdate({
124→          target: [actorProfiles.accountId, actorProfiles.actorId, actorProfiles.environment],
125→          set: {
126→            name: actor.name || null,
127→            email: actor.email || null,
128→            metadata: actor.metadata || {},
129→            updatedAt: new Date(),
130→          },
131→        });
132→    }
133→
134→    // Compute skip-list hashes for O(log n) range verification
135→    let skipHashes: Array<{ offset: number; seq: number; hash: string }> | null = null;
136→    if (sequenceNumber > 1) {
137→      const offsets = computeSkipOffsets(sequenceNumber);
138→      const skipSeqs = offsets.map((o) => sequenceNumber - o);
139→
140→      const predecessors = await dataStore.getEventsBySequenceNumbers(organizationId, accountId, skipSeqs);
141→
142→      const hashBySeq = new Map(predecessors.map((p) => [p.sequenceNumber, p.eventHash]));
143→      skipHashes = offsets
144→        .map((offset) => {
145→          const seq = sequenceNumber - offset;
146→          const hash = hashBySeq.get(seq);
147→          if (hash) return { offset, seq, hash };
148→          return null;
149→        })
150→        .filter((h): h is NonNullable<typeof h> => h !== null);
151→    }
152→
153→    // Insert the event — with PII separation, name/email are null in audit_events
154→    await dataStore.insertEvent({
155→      id: eventId,
156→      accountId,
157→      organizationId,
158→      environment,
159→      action,
160→      actorId: actor.id,
161→      actorType: actor.type || 'user',
162→      actorName: piiSeparationEnabled ? null : actor.name,
163→      actorEmail: piiSeparationEnabled ? null : actor.email,
164→      actorMetadata: actor.metadata || {},
165→      targets: targets || [],
166→      metadata: metadata || {},
167→      ipAddress: context.ip_address,
168→      userAgent: context.user_agent,
169→      requestId: context.request_id,
170→      occurredAt: new Date(occurredAt),
171→      previousHash,
172→      eventHash,
173→      sequenceNumber,
174→      idempotencyKey,
175→      skipHashes,
176→    });
177→
178→    sequenceNumberResult = sequenceNumber;
179→  } finally {
180→    await releaseLock(redis, lockKey, lock.token);
181→  }
182→
183→  // Trigger Merkle tree build at batch boundaries (outside the lock)
184→  if (merkleQueue && sequenceNumberResult > 0 && sequenceNumberResult % 1024 === 0) {
185→    await merkleQueue.add(
186→      'build-merkle-tree',
187→      {
188→        organizationId,
189→        environment,
190→        toSequence: sequenceNumberResult,
191→      },
192→      {
193→        jobId: `merkle-${organizationId}-${environment}-${sequenceNumberResult}`,
194→        attempts: 3,
195→        backoff: { type: 'exponential', delay: 2000 },
196→      }
197→    );
198→  }
199→
200→  // Fan out to webhooks (outside the lock — no need to hold it during webhook queuing)
201→  const activeWebhooks = await db
202→    .select()
203→    .from(webhooks)
204→    .where(
205→      and(
206→        eq(webhooks.accountId, accountId),
207→        eq(webhooks.environment, environment),
208→        eq(webhooks.enabled, true)
209→      )
210→    );
211→
212→  for (const webhook of activeWebhooks) {
213→    // Check if webhook is scoped to this org or applies to all orgs
214→    if (webhook.organizationId && webhook.organizationId !== organizationId) {
215→      continue;
216→    }
217→
218→    // Check if webhook subscribes to this event type
219→    if (webhook.events.length > 0) {
220→      const matches = webhook.events.some((pattern) => {
221→        if (pattern === '*' || pattern === 'event.*' || pattern === 'event.created') {
222→          return true;
223→        }
224→        // Support patterns like 'user.*' matching 'user.created'
225→        if (pattern.endsWith('.*')) {
226→          const prefix = pattern.slice(0, -1);
227→          return action.startsWith(prefix);
228→        }
229→        return action === pattern;
230→      });
231→
232→      if (!matches) continue;
233→    }
234→
235→    // Queue webhook delivery — only pass webhookId, not secret/url
236→    await webhookQueue.add(
237→      'deliver',
238→      {
239→        webhookId: webhook.id,
240→        eventId,
241→        payload: {
242→          id: eventId,
243→          type: 'event.created',
244→          created: new Date().toISOString(),
245→          data: {
246→            object: {
247→              id: eventId,
248→              action,
249→              actor: {
250→                id: actor.id,
251→                type: actor.type || 'user',
252→                name: actor.name,
253→                email: actor.email,
254→              },
255→              targets,
256→              metadata,
257→              occurred_at: occurredAt,
258→              organization_id: organizationId,
259→            },
260→          },
261→        },
262→      },
263→      {
264→        attempts: 5,
265→        backoff: {
266→          type: 'exponential',
267→          delay: 1000,
268→        },
269→      }
270→    );
271→  }
272→}
