  73→async function validateAgainstSchema(
  74→  db: Database,
  75→  accountId: string,
  76→  environment: 'test' | 'live',
  77→  action: string,
  78→  targets: Array<{ type: string; id: string }>,
  79→  metadata: Record<string, unknown>,
  80→): Promise<void> {
  81→  const [schema] = await db
  82→    .select()
  83→    .from(eventSchemas)
  84→    .where(and(
  85→      eq(eventSchemas.accountId, accountId),
  86→      eq(eventSchemas.action, action),
  87→      eq(eventSchemas.environment, environment),
  88→      eq(eventSchemas.isActive, true),
  89→    ))
  90→    .limit(1);
  91→
  92→  if (!schema) {
  93→    throw errors.schemaNotFound(action);
  94→  }
  95→
  96→  if (schema.targetTypes.length > 0) {
  97→    const allowedTypes = new Set(schema.targetTypes);
  98→    for (const target of targets) {
  99→      if (!allowedTypes.has(target.type)) {
 100→        throw errors.schemaValidationFailed(
 101→          `Target type '${target.type}' is not allowed by the schema for '${action}'. Allowed: ${schema.targetTypes.join(', ')}`
 102→        );
 103→      }
 104→    }
 105→  }
 106→
 107→  if (schema.metadataSchema) {
 108→    const requiredKeys = Object.keys(schema.metadataSchema);
 109→    for (const key of requiredKeys) {
 110→      if (!(key in metadata)) {
 111→        throw errors.schemaValidationFailed(
 112→          `Missing required metadata field '${key}' for action '${action}'.`
 113→        );
 114→      }
 115→    }
 116→  }
 117→}
