 119→export const eventsRoutes: FastifyPluginAsync = async (fastify) => {
 120→  const getDS = (accountId: string) => fastify.dataStoreManager.getDataStore(accountId);
 121→
 122→  // POST /v1/events - Emit a single event
 123→  fastify.post('/events', async (request, reply) => {
 124→    const account = request.account;
 125→    if (!account) {
 126→      throw errors.missingApiKey();
 127→    }
 128→
 129→    const input = emitEventSchema.parse(request.body);
 130→    const orgExternalId = input.organization_id || DEFAULT_ORG_EXTERNAL_ID;
 131→
 132→    // Check schema enforcement
 133→    const [enforcementAccount] = await fastify.db
 134→      .select({ schemaEnforcement: accounts.schemaEnforcement })
 135→      .from(accounts)
 136→      .where(eq(accounts.id, account.accountId))
 137→      .limit(1);
 138→
 139→    if (enforcementAccount?.schemaEnforcement === 'strict') {
 140→      await validateAgainstSchema(
 141→        fastify.db,
 142→        account.accountId,
 143→        account.environment,
 144→        input.action,
 145→        input.targets,
 146→        input.metadata,
 147→      );
 148→    }
 149→
 150→    // Check entitlement (compliance-safe: allow writes even when defaulted)
 151→    const { allowed, limit } = await checkEntitlement(
 152→      fastify.db,
 153→      fastify.redis,
 154→      account.accountId,
 155→      account.environment,
 156→      'eventsPerMonth'
 157→    );
 158→
 159→    if (!allowed) {
 160→      throw errors.entitlementExceeded('events per month', limit);
 161→    }
 162→
 163→    // Verify organization exists or create it
 164→    const ds = await getDS(account.accountId);
 165→    let org = await ds.getOrganizationByExternalId(account.accountId, orgExternalId, account.environment);
 166→
 167→    if (!org) {
 168→      // Auto-create organization
 169→      org = await ds.insertOrganization({
 170→        accountId: account.accountId,
 171→        externalId: orgExternalId,
 172→        environment: account.environment,
 173→      });
 174→    }
 175→
 176→    // Check for idempotency
 177→    if (input.idempotency_key) {
 178→      const existing = await ds.getEventsByIdempotencyKey(account.accountId, input.idempotency_key);
 179→
 180→      if (existing) {
 181→        return reply.status(200).send({
 182→          id: existing.id,
 183→          action: input.action,
 184→          occurred_at: input.occurred_at || new Date().toISOString(),
 185→          received_at: new Date().toISOString(),
 186→          organization_id: orgExternalId,
 187→          object: 'event',
 188→        });
 189→      }
 190→    }
 191→
 192→    const eventId = createEventId();
 193→    const occurredAt = input.occurred_at ? new Date(input.occurred_at) : new Date();
 194→
 195→    // Queue the event for processing (hash chain computation happens in worker)
 196→    await fastify.eventQueue.add(
 197→      'process-event',
 198→      {
 199→        eventId,
 200→        accountId: account.accountId,
 201→        organizationId: org.id,
 202→        environment: account.environment,
 203→        action: input.action,
 204→        actor: input.actor,
 205→        targets: input.targets,
 206→        metadata: input.metadata,
 207→        context: input.context || {},
 208→        occurredAt: occurredAt.toISOString(),
 209→        idempotencyKey: input.idempotency_key,
 210→      },
 211→      {
 212→        jobId: eventId,
 213→      }
 214→    );
 215→
 216→    // Increment usage (async, don't block response)
 217→    incrementUsage(fastify.db, fastify.redis, account.accountId, account.environment, 'eventsCount').catch((err) =>
 218→      fastify.log.error(err, 'Failed to increment events usage')
 219→    );
 220→
 221→    // Auto-detect schema (fire-and-forget)
 222→    autoDetectSchema(
 223→      fastify.db, account.accountId, account.environment,
 224→      input.action, input.targets, input.metadata
 225→    ).catch((err) => fastify.log.error(err, 'Failed to auto-detect schema'));
 226→
 227→    return reply.status(202).send({
 228→      id: eventId,
 229→      action: input.action,
 230→      occurred_at: occurredAt.toISOString(),
 231→      received_at: new Date().toISOString(),
 232→      organization_id: orgExternalId,
 233→      object: 'event',
 234→    });
 235→  });
 236→
 237→  // POST /v1/events/batch - Emit multiple events
 238→  fastify.post('/events/batch', async (request, reply) => {
 239→    const account = request.account;
 240→    if (!account) {
 241→      throw errors.missingApiKey();
 242→    }
 243→
 244→    const input = batchEmitSchema.parse(request.body);
 245→    const results: Array<{
 246→      id: string | null;
 247→      action: string;
 248→      status: 'accepted' | 'rejected';
 249→      error?: { code: string; message: string };
 250→    }> = [];
 251→
 252→    let accepted = 0;
 253→    let rejected = 0;
 254→    const acceptedEventsForSchema: Array<{
 255→      action: string;
 256→      targets: Array<{ type: string; id: string; [key: string]: unknown }>;
 257→      metadata: Record<string, unknown>;
 258→    }> = [];
 259→
 260→    // Check schema enforcement once for the batch
 261→    const [batchEnforcementAccount] = await fastify.db
 262→      .select({ schemaEnforcement: accounts.schemaEnforcement })
 263→      .from(accounts)
 264→      .where(eq(accounts.id, account.accountId))
 265→      .limit(1);
 266→    const isStrict = batchEnforcementAccount?.schemaEnforcement === 'strict';
 267→
 268→    // Pre-fetch all referenced organizations in a single query
 269→    const ds = await getDS(account.accountId);
 270→    // Safely extract org IDs from raw (unvalidated) events
 271→    const uniqueOrgExternalIds = [
 272→      ...new Set(
 273→        input.events
 274→          .map((e: any) => e?.organization_id)
 275→          .filter((id: unknown): id is string => typeof id === 'string' && id.length > 0)
 276→          .concat(DEFAULT_ORG_EXTERNAL_ID)
 277→      ),
 278→    ];
 279→    const existingOrgs = await ds.getOrganizationsByExternalIds(account.accountId, uniqueOrgExternalIds, account.environment);
 280→    const orgMap = new Map(existingOrgs.map((o) => [o.externalId, o]));
 281→
 282→    // Pre-fetch schemas if strict mode
 283→    let schemaMap: Map<string, typeof eventSchemas.$inferSelect> | undefined;
 284→    if (isStrict) {
 285→      const uniqueActions = [
 286→        ...new Set(
 287→          input.events
 288→            .map((e: any) => e?.action)
 289→            .filter((a: unknown): a is string => typeof a === 'string' && a.length > 0)
 290→        ),
 291→      ];
 292→      if (uniqueActions.length > 0) {
 293→        const existingSchemas = await fastify.db
 294→          .select()
 295→          .from(eventSchemas)
 296→          .where(
 297→            and(
 298→              eq(eventSchemas.accountId, account.accountId),
 299→              eq(eventSchemas.environment, account.environment),
 300→              inArray(eventSchemas.action, uniqueActions),
 301→              eq(eventSchemas.isActive, true)
 302→            )
 303→          );
 304→        schemaMap = new Map(existingSchemas.map((s) => [s.action, s]));
 305→      }
 306→    }
 307→
 308→    for (const rawEvent of input.events) {
 309→      try {
 310→        // Validate individual event schema
 311→        const event = emitEventSchema.parse(rawEvent);
 312→
 313→        // Validate against schema if strict mode (using pre-fetched schemas)
 314→        if (isStrict && schemaMap) {
 315→          const schema = schemaMap.get(event.action);
 316→          if (!schema) {
 317→            throw errors.schemaNotFound(event.action);
 318→          }
 319→
 320→          const eventTargets = event.targets ?? [];
 321→          if (schema.targetTypes.length > 0) {
 322→            const allowedTypes = new Set(schema.targetTypes);
 323→            for (const target of eventTargets) {
 324→              if (!allowedTypes.has(target.type)) {
 325→                throw errors.schemaValidationFailed(
 326→                  `Target type '${target.type}' is not allowed by the schema for '${event.action}'. Allowed: ${schema.targetTypes.join(', ')}`
 327→                );
 328→              }
 329→            }
 330→          }
 331→
 332→          if (schema.metadataSchema) {
 333→            const eventMetadata = event.metadata ?? {};
 334→            const requiredKeys = Object.keys(schema.metadataSchema);
 335→            for (const key of requiredKeys) {
 336→              if (!(key in eventMetadata)) {
 337→                throw errors.schemaValidationFailed(
 338→                  `Missing required metadata field '${key}' for action '${event.action}'.`
 339→                );
 340→              }
 341→            }
 342→          }
 343→        }
 344→
 345→        const eventOrgExternalId = event.organization_id || DEFAULT_ORG_EXTERNAL_ID;
 346→
 347→        // Look up org from pre-fetched map; create if missing
 348→        let org = orgMap.get(eventOrgExternalId);
 349→        if (!org) {
 350→          org = await ds.insertOrganization({
 351→            accountId: account.accountId,
 352→            externalId: eventOrgExternalId,
 353→            environment: account.environment,
 354→          });
 355→          orgMap.set(eventOrgExternalId, org);
 356→        }
 357→
 358→        const eventId = createEventId();
 359→        const occurredAt = event.occurred_at ? new Date(event.occurred_at) : new Date();
 360→
 361→        await fastify.eventQueue.add(
 362→          'process-event',
 363→          {
 364→            eventId,
 365→            accountId: account.accountId,
 366→            organizationId: org.id,
 367→            environment: account.environment,
 368→            action: event.action,
 369→            actor: event.actor,
 370→            targets: event.targets,
 371→            metadata: event.metadata,
 372→            context: event.context || {},
 373→            occurredAt: occurredAt.toISOString(),
 374→            idempotencyKey: event.idempotency_key,
 375→          },
 376→          { jobId: eventId }
 377→        );
 378→
 379→        results.push({
 380→          id: eventId,
 381→          action: event.action,
 382→          status: 'accepted',
 383→        });
 384→        accepted++;
 385→        acceptedEventsForSchema.push({
 386→          action: event.action,
 387→          targets: event.targets ?? [],
 388→          metadata: event.metadata ?? {},
 389→        });
 390→      } catch (err: any) {
 391→        results.push({
 392→          id: null,
 393→          action: (rawEvent as any)?.action || 'unknown',
 394→          status: 'rejected',
 395→          error: {
 396→            code: err.code || 'validation_error',
 397→            message: err.message || 'Failed to process event',
 398→          },
 399→        });
 400→        rejected++;
 401→      }
 402→    }
 403→
 404→    // Auto-detect schemas for accepted events (fire-and-forget)
 405→    if (acceptedEventsForSchema.length > 0) {
 406→      autoDetectSchemaBatch(
 407→        fastify.db, account.accountId, account.environment,
 408→        acceptedEventsForSchema
 409→      ).catch((err) => fastify.log.error(err, 'Failed to auto-detect batch schemas'));
 410→    }
 411→
 412→    return reply.status(202).send({
 413→      events: results,
 414→      accepted,
 415→      rejected,
 416→      object: 'batch',
 417→    });
 418→  });
 419→
 420→  // GET /v1/events - List events
 421→  fastify.get('/events', async (request, reply) => {
 422→    const account = request.account;
 423→    const viewerToken = request.viewerToken;
 424→
 425→    if (!account && !viewerToken) {
