 427→    }
 428→
 429→    // Check for defaulted account (block reads but allow writes for compliance)
 430→    if (account?.accountStatus === 'defaulted') {
 431→      throw errors.accountDefaulted();
 432→    }
 433→
 434→    const params = listEventsSchema.parse(request.query);
 435→    const listOrgExternalId = params.organization_id || DEFAULT_ORG_EXTERNAL_ID;
 436→
 437→    const accountId = account?.accountId || viewerToken!.accountId;
 438→    const environment = account?.environment || viewerToken!.environment;
 439→
 440→    const ds = await getDS(accountId);
 441→
 442→    // If using viewer token, verify org access
 443→    if (viewerToken) {
 444→      const org = await ds.getOrganizationByExternalId(viewerToken.accountId, listOrgExternalId, viewerToken.environment);
 445→
 446→      if (!org || org.id !== viewerToken.organizationId) {
