 460→    }
 461→
 462→    // Decode cursors if provided
 463→    let cursorAfter: { id: string; t: string } | undefined;
 464→    let cursorBefore: { id: string; t: string } | undefined;
 465→    if (params.starting_after) {
 466→      try {
 467→        const decoded = JSON.parse(Buffer.from(params.starting_after, 'base64').toString());
 468→        cursorAfter = { id: decoded.id, t: decoded.t };
 469→      } catch {
 470→        // Invalid cursor, ignore
 471→      }
 472→    } else if (params.ending_before) {
 473→      try {
 474→        const decoded = JSON.parse(Buffer.from(params.ending_before, 'base64').toString());
 475→        cursorBefore = { id: decoded.id, t: decoded.t };
 476→      } catch {
 477→        // Invalid cursor, ignore
 478→      }
 479→    }
 480→
 481→    const { events, hasMore } = await ds.getEvents(
 482→      accountId,
 483→      org.id,
 484→      environment,
 485→      {
 486→        action: params.action,
 487→        actionPrefix: params.action_prefix,
 488→        actorId: params.actor_id,
 489→        after: params.after ? new Date(params.after) : undefined,
 490→        before: params.before ? new Date(params.before) : undefined,
 491→        limit: params.limit,
 492→        cursorAfter,
 493→        cursorBefore,
 494→      }
