 737→  fastify.post('/events/verify-range', async (request, reply) => {
 738→    const account = request.account;
 739→    if (!account) {
 740→      throw errors.missingApiKey();
 741→    }
 742→
 743→    if (account.accountStatus === 'defaulted') {
 744→      throw errors.accountDefaulted();
 745→    }
 746→
 747→    const verifyRangeSchema = z.object({
 748→      organization_id: z.string().min(1).optional(),
 749→      from_sequence: z.number().int().min(1),
 750→      to_sequence: z.number().int().min(1),
 751→    });
 752→
 753→    const { organization_id, from_sequence, to_sequence } = verifyRangeSchema.parse(request.body);
 754→    const rangeOrgExternalId = organization_id || DEFAULT_ORG_EXTERNAL_ID;
 755→
 756→    if (from_sequence > to_sequence) {
 757→      throw errors.invalidFieldValue('from_sequence', 'from_sequence must be less than or equal to to_sequence');
 758→    }
 759→
 760→    // Get organization
 761→    const ds = await getDS(account.accountId);
 762→    const org = await ds.getOrganizationByExternalId(account.accountId, rangeOrgExternalId, account.environment);
 763→
 764→    if (!org) {
 765→      throw errors.notFound('organization');
 766→    }
 767→
 768→    // Fetch the from and to events
 769→    const fromEvent = await ds.getEventBySequenceNumber(org.id, account.accountId, from_sequence);
 770→    const toEvent = await ds.getEventBySequenceNumber(org.id, account.accountId, to_sequence);
 771→
 772→    if (!fromEvent || !toEvent) {
 773→      throw errors.notFound('event');
 774→    }
 775→
 776→    // Check if skip hashes are available for skip-list verification
 777→    if (toEvent.skipHashes && toEvent.skipHashes.length > 0) {
 778→      // Use skip-list path for O(log n) verification
 779→      const { computeSkipVerificationPath } = await import('@logseal/utils');
 780→      const path = computeSkipVerificationPath(from_sequence, to_sequence);
 781→
 782→      // Fetch all events in the path via DataStore
 783→      const pathEventsList = await Promise.all(
 784→        path.map((seq) => ds.getEventBySequenceNumber(org.id, account.accountId, seq))
 785→      );
 786→      const pathEvents = pathEventsList.filter((e): e is NonNullable<typeof e> => e !== null);
 787→
 788→      const eventBySeq = new Map(pathEvents.map((e) => [e.sequenceNumber, e]));
 789→
 790→      // Verify each link in the skip path
 791→      for (let i = 1; i < path.length; i++) {
 792→        const currentSeq = path[i];
 793→        const prevSeq = path[i - 1];
 794→        const currentEvent = eventBySeq.get(currentSeq);
 795→        const prevEvent = eventBySeq.get(prevSeq);
 796→
 797→        if (!currentEvent || !prevEvent) {
 798→          return reply.send({
 799→            status: 'unverifiable',
 800→            reason: `Event at sequence ${!currentEvent ? currentSeq : prevSeq} not found`,
 801→            events_checked: i,
 802→            verified_at: new Date().toISOString(),
 803→          });
 804→        }
 805→
 806→        // Check if currentEvent has a skip hash pointing to prevEvent
 807→        const offset = currentSeq - prevSeq;
 808→        const skipEntry = currentEvent.skipHashes?.find(
 809→          (s) => s.offset === offset && s.seq === prevSeq
 810→        );
 811→
 812→        if (skipEntry) {
 813→          if (skipEntry.hash !== prevEvent.eventHash) {
 814→            return reply.send({
 815→              status: 'broken',
 816→              broken_at_sequence: currentSeq,
 817→              expected_hash: prevEvent.eventHash,
 818→              skip_hash: skipEntry.hash,
 819→              events_checked: path.length,
 820→              verified_at: new Date().toISOString(),
 821→            });
 822→          }
 823→        } else {
 824→          // Fall back to checking direct chain linkage if skip hash not available
 825→          if (offset === 1 && currentEvent.previousHash !== prevEvent.eventHash) {
 826→            return reply.send({
 827→              status: 'broken',
 828→              broken_at_sequence: currentSeq,
 829→              expected_hash: prevEvent.eventHash,
 830→              actual_hash: currentEvent.previousHash,
 831→              events_checked: path.length,
 832→              verified_at: new Date().toISOString(),
 833→            });
 834→          }
 835→        }
 836→      }
 837→
 838→      return reply.send({
 839→        status: 'valid',
 840→        events_checked: path.length,
 841→        verification_method: 'skip_list',
 842→        path_length: path.length,
 843→        range: { from: from_sequence, to: to_sequence },
 844→        verified_at: new Date().toISOString(),
 845→      });
 846→    }
 847→
 848→    // Fallback: sequential walk for pre-migration events without skipHashes
 849→    const BATCH_SIZE = 10_000;
 850→    let expectedPreviousHash: string | null = fromEvent.previousHash;
 851→    let eventsChecked = 0;
 852→    let lastSequence = from_sequence - 1;
 853→
 854→    while (lastSequence < to_sequence) {
 855→      const batch = await ds.getChainBatch(org.id, account.accountId, lastSequence, BATCH_SIZE, undefined, to_sequence);
 856→
 857→      if (batch.length === 0) break;
 858→
 859→      for (const event of batch) {
 860→        if (event.previousHash !== expectedPreviousHash) {
 861→          return reply.send({
 862→            status: 'broken',
 863→            broken_at: event.id,
 864→            broken_at_sequence: event.sequenceNumber,
 865→            expected_hash: expectedPreviousHash,
 866→            actual_hash: event.previousHash,
 867→            events_checked: eventsChecked,
 868→            verified_at: new Date().toISOString(),
 869→          });
 870→        }
 871→        expectedPreviousHash = event.eventHash;
 872→        eventsChecked++;
 873→      }
 874→
 875→      lastSequence = batch[batch.length - 1].sequenceNumber;
 876→    }
 877→
 878→    return reply.send({
 879→      status: 'valid',
 880→      events_checked: eventsChecked,
 881→      verification_method: 'sequential',
 882→      range: { from: from_sequence, to: to_sequence },
 883→      verified_at: new Date().toISOString(),
 884→    });
 885→  });
