 887→  // POST /v1/events/verify - Verify hash chain integrity with deep content verification
 888→  fastify.post('/events/verify', async (request, reply) => {
 889→    const account = request.account;
 890→    if (!account) {
 891→      throw errors.missingApiKey();
 892→    }
 893→
 894→    const verifyBodySchema = z.object({
 895→      organization_id: z.string().min(1).optional(),
 896→      after: z.string().datetime().optional(),
 897→      before: z.string().datetime().optional(),
 898→    });
 899→
 900→    const { organization_id, after, before } = verifyBodySchema.parse(request.body);
 901→    const verifyOrgExternalId = organization_id || DEFAULT_ORG_EXTERNAL_ID;
 902→
 903→    // Get organization
 904→    const ds = await getDS(account.accountId);
 905→    const org = await ds.getOrganizationByExternalId(account.accountId, verifyOrgExternalId, account.environment);
 906→
 907→    if (!org) {
 908→      throw errors.notFound('organization');
 909→    }
 910→
 911→    // Verify chain in batches to avoid loading all events into memory
 912→    const VERIFY_BATCH_SIZE = 10_000;
 913→    let expectedPreviousHash: string | null = null;
 914→    let eventsChecked = 0;
 915→    let chainStart: string | null = null;
 916→    let chainEnd: string | null = null;
 917→    let lastSequence = 0;
 918→    let isFirstBatch = true;
 919→
 920→    while (true) {
 921→      const dateRange = {
 922→        ...(after && { after: new Date(after) }),
 923→        ...(before && { before: new Date(before) }),
 924→      };
 925→
 926→      // Fetch full event data for deep content verification
 927→      const batch = await ds.getFullEventBatch(
 928→        org.id,
 929→        account.accountId,
 930→        lastSequence,
 931→        VERIFY_BATCH_SIZE,
 932→        Object.keys(dateRange).length > 0 ? dateRange : undefined
 933→      );
 934→
 935→      if (batch.length === 0) break;
 936→
 937→      // On first batch with a date filter, trust the first event's previousHash
 938→      if (isFirstBatch && after) {
 939→        expectedPreviousHash = batch[0].previousHash;
 940→      }
 941→      isFirstBatch = false;
 942→
 943→      if (!chainStart) {
 944→        chainStart = batch[0].id;
 945→      }
 946→
 947→      for (let i = 0; i < batch.length; i++) {
 948→        const event = batch[i];
 949→
 950→        // Chain linkage check
 951→        if (event.previousHash !== expectedPreviousHash) {
 952→          return reply.send({
 953→            status: 'broken',
 954→            events_checked: eventsChecked + i,
 955→            broken_at: event.id,
 956→            expected_hash: expectedPreviousHash,
 957→            actual_hash: event.previousHash,
 958→            verified_at: new Date().toISOString(),
 959→          });
 960→        }
 961→
 962→        // Deep content verification: recompute hash from stored event fields
 963→        // Convert null → undefined so JSON serialization matches the original hash input
 964→        const eventData: EventForHashing = {
 965→          action: event.action,
 966→          actor: {
 967→            id: event.actorId,
 968→            type: event.actorType,
 969→            ...(event.actorName != null && { name: event.actorName }),
 970→            ...(event.actorEmail != null && { email: event.actorEmail }),
 971→            metadata: event.actorMetadata || {},
 972→          },
 973→          targets: event.targets || [],
 974→          metadata: event.metadata || {},
 975→          occurred_at: event.occurredAt.toISOString(),
 976→          organization_id: event.organizationId,
 977→          sequence_number: event.sequenceNumber,
 978→        };
 979→
 980→        const recomputedHash = computeEventHash(event.previousHash, eventData);
 981→        if (recomputedHash !== event.eventHash) {
 982→          return reply.send({
 983→            status: 'content_tampered',
 984→            events_checked: eventsChecked + i,
 985→            tampered_event_id: event.id,
 986→            expected_hash: recomputedHash,
 987→            stored_hash: event.eventHash,
 988→            verified_at: new Date().toISOString(),
 989→          });
 990→        }
 991→
 992→        expectedPreviousHash = event.eventHash;
 993→      }
 994→
 995→      eventsChecked += batch.length;
 996→      chainEnd = batch[batch.length - 1].id;
 997→      lastSequence = batch[batch.length - 1].sequenceNumber;
 998→
 999→      // If we got fewer than VERIFY_BATCH_SIZE, we're done
1000→      if (batch.length < VERIFY_BATCH_SIZE) break;
1001→    }
1002→
1003→    if (eventsChecked === 0) {
1004→      return reply.send({
1005→        status: 'valid',
1006→        content_verified: true,
1007→        events_checked: 0,
1008→        verified_at: new Date().toISOString(),
1009→      });
1010→    }
1011→
1012→    return reply.send({
1013→      status: 'valid',
1014→      content_verified: true,
1015→      events_checked: eventsChecked,
1016→      chain_start: chainStart,
1017→      chain_end: chainEnd,
1018→      verified_at: new Date().toISOString(),
1019→    });
1020→  });
1021→};
