393→async function handleSubscriptionUpdated(fastify: any, stripeSubscription: any) {
394→  const accountId = stripeSubscription.metadata?.logseal_account_id;
395→  if (!accountId) {
396→    // Try to find by stripe subscription ID
397→    const [sub] = await fastify.db
398→      .select()
399→      .from(subscriptions)
400→      .where(eq(subscriptions.stripeSubscriptionId, stripeSubscription.id))
401→      .limit(1);
402→
403→    if (!sub) {
404→      fastify.log.warn('Subscription update missing account mapping');
405→      return;
406→    }
407→
408→    await updateSubscriptionFromStripe(fastify, sub.accountId, stripeSubscription);
409→  } else {
410→    await updateSubscriptionFromStripe(fastify, accountId, stripeSubscription);
411→  }
412→}
