452→async function handleSubscriptionDeleted(fastify: any, stripeSubscription: any) {
453→  // Find subscription by Stripe ID
454→  const [sub] = await fastify.db
455→    .select()
456→    .from(subscriptions)
457→    .where(eq(subscriptions.stripeSubscriptionId, stripeSubscription.id))
458→    .limit(1);
459→
460→  if (!sub) {
461→    return;
462→  }
463→
464→  // Get default free plan
465→  const [defaultPlan] = await fastify.db
466→    .select()
467→    .from(plans)
468→    .where(and(eq(plans.isDefault, true), eq(plans.active, true)))
469→    .limit(1);
470→
471→  if (defaultPlan) {
472→    // Revert to free plan
473→    const now = new Date();
474→    const periodEnd = new Date(now);
475→    periodEnd.setMonth(periodEnd.getMonth() + 1);
476→
477→    await fastify.db
478→      .update(subscriptions)
479→      .set({
480→        planId: defaultPlan.id,
481→        stripeSubscriptionId: null,
482→        stripeStatus: null,
483→        currentPeriodStart: now,
484→        currentPeriodEnd: periodEnd,
485→        cancelAtPeriodEnd: false,
486→        updatedAt: new Date(),
487→      })
488→      .where(eq(subscriptions.id, sub.id));
489→  }
490→
491→  // Update account status
492→  await fastify.db
493→    .update(accounts)
494→    .set({ accountStatus: 'cancelled' })
495→    .where(eq(accounts.id, sub.accountId));
496→}
