498→async function handleInvoicePaymentSucceeded(fastify: any, invoice: any) {
499→  if (!invoice.subscription) {
500→    return;
501→  }
502→
503→  // Find subscription by Stripe ID
504→  const [sub] = await fastify.db
505→    .select()
506→    .from(subscriptions)
507→    .where(eq(subscriptions.stripeSubscriptionId, invoice.subscription))
508→    .limit(1);
509→
510→  if (!sub) {
511→    return;
512→  }
513→
514→  // Update account status to active
515→  await fastify.db
516→    .update(accounts)
517→    .set({ accountStatus: 'active' })
518→    .where(eq(accounts.id, sub.accountId));
519→
520→  // Create new usage records for the billing period — one per environment
521→  const periodStart = new Date(invoice.period_start * 1000);
522→  const periodEnd = new Date(invoice.period_end * 1000);
523→
524→  for (const env of ['test', 'live'] as const) {
525→    const [existingUsage] = await fastify.db
526→      .select()
527→      .from(usageRecords)
528→      .where(
529→        and(
530→          eq(usageRecords.accountId, sub.accountId),
531→          eq(usageRecords.environment, env),
532→          eq(usageRecords.periodStart, periodStart),
533→        )
534→      )
535→      .limit(1);
536→
537→    if (!existingUsage) {
538→      await fastify.db.insert(usageRecords).values({
539→        accountId: sub.accountId,
540→        environment: env,
541→        periodStart,
542→        periodEnd,
543→      });
544→    }
545→  }
546→}
