548→async function handleInvoicePaymentFailed(fastify: any, invoice: any) {
549→  if (!invoice.subscription) {
550→    return;
551→  }
552→
553→  // Find subscription by Stripe ID
554→  const [sub] = await fastify.db
555→    .select()
556→    .from(subscriptions)
557→    .where(eq(subscriptions.stripeSubscriptionId, invoice.subscription))
558→    .limit(1);
559→
560→  if (!sub) {
561→    return;
562→  }
563→
564→  // Update account status to defaulted after grace period
565→  // Stripe typically sends this after multiple retry attempts
566→  if (invoice.attempt_count >= 3) {
567→    await fastify.db
568→      .update(accounts)
569→      .set({ accountStatus: 'defaulted' })
570→      .where(eq(accounts.id, sub.accountId));
571→  }
572→}
