  1→import { eq, and, lt, gt, inArray, sql } from 'drizzle-orm';
  2→import { accounts, auditEvents, subscriptions, plans, usageRecords, type Database } from '@logseal/database';
  3→import type { Redis } from 'ioredis';
  4→
  5→const BATCH_SIZE = 1000;
  6→
  7→interface AccountRetention {
  8→  accountId: string;
  9→  retentionDays: number;
 10→}
 11→
 12→/**
 13→ * Process retention cleanup for all accounts.
 14→ * Deletes audit events older than the plan's retentionDays.
 15→ */
 16→export async function processRetentionCleanup(
 17→  db: Database,
 18→  redis: Redis,
 19→): Promise<void> {
 20→  // Get all active accounts with their retention settings
 21→  const accountRetentions = await db
 22→    .select({
 23→      accountId: accounts.id,
 24→      entitlements: plans.entitlements,
 25→    })
 26→    .from(accounts)
 27→    .innerJoin(subscriptions, eq(subscriptions.accountId, accounts.id))
 28→    .innerJoin(plans, eq(plans.id, subscriptions.planId))
 29→    .where(eq(accounts.accountStatus, 'active'));
 30→
 31→  const retentionConfigs: AccountRetention[] = accountRetentions
 32→    .map((row) => ({
 33→      accountId: row.accountId,
 34→      retentionDays: row.entitlements.retentionDays,
 35→    }))
 36→    .filter((config) => config.retentionDays > 0); // Skip unlimited (-1)
 37→
 38→  for (const config of retentionConfigs) {
 39→    await purgeExpiredEvents(db, redis, config);
 40→  }
 41→}
 42→
 43→async function purgeExpiredEvents(
 44→  db: Database,
 45→  redis: Redis,
 46→  config: AccountRetention,
 47→): Promise<void> {
 48→  const cutoffDate = new Date();
 49→  cutoffDate.setDate(cutoffDate.getDate() - config.retentionDays);
 50→
 51→  while (true) {
 52→    // Find events to delete in batches
 53→    const expiredEvents = await db
 54→      .select({ id: auditEvents.id, environment: auditEvents.environment })
 55→      .from(auditEvents)
 56→      .where(
 57→        and(
 58→          eq(auditEvents.accountId, config.accountId),
 59→          lt(auditEvents.receivedAt, cutoffDate),
 60→        )
 61→      )
 62→      .limit(BATCH_SIZE);
 63→
 64→    if (expiredEvents.length === 0) break;
 65→
 66→    const eventIds = expiredEvents.map((e) => e.id);
 67→
 68→    // Count per environment for usage decrement
 69→    const envCounts = new Map<string, number>();
 70→    for (const event of expiredEvents) {
 71→      envCounts.set(event.environment, (envCounts.get(event.environment) || 0) + 1);
 72→    }
 73→
 74→    // Delete within a transaction so SET LOCAL applies to the delete
 75→    await db.transaction(async (tx) => {
 76→      // Set session variable to bypass append-only trigger
 77→      await tx.execute(sql`SET LOCAL app.retention_purge = 'true'`);
 78→      await tx.delete(auditEvents).where(inArray(auditEvents.id, eventIds));
 79→    });
 80→
 81→    // Decrement usage counts per environment
 82→    for (const [environment, count] of envCounts) {
 83→      const [existingUsage] = await db
 84→        .select()
 85→        .from(usageRecords)
 86→        .where(and(
 87→          eq(usageRecords.accountId, config.accountId),
 88→          eq(usageRecords.environment, environment as 'test' | 'live'),
 89→          gt(usageRecords.periodEnd, new Date()),
 90→        ))
 91→        .limit(1);
 92→
 93→      if (existingUsage) {
 94→        await db.execute(
 95→          sql`UPDATE usage_records
 96→              SET events_count = GREATEST(0, events_count - ${count}),
 97→                  updated_at = NOW()
 98→              WHERE id = ${existingUsage.id}`
 99→        );
100→
101→        // Invalidate entitlements cache
102→        const cacheKey = `entitlements:${config.accountId}:${environment}`;
103→        await redis.del(cacheKey);
104→      }
105→    }
106→
107→    // If we got fewer than BATCH_SIZE, we're done
108→    if (expiredEvents.length < BATCH_SIZE) break;
109→  }
110→}
