  1→import type { Redis } from 'ioredis';
  2→import { eq, and, gt } from 'drizzle-orm';
  3→import { accounts, subscriptions, plans, usageRecords, type PlanEntitlements, type Database, type AccountStatus } from '@logseal/database';
  4→
  5→const ENTITLEMENTS_CACHE_TTL_SECONDS = 60; // 1 minute
  6→const ENTITLEMENTS_CACHE_PREFIX = 'entitlements:';
  7→
  8→export interface AccountEntitlements {
  9→  accountStatus: AccountStatus;
 10→  entitlements: PlanEntitlements;
 11→  usage: {
 12→    eventsCount: number;
 13→    organizationsCount: number;
 14→    apiKeysCount: number;
 15→    webhooksCount: number;
 16→    exportsCount: number;
 17→    periodStart: Date;
 18→    periodEnd: Date;
 19→  } | null;
 20→}
 21→
 22→/**
 23→ * Get account entitlements with caching
 24→ */
 25→export async function getAccountEntitlements(
 26→  db: Database,
 27→  redis: Redis,
 28→  accountId: string,
 29→  environment: 'test' | 'live'
 30→): Promise<AccountEntitlements> {
 31→  const cacheKey = `${ENTITLEMENTS_CACHE_PREFIX}${accountId}:${environment}`;
 32→
 33→  // Check cache first
 34→  const cached = await redis.get(cacheKey);
 35→  if (cached) {
 36→    const parsed = JSON.parse(cached);
 37→    // Restore Date objects
 38→    if (parsed.usage) {
 39→      parsed.usage.periodStart = new Date(parsed.usage.periodStart);
 40→      parsed.usage.periodEnd = new Date(parsed.usage.periodEnd);
 41→    }
 42→    return parsed as AccountEntitlements;
 43→  }
 44→
 45→  // Get account status
 46→  const [account] = await db
 47→    .select({ accountStatus: accounts.accountStatus })
 48→    .from(accounts)
 49→    .where(eq(accounts.id, accountId))
 50→    .limit(1);
 51→
 52→  if (!account) {
 53→    throw new Error(`Account not found: ${accountId}`);
 54→  }
 55→
 56→  // Get subscription with plan
 57→  const [subscription] = await db
 58→    .select({
 59→      entitlements: plans.entitlements,
 60→    })
 61→    .from(subscriptions)
 62→    .innerJoin(plans, eq(subscriptions.planId, plans.id))
 63→    .where(eq(subscriptions.accountId, accountId))
 64→    .limit(1);
 65→
 66→  // Get current usage filtered by environment
 67→  const [usage] = await db
 68→    .select()
 69→    .from(usageRecords)
 70→    .where(and(
 71→      eq(usageRecords.accountId, accountId),
 72→      eq(usageRecords.environment, environment),
 73→      gt(usageRecords.periodEnd, new Date()),
 74→    ))
 75→    .limit(1);
 76→
 77→  const entitlements = subscription?.entitlements || {
 78→    eventsPerMonth: 0,
 79→    organizations: 0,
 80→    apiKeys: 0,
 81→    webhooks: 0,
 82→    exports: 0,
 83→    retentionDays: 0,
 84→    features: [],
 85→  };
 86→
 87→  const result: AccountEntitlements = {
 88→    accountStatus: account.accountStatus,
 89→    entitlements,
 90→    usage: usage
 91→      ? {
 92→          eventsCount: usage.eventsCount,
 93→          organizationsCount: usage.organizationsCount,
 94→          apiKeysCount: usage.apiKeysCount,
 95→          webhooksCount: usage.webhooksCount,
 96→          exportsCount: usage.exportsCount,
 97→          periodStart: usage.periodStart,
 98→          periodEnd: usage.periodEnd,
 99→        }
100→      : null,
101→  };
102→
103→  // Cache the result
104→  await redis.setex(cacheKey, ENTITLEMENTS_CACHE_TTL_SECONDS, JSON.stringify(result));
105→
106→  return result;
107→}
108→
109→export type EntitlementResource =
110→  | 'eventsPerMonth'
111→  | 'organizations'
112→  | 'apiKeys'
113→  | 'webhooks'
114→  | 'exports';
115→
116→type UsageCountField = 'eventsCount' | 'organizationsCount' | 'apiKeysCount' | 'webhooksCount' | 'exportsCount';
117→
118→const USAGE_FIELD_MAP: Record<EntitlementResource, UsageCountField> = {
119→  eventsPerMonth: 'eventsCount',
120→  organizations: 'organizationsCount',
121→  apiKeys: 'apiKeysCount',
122→  webhooks: 'webhooksCount',
123→  exports: 'exportsCount',
124→};
125→
126→/**
127→ * Check if an account has entitlement for a resource
128→ * Returns { allowed: boolean, limit: number, current: number }
129→ */
130→export async function checkEntitlement(
131→  db: Database,
132→  redis: Redis,
133→  accountId: string,
134→  environment: 'test' | 'live',
135→  resource: EntitlementResource
136→): Promise<{ allowed: boolean; limit: number; current: number }> {
137→  const accountEntitlements = await getAccountEntitlements(db, redis, accountId, environment);
138→
139→  const limit = accountEntitlements.entitlements[resource];
140→  const usageField = USAGE_FIELD_MAP[resource];
141→  const current = accountEntitlements.usage?.[usageField] ?? 0;
142→
143→  // -1 means unlimited
144→  if (limit === -1) {
145→    return { allowed: true, limit, current };
146→  }
147→
148→  return {
149→    allowed: current < limit,
150→    limit,
151→    current,
152→  };
153→}
154→
155→/**
156→ * Check if an account has access to a feature (from the features array)
157→ * Returns { allowed: boolean }
158→ */
159→export async function checkFeature(
160→  db: Database,
161→  redis: Redis,
162→  accountId: string,
163→  environment: 'test' | 'live',
164→  feature: string
165→): Promise<{ allowed: boolean }> {
166→  const accountEntitlements = await getAccountEntitlements(db, redis, accountId, environment);
167→  const allowed = accountEntitlements.entitlements.features.includes(feature);
168→  return { allowed };
169→}
170→
171→/**
172→ * Invalidate entitlements cache for an account
173→ * If environment is given, delete that key; if omitted, delete both test and live keys
174→ */
175→export async function invalidateEntitlementsCache(
176→  redis: Redis,
177→  accountId: string,
178→  environment?: 'test' | 'live'
179→): Promise<void> {
180→  if (environment) {
181→    await redis.del(`${ENTITLEMENTS_CACHE_PREFIX}${accountId}:${environment}`);
182→  } else {
183→    await redis.del(
184→      `${ENTITLEMENTS_CACHE_PREFIX}${accountId}:test`,
185→      `${ENTITLEMENTS_CACHE_PREFIX}${accountId}:live`
186→    );
187→  }
188→}
