 1→import { customAlphabet } from 'nanoid';
 2→
 3→// URL-safe alphabet without ambiguous characters (no 0, O, I, l)
 4→const alphabet = 'REDACTED';
 5→
 6→// Create a custom nanoid generator
 7→const generateId = customAlphabet(alphabet, 12);
 8→
 9→/**
10→ * Generate a prefixed ID in the Stripe style
11→ * Examples: acct_a8Kj29xMq4, evt_dH2jP6sUn9
12→ */
13→export function createId(prefix: string): string {
14→  return `${prefix}_${generateId()}`;
15→}
16→
17→// Convenience functions for each entity type
18→export const createAccountId = () => createId('acct');
19→export const createApiKeyId = () => createId('key');
20→export const createOrganizationId = () => createId('org');
21→export const createEventId = () => createId('evt');
22→export const createSchemaId = () => createId('sch');
23→export const createRequestLogId = () => createId('req');
24→export const createWebhookId = () => createId('whk');
25→export const createWebhookDeliveryId = () => createId('whd');
26→export const createExportId = () => createId('exp');
27→export const createViewerTokenId = () => createId('vtk');
28→export const createSessionId = () => createId('sess');
29→export const createEmailVerificationId = () => createId('emv');
30→export const createPasswordResetId = () => createId('pwr');
31→export const createPlanId = () => createId('plan');
32→export const createSubscriptionId = () => createId('sub');
33→export const createUsageRecordId = () => createId('usg');
