35→/**
36→ * Generate a full API key with prefix
37→ * Format: sk_test_xxxxxxxxxxxxxxxxxxxx or sk_live_xxxxxxxxxxxxxxxxxxxx
38→ */
39→export function generateApiKey(environment: 'test' | 'live'): string {
40→  const prefix = environment === 'test' ? 'sk_test' : 'sk_live';
41→  // Generate a longer key for security (32 characters)
42→  const keyGenerator = customAlphabet(alphabet, 32);
43→  return `${prefix}_${keyGenerator()}`;
44→}
45→
46→/**
47→ * Generate a viewer token
48→ * Format: vtk_xxxxxxxxxxxxxxxxxxxx
49→ */
50→export function generateViewerToken(): string {
51→  const tokenGenerator = customAlphabet(alphabet, 32);
52→  return `vtk_${tokenGenerator()}`;
53→}
54→
55→/**
56→ * Extract the last 4 characters of an API key for display
57→ */
58→export function getKeyLastFour(key: string): string {
59→  return key.slice(-4);
60→}
61→
62→/**
63→ * Get the prefix from an API key
64→ */
65→export function getKeyPrefix(key: string): string {
66→  // sk_test_xxx -> sk_test_
67→  // sk_live_xxx -> sk_live_
68→  const match = key.match(/^(sk_(?:test|live)_)/);
69→  return match ? match[1] : '';
70→}
71→
72→/**
73→ * Determine environment from API key prefix
74→ */
75→export function getEnvironmentFromKey(key: string): 'test' | 'live' | null {
76→  if (key.startsWith('sk_test_')) return 'test';
77→  if (key.startsWith('sk_live_')) return 'live';
78→  return null;
79→}
80→
81→/**
82→ * Generate a session token (48 characters for extra security)
83→ * This is the raw token sent to the client; it should be hashed before storage
84→ */
85→export function generateSessionToken(): string {
86→  const tokenGenerator = customAlphabet(alphabet, 48);
87→  return tokenGenerator();
88→}
89→
90→/**
91→ * Generate a verification token (32 characters)
92→ * Used for email verification and password reset links
93→ */
94→export function generateVerificationToken(): string {
95→  const tokenGenerator = customAlphabet(alphabet, 32);
96→  return tokenGenerator();
97→}
