 1→import { eq } from 'drizzle-orm';
 2→import { webhooks, webhookDeliveries, type Database } from '@logseal/database';
 3→import { computeWebhookSignature } from '@logseal/utils';
 4→
 5→interface WebhookJobData {
 6→  webhookId: string;
 7→  eventId: string;
 8→  payload: Record<string, unknown>;
 9→}
10→
11→export async function processWebhookJob(
12→  data: WebhookJobData,
13→  db: Database
14→): Promise<void> {
15→  const { webhookId, eventId, payload } = data;
16→
17→  // Fetch webhook from DB at delivery time (secret never passes through Redis)
18→  const [webhook] = await db
19→    .select()
20→    .from(webhooks)
21→    .where(eq(webhooks.id, webhookId))
22→    .limit(1);
23→
24→  if (!webhook) {
25→    // Webhook was deleted between queuing and delivery — skip
26→    return;
27→  }
28→
29→  if (!webhook.enabled) {
30→    return;
31→  }
32→
33→  const payloadString = JSON.stringify(payload);
34→  const signature = computeWebhookSignature(payloadString, webhook.secret);
35→  const timestamp = Math.floor(Date.now() / 1000);
36→
37→  // Create delivery record
38→  const [delivery] = await db
39→    .insert(webhookDeliveries)
40→    .values({
41→      webhookId,
42→      eventId,
43→      attempts: '1',
44→    })
45→    .returning();
46→
47→  try {
48→    const response = await fetch(webhook.url, {
49→      method: 'POST',
50→      headers: {
51→        'Content-Type': 'application/json',
52→        'User-Agent': 'LogSeal-Webhook/1.0',
53→        'X-LogSeal-Signature': signature,
54→        'X-LogSeal-Timestamp': timestamp.toString(),
55→        'X-LogSeal-Event-ID': eventId,
56→      },
57→      body: payloadString,
58→      signal: AbortSignal.timeout(30000), // 30 second timeout
59→    });
60→
61→    const responseText = await response.text().catch(() => '');
62→
63→    // Update delivery record
64→    await db
65→      .update(webhookDeliveries)
66→      .set({
67→        statusCode: response.status.toString(),
68→        responseBody: responseText.slice(0, 1024), // Limit response body
69→        deliveredAt: response.ok ? new Date() : null,
70→        nextRetryAt: response.ok ? null : new Date(Date.now() + 60000), // Retry in 1 min if failed
71→      })
72→      .where(eq(webhookDeliveries.id, delivery.id));
73→
74→    if (!response.ok) {
75→      throw new Error(`Webhook returned ${response.status}: ${responseText.slice(0, 200)}`);
76→    }
77→  } catch (error: any) {
78→    // Update delivery record with error
79→    await db
80→      .update(webhookDeliveries)
81→      .set({
82→        responseBody: error.message?.slice(0, 1024),
83→        nextRetryAt: new Date(Date.now() + 60000),
84→      })
85→      .where(eq(webhookDeliveries.id, delivery.id));
86→
87→    throw error; // Re-throw so BullMQ can retry
88→  }
89→}
