312→async function handleCheckoutCompleted(fastify: any, session: any) {
313→  const accountId = session.metadata?.logseal_account_id;
314→  if (!accountId) {
315→    fastify.log.warn('Checkout session missing logseal_account_id metadata');
316→    return;
317→  }
318→
319→  const stripeSubscriptionId = session.subscription;
320→  if (!stripeSubscriptionId) {
321→    return;
322→  }
323→
324→  // Get the subscription from Stripe to get details
325→  const { getStripeClient } = await import('../services/stripe.js');
326→  const stripe = getStripeClient();
327→  const stripeSubscription = await stripe.subscriptions.retrieve(stripeSubscriptionId as string) as Stripe.Subscription;
328→
329→  // Find the plan by Stripe price ID
330→  const stripePriceId = stripeSubscription.items.data[0]?.price.id;
331→  const [plan] = await fastify.db
332→    .select()
333→    .from(plans)
334→    .where(eq(plans.stripePriceId, stripePriceId))
335→    .limit(1);
336→
337→  if (!plan) {
338→    fastify.log.warn({ stripePriceId }, 'No plan found for Stripe price');
339→    return;
340→  }
341→
342→  // Update or create subscription
343→  const [existingSubscription] = await fastify.db
344→    .select()
345→    .from(subscriptions)
346→    .where(eq(subscriptions.accountId, accountId))
347→    .limit(1);
348→
349→  // Get billing period from the first subscription item
350→  const subscriptionItem = stripeSubscription.items.data[0];
351→  const currentPeriodStart = subscriptionItem?.current_period_start
352→    ? new Date(subscriptionItem.current_period_start * 1000)
353→    : new Date();
354→  const currentPeriodEnd = subscriptionItem?.current_period_end
355→    ? new Date(subscriptionItem.current_period_end * 1000)
356→    : new Date(Date.now() + 30 * 24 * 60 * 60 * 1000);
357→
358→  const subscriptionData = {
359→    planId: plan.id,
360→    stripeSubscriptionId,
361→    stripeStatus: stripeSubscription.status,
362→    currentPeriodStart,
363→    currentPeriodEnd,
364→    cancelAtPeriodEnd: stripeSubscription.cancel_at_period_end,
365→    updatedAt: new Date(),
366→  };
367→
368→  if (existingSubscription) {
369→    await fastify.db
370→      .update(subscriptions)
371→      .set(subscriptionData)
372→      .where(eq(subscriptions.id, existingSubscription.id));
373→  } else {
374→    await fastify.db.insert(subscriptions).values({
375→      ...subscriptionData,
376→      accountId,
377→    });
378→  }
379→
380→  // Reset usage for new billing period — create rows for both environments
381→  const periodStart = currentPeriodStart;
382→  const periodEnd = currentPeriodEnd;
383→
384→  await fastify.db.insert(usageRecords).values([
385→    { accountId, environment: 'test' as const, periodStart, periodEnd },
386→    { accountId, environment: 'live' as const, periodStart, periodEnd },
387→  ]);
388→
389→  // Update account status to active
390→  await fastify.db.update(accounts).set({ accountStatus: 'active' }).where(eq(accounts.id, accountId));
