414→async function updateSubscriptionFromStripe(fastify: any, accountId: string, stripeSubscription: any) {
415→  // Find the plan by Stripe price ID
416→  const stripePriceId = stripeSubscription.items.data[0]?.price.id;
417→  const [plan] = await fastify.db
418→    .select()
419→    .from(plans)
420→    .where(eq(plans.stripePriceId, stripePriceId))
421→    .limit(1);
422→
423→  const subscriptionData: any = {
424→    stripeSubscriptionId: stripeSubscription.id,
425→    stripeStatus: stripeSubscription.status,
426→    currentPeriodStart: new Date(stripeSubscription.current_period_start * 1000),
427→    currentPeriodEnd: new Date(stripeSubscription.current_period_end * 1000),
428→    cancelAtPeriodEnd: stripeSubscription.cancel_at_period_end,
429→    updatedAt: new Date(),
430→  };
431→
432→  if (plan) {
433→    subscriptionData.planId = plan.id;
434→  }
435→
436→  await fastify.db
437→    .update(subscriptions)
438→    .set(subscriptionData)
439→    .where(eq(subscriptions.accountId, accountId));
440→
441→  // Update account status based on subscription status
442→  let accountStatus: 'active' | 'defaulted' | 'cancelled' = 'active';
443→  if (stripeSubscription.status === 'past_due' || stripeSubscription.status === 'unpaid') {
444→    accountStatus = 'defaulted';
445→  } else if (stripeSubscription.status === 'canceled') {
446→    accountStatus = 'cancelled';
447→  }
448→
449→  await fastify.db.update(accounts).set({ accountStatus }).where(eq(accounts.id, accountId));
450→}
451→
452→async function handleSubscriptionDeleted(fastify: any, stripeSubscription: any) {
453→  // Find subscription by Stripe ID
454→  const [sub] = await fastify.db
455→    .select()
456→    .from(subscriptions)
457→    .where(eq(subscriptions.stripeSubscriptionId, stripeSubscription.id))
458→    .limit(1);
459→
460→  if (!sub) {
461→    return;
462→  }
463→
464→  // Get default free plan
465→  const [defaultPlan] = await fastify.db
466→    .select()
467→    .from(plans)
468→    .where(and(eq(plans.isDefault, true), eq(plans.active, true)))
469→    .limit(1);
470→
471→  if (defaultPlan) {
472→    // Revert to free plan
473→    const now = new Date();
474→    const periodEnd = new Date(now);
475→    periodEnd.setMonth(periodEnd.getMonth() + 1);
476→
477→    await fastify.db
478→      .update(subscriptions)
479→      .set({
480→        planId: defaultPlan.id,
481→        stripeSubscriptionId: null,
482→        stripeStatus: null,
483→        currentPeriodStart: now,
484→        currentPeriodEnd: periodEnd,
485→        cancelAtPeriodEnd: false,
486→        updatedAt: new Date(),
487→      })
488→      .where(eq(subscriptions.id, sub.id));
489→  }
490→
491→  // Update account status
492→  await fastify.db
493→    .update(accounts)
494→    .set({ accountStatus: 'cancelled' })
495→    .where(eq(accounts.id, sub.accountId));
496→}
497→
498→async function handleInvoicePaymentSucceeded(fastify: any, invoice: any) {
499→  if (!invoice.subscription) {
500→    return;
501→  }
502→
503→  // Find subscription by Stripe ID
504→  const [sub] = await fastify.db
505→    .select()
506→    .from(subscriptions)
507→    .where(eq(subscriptions.stripeSubscriptionId, invoice.subscription))
508→    .limit(1);
509→
510→  if (!sub) {
511→    return;
512→  }
513→
514→  // Update account status to active
515→  await fastify.db
516→    .update(accounts)
517→    .set({ accountStatus: 'active' })
518→    .where(eq(accounts.id, sub.accountId));
519→
520→  // Create new usage records for the billing period — one per environment
521→  const periodStart = new Date(invoice.period_start * 1000);
522→  const periodEnd = new Date(invoice.period_end * 1000);
523→
524→  for (const env of ['test', 'live'] as const) {
525→    const [existingUsage] = await fastify.db
526→      .select()
527→      .from(usageRecords)
528→      .where(
529→        and(
530→          eq(usageRecords.accountId, sub.accountId),
531→          eq(usageRecords.environment, env),
532→          eq(usageRecords.periodStart, periodStart),
533→        )
534→      )
535→      .limit(1);
536→
537→    if (!existingUsage) {
538→      await fastify.db.insert(usageRecords).values({
539→        accountId: sub.accountId,
540→        environment: env,
541→        periodStart,
542→        periodEnd,
543→      });
544→    }
545→  }
546→}
547→
548→async function handleInvoicePaymentFailed(fastify: any, invoice: any) {
549→  if (!invoice.subscription) {
550→    return;
551→  }
552→
553→  // Find subscription by Stripe ID
554→  const [sub] = await fastify.db
555→    .select()
556→    .from(subscriptions)
557→    .where(eq(subscriptions.stripeSubscriptionId, invoice.subscription))
558→    .limit(1);
559→
560→  if (!sub) {
561→    return;
562→  }
563→
564→  // Update account status to defaulted after grace period
565→  // Stripe typically sends this after multiple retry attempts
566→  if (invoice.attempt_count >= 3) {
567→    await fastify.db
568→      .update(accounts)
569→      .set({ accountStatus: 'defaulted' })
570→      .where(eq(accounts.id, sub.accountId));
571→  }
572→}
