  7→const HEALTH_CHECK_INTERVAL_MS = 60_000; // 1 minute
  8→const MAX_FAILURES_BEFORE_UNHEALTHY = 3;
  9→
 10→interface ManagedConnection {
 11→  dataStore: DataStore;
 12→  db: Database;
 13→  failureCount: number;
 14→  schemaInitialized: boolean;
 15→}
 16→
 17→export interface DecryptFn {
 18→  (data: { ciphertext: string; iv: string; authTag: string }): string;
 19→}
 20→
 21→/**
 22→ * DataStoreManager — resolves accountId to the correct DataStore instance.
 23→ * Maintains a pool of customer DataStore connections for BYOD accounts.
 24→ */
 25→export class DataStoreManager {
 26→  private connections = new Map<string, ManagedConnection>();
 27→  private healthCheckTimer: ReturnType<typeof setInterval> | null = null;
 28→  private defaultDataStore: DataStore;
 29→
 30→  constructor(
 31→    private mainDb: Database,
 32→    private decryptFn: DecryptFn,
 33→    defaultDataStore?: DataStore
 34→  ) {
 35→    this.defaultDataStore = defaultDataStore ?? new PostgresDataStore(mainDb);
 36→  }
 37→
 38→  /**
 39→   * Get the DataStore for an account.
 40→   * If the account has a BYOD connection, returns a customer-specific DataStore.
 41→   * Otherwise returns the default (main DB) DataStore.
 42→   */
 43→  async getDataStore(accountId: string): Promise<DataStore> {
 44→    // Check if we already have a cached connection
 45→    const cached = this.connections.get(accountId);
 46→    if (cached) {
 47→      return cached.dataStore;
 48→    }
 49→
 50→    // Look up data_connections for this account
 51→    const [connection] = await this.mainDb
 52→      .select()
 53→      .from(dataConnections)
 54→      .where(eq(dataConnections.accountId, accountId))
 55→      .limit(1);
 56→
 57→    if (!connection || connection.status === 'disabled') {
 58→      return this.defaultDataStore;
 59→    }
 60→
 61→    // Decrypt the connection string and create a new DataStore
 62→    const connectionString = this.decryptFn({
 63→      ciphertext: connection.encryptedConnectionString,
 64→      iv: connection.iv,
 65→      authTag: connection.authTag,
 66→    });
 67→
 68→    const db = createDb(connectionString);
 69→    const dataStore = new PostgresDataStore(db);
 70→
 71→    // Initialize schema on first connection
 72→    await dataStore.setupSchema();
 73→
 74→    this.connections.set(accountId, { dataStore, db, failureCount: 0, schemaInitialized: true });
 75→
 76→    return dataStore;
 77→  }
 78→
 79→  /**
 80→   * Get the default DataStore (main DB).
 81→   */
 82→  getDefaultDataStore(): DataStore {
 83→    return this.defaultDataStore;
 84→  }
 85→
 86→  /**
 87→   * Check if an account has a BYOD connection configured.
 88→   */
 89→  async hasByodConnection(accountId: string): Promise<boolean> {
 90→    const [connection] = await this.mainDb
 91→      .select({ id: dataConnections.id })
 92→      .from(dataConnections)
 93→      .where(eq(dataConnections.accountId, accountId))
 94→      .limit(1);
 95→    return !!connection;
 96→  }
 97→
 98→  /**
 99→   * Invalidate a cached connection (e.g., when connection is updated/deleted).
100→   */
101→  evictConnection(accountId: string): void {
102→    this.connections.delete(accountId);
103→  }
104→
105→  /**
106→   * Run a single health-check pass over all active connections.
107→   */
108→  async runHealthChecks(): Promise<void> {
109→    for (const [accountId, conn] of this.connections) {
110→      try {
111→        const healthy = await conn.dataStore.healthCheck();
112→        if (healthy) {
113→          conn.failureCount = 0;
114→        } else {
115→          conn.failureCount++;
116→        }
117→      } catch {
118→        conn.failureCount++;
119→      }
120→
121→      if (conn.failureCount >= MAX_FAILURES_BEFORE_UNHEALTHY) {
122→        // Mark as unhealthy in DB
123→        await this.mainDb
124→          .update(dataConnections)
125→          .set({ status: 'unhealthy', lastHealthCheck: new Date() })
126→          .where(eq(dataConnections.accountId, accountId));
127→      } else {
128→        await this.mainDb
129→          .update(dataConnections)
130→          .set({ status: 'active', lastHealthCheck: new Date() })
131→          .where(eq(dataConnections.accountId, accountId));
132→      }
133→    }
134→  }
135→
136→  /**
137→   * Start periodic health checks for all active connections.
138→   */
139→  startHealthChecks(): void {
140→    if (this.healthCheckTimer) return;
141→
142→    this.healthCheckTimer = setInterval(() => {
143→      this.runHealthChecks();
144→    }, HEALTH_CHECK_INTERVAL_MS);
145→  }
146→
147→  /**
148→   * Stop health checks and close all connections.
149→   */
150→  async close(): Promise<void> {
151→    if (this.healthCheckTimer) {
152→      clearInterval(this.healthCheckTimer);
153→      this.healthCheckTimer = null;
154→    }
155→    for (const [, conn] of this.connections) {
156→      await conn.dataStore.close();
157→    }
158→    this.connections.clear();
159→  }
160→}
