 75→        fastify.dataStoreManager.evictConnection(accountId);
 76→      }
 77→    );
 78→
 79→    return reply.status(201).send({
 80→      id: connection.id,
 81→      status: connection.status,
 82→      created_at: connection.createdAt.toISOString(),
 83→      object: 'data_connection',
 84→    });
 85→  });
 86→
 87→  // GET /v1/data-connections - Get current connection
 88→  fastify.get('/data-connections', async (request, reply) => {
 89→    if (!request.session) {
 90→      if (request.account?.keyId) {
 91→        throw errors.apiKeyNotAllowed();
 92→      }
 93→      throw errors.sessionExpired();
 94→    }
 95→
 96→    const accountId = request.session.accountId;
 97→
 98→    const [connection] = await fastify.db
 99→      .select()
100→      .from(dataConnections)
101→      .where(eq(dataConnections.accountId, accountId))
102→      .limit(1);
103→
104→    if (!connection) {
105→      throw errors.notFound('data_connection');
106→    }
107→
108→    return reply.send({
109→      id: connection.id,
110→      status: connection.status,
111→      last_health_check: connection.lastHealthCheck?.toISOString() ?? null,
112→      created_at: connection.createdAt.toISOString(),
113→      updated_at: connection.updatedAt.toISOString(),
114→      object: 'data_connection',
115→    });
116→  });
117→
118→  // PATCH /v1/data-connections - Update connection
119→  fastify.patch('/data-connections', async (request, reply) => {
120→    if (!request.session) {
121→      if (request.account?.keyId) {
122→        throw errors.apiKeyNotAllowed();
123→      }
124→      throw errors.sessionExpired();
125→    }
126→
127→    const accountId = request.session.accountId;
128→    const input = updateConnectionSchema.parse(request.body);
129→
130→    const [existing] = await fastify.db
131→      .select()
132→      .from(dataConnections)
133→      .where(eq(dataConnections.accountId, accountId))
134→      .limit(1);
135→
136→    if (!existing) {
137→      throw errors.notFound('data_connection');
138→    }
139→
140→    const updates: Record<string, unknown> = {
141→      updatedAt: new Date(),
142→    };
143→
144→    if (input.connection_string) {
145→      const encrypted = encrypt(input.connection_string);
146→      updates.encryptedConnectionString = encrypted.ciphertext;
147→      updates.iv = encrypted.iv;
148→      updates.authTag = encrypted.authTag;
149→    }
150→
151→    if (input.status) {
152→      updates.status = input.status;
153→    }
154→
155→    const [updated] = await fastify.db
156→      .update(dataConnections)
157→      .set(updates)
158→      .where(eq(dataConnections.accountId, accountId))
159→      .returning();
160→
161→    // Evict cached connection
162→    if (fastify.dataStoreManager) {
163→      fastify.dataStoreManager.evictConnection(accountId);
164→    }
165→
166→    return reply.send({
167→      id: updated.id,
168→      status: updated.status,
169→      last_health_check: updated.lastHealthCheck?.toISOString() ?? null,
170→      created_at: updated.createdAt.toISOString(),
171→      updated_at: updated.updatedAt.toISOString(),
172→      object: 'data_connection',
173→    });
174→  });
175→
176→  // DELETE /v1/data-connections - Delete connection
177→  fastify.delete('/data-connections', async (request, reply) => {
178→    if (!request.session) {
179→      if (request.account?.keyId) {
180→        throw errors.apiKeyNotAllowed();
181→      }
182→      throw errors.sessionExpired();
183→    }
184→
185→    const accountId = request.session.accountId;
186→
187→    const deleted = await fastify.db
188→      .delete(dataConnections)
189→      .where(eq(dataConnections.accountId, accountId))
190→      .returning();
191→
192→    if (deleted.length === 0) {
193→      throw errors.notFound('data_connection');
194→    }
195→
196→    // Evict cached connection
197→    if (fastify.dataStoreManager) {
198→      fastify.dataStoreManager.evictConnection(accountId);
199→    }
200→
201→    return reply.send({
202→      deleted: true,
203→      object: 'data_connection',
204→    });
205→  });
206→
207→  // POST /v1/data-connections/health - Health check
208→  fastify.post('/data-connections/health', async (request, reply) => {
209→    if (!request.session) {
210→      if (request.account?.keyId) {
211→        throw errors.apiKeyNotAllowed();
212→      }
213→      throw errors.sessionExpired();
214→    }
215→
216→    const accountId = request.session.accountId;
217→
218→    const [connection] = await fastify.db
219→      .select()
220→      .from(dataConnections)
221→      .where(eq(dataConnections.accountId, accountId))
222→      .limit(1);
223→
224→    if (!connection) {
225→      throw errors.notFound('data_connection');
226→    }
227→
228→    // Try to connect and run health check
229→    try {
230→      const connectionString = decrypt({
231→        ciphertext: connection.encryptedConnectionString,
232→        iv: connection.iv,
233→        authTag: connection.authTag,
234→      });
235→
236→      const { createDb } = await import('@logseal/database');
237→      const { PostgresDataStore } = await import('@logseal/database/datastore');
238→      const testDb = createDb(connectionString);
239→      const testStore = new PostgresDataStore(testDb);
240→      const healthy = await testStore.healthCheck();
241→
242→      // Update health check timestamp
243→      await fastify.db
244→        .update(dataConnections)
245→        .set({
246→          status: healthy ? 'active' : 'unhealthy',
247→          lastHealthCheck: new Date(),
248→        })
249→        .where(eq(dataConnections.accountId, accountId));
250→
251→      return reply.send({
252→        healthy,
253→        checked_at: new Date().toISOString(),
254→        status: healthy ? 'active' : 'unhealthy',
255→        object: 'health_check',
256→      });
257→    } catch (err: any) {
258→      // Update as unhealthy
259→      await fastify.db
260→        .update(dataConnections)
261→        .set({
262→          status: 'unhealthy',
263→          lastHealthCheck: new Date(),
264→        })
265→        .where(eq(dataConnections.accountId, accountId));
266→
267→      return reply.send({
268→        healthy: false,
269→        checked_at: new Date().toISOString(),
270→        status: 'unhealthy',
271→        error: err.message,
272→        object: 'health_check',
273→      });
274→    }
275→  });
276→};
