  3→// Lazy-initialized Stripe client to avoid crashing at module load when API key is missing
  4→let stripeClient: Stripe | null = null;
  5→
  6→function getStripeClient(): Stripe {
  7→  if (!stripeClient) {
  8→    const apiKey = process.env.STRIPE_SECRET_KEY;
  9→    if (!apiKey) {
 10→      throw new Error(
 11→        'STRIPE_SECRET_KEY environment variable is not set. Stripe functionality is disabled.'
 12→      );
 13→    }
 14→    stripeClient = new Stripe(apiKey);
 15→  }
 16→  return stripeClient;
 17→}
