 19→/**
 20→ * Create a Stripe customer for an account
 21→ */
 22→export async function createStripeCustomer(
 23→  email: string,
 24→  accountId: string,
 25→  companyName?: string
 26→): Promise<string> {
 27→  const customer = await getStripeClient().customers.create({
 28→    email,
 29→    name: companyName,
 30→    metadata: {
 31→      logseal_account_id: accountId,
 32→    },
 33→  });
 34→
 35→  return customer.id;
 36→}
