 38→/**
 39→ * Create a Stripe Checkout session for subscription
 40→ */
 41→export async function createCheckoutSession(
 42→  customerId: string,
 43→  priceId: string,
 44→  accountId: string,
 45→  successUrl: string,
 46→  cancelUrl: string
 47→): Promise<string> {
 48→  const session = await getStripeClient().checkout.sessions.create({
