  1→import { auditEvents, exports, type Database } from '@logseal/database';
  2→import { and, desc, eq, gte, lte } from 'drizzle-orm';
  3→
  4→interface ExportJobData {
  5→  exportId: string;
  6→  accountId: string;
  7→  organizationId: string;
  8→  environment: 'test' | 'live';
  9→  format: 'csv' | 'json';
 10→  filters: {
 11→    after?: string;
 12→    before?: string;
 13→    action?: string;
 14→    actor_id?: string;
 15→  };
 16→}
 17→
 18→export async function processExportJob(
 19→  data: ExportJobData,
 20→  db: Database
 21→): Promise<void> {
 22→  const { exportId, accountId, organizationId, environment, format, filters } = data;
 23→
 24→  try {
 25→    // Update status to processing
 26→    await db
 27→      .update(exports)
 28→      .set({ status: 'processing' })
 29→      .where(eq(exports.id, exportId));
 30→
 31→    // Build query conditions
 32→    const conditions = [
 33→      eq(auditEvents.accountId, accountId),
 34→      eq(auditEvents.organizationId, organizationId),
 35→      eq(auditEvents.environment, environment),
 36→    ];
 37→
 38→    if (filters.after) {
 39→      conditions.push(gte(auditEvents.occurredAt, new Date(filters.after)));
 40→    }
 41→    if (filters.before) {
 42→      conditions.push(lte(auditEvents.occurredAt, new Date(filters.before)));
 43→    }
 44→    if (filters.action) {
 45→      conditions.push(eq(auditEvents.action, filters.action));
 46→    }
 47→    if (filters.actor_id) {
 48→      conditions.push(eq(auditEvents.actorId, filters.actor_id));
 49→    }
 50→
 51→    // Fetch all events
 52→    const events = await db
 53→      .select()
 54→      .from(auditEvents)
 55→      .where(and(...conditions))
 56→      .orderBy(desc(auditEvents.occurredAt));
 57→
 58→    // Generate export content (will be used when S3 upload is implemented)
 59→    let _content: string;
 60→    if (format === 'json') {
 61→      _content = JSON.stringify(
 62→        events.map((e) => ({
 63→          id: e.id,
 64→          action: e.action,
 65→          occurred_at: e.occurredAt.toISOString(),
 66→          actor: {
 67→            id: e.actorId,
 68→            type: e.actorType,
 69→            name: e.actorName,
 70→            email: e.actorEmail,
 71→          },
 72→          targets: e.targets,
 73→          metadata: e.metadata,
 74→          event_hash: e.eventHash,
 75→        })),
 76→        null,
 77→        2
 78→      );
 79→    } else {
 80→      // CSV format
 81→      const headers = [
 82→        'id',
 83→        'action',
 84→        'occurred_at',
 85→        'actor_id',
 86→        'actor_type',
 87→        'actor_name',
 88→        'actor_email',
 89→        'targets',
 90→        'metadata',
 91→        'event_hash',
 92→      ];
 93→
 94→      const rows = events.map((e) => [
 95→        e.id,
 96→        e.action,
 97→        e.occurredAt.toISOString(),
 98→        e.actorId,
 99→        e.actorType,
100→        e.actorName || '',
101→        e.actorEmail || '',
102→        JSON.stringify(e.targets),
103→        JSON.stringify(e.metadata),
104→        e.eventHash,
105→      ]);
106→
107→      _content = [
108→        headers.join(','),
109→        ...rows.map((row) =>
110→          row.map((cell) => `"${String(cell).replace(/"/g, '""')}"`).join(',')
111→        ),
112→      ].join('\n');
113→    }
114→
115→    // In a real implementation, you'd upload _content to S3 here
116→    // For now, we'll just mark as completed with a placeholder URL
117→    const fileUrl = `https://exports.logseal.io/${exportId}.${format}`;
118→    const expiresAt = new Date(Date.now() + 24 * 60 * 60 * 1000); // 24 hours
119→
120→    await db
121→      .update(exports)
122→      .set({
123→        status: 'completed',
124→        fileUrl,
125→        eventCount: events.length,
126→        expiresAt,
127→      })
128→      .where(eq(exports.id, exportId));
129→
130→    console.log(`Export ${exportId} completed with ${events.length} events (${_content.length} bytes)`);
131→  } catch (error: any) {
132→    console.error(`Export ${exportId} failed:`, error);
133→
134→    await db
135→      .update(exports)
136→      .set({ status: 'failed' })
137→      .where(eq(exports.id, exportId));
138→
139→    throw error;
140→  }
141→}
