import { createHash } from 'crypto';

/**
 * Compute SHA-256 hash of a string
 */
export function sha256(input: string): string {
  return createHash('sha256').update(input).digest('hex');
}

/**
 * Canonicalize an object for hashing (deterministic JSON with sorted keys)
 */
export function canonicalize(data: Record<string, unknown>): string {
  return JSON.stringify(data, Object.keys(data).sort());
}

/**
 * Data structure for computing event hash
 */
export interface EventForHashing {
  action: string;
  actor: Record<string, unknown>;
  targets: Record<string, unknown>[];
  metadata: Record<string, unknown>;
  occurred_at: string;
  organization_id: string;
  sequence_number: number;
}

/**
 * Compute the hash chain hash for an audit event
 * This links each event to its predecessor, creating a tamper-evident chain
 */
export function computeEventHash(
  previousHash: string | null,
  eventData: EventForHashing
): string {
  const canonical = canonicalize(eventData as unknown as Record<string, unknown>);
  const input = (previousHash ?? 'GENESIS') + ':' + canonical;
  return sha256(input);
}

/**
 * Compute skip-list offsets for a given sequence number.
 * Returns offsets [1, 2, 4, 8, ...] where seq - offset >= 1.
 */
export function computeSkipOffsets(sequenceNumber: number): number[] {
  const offsets: number[] = [];
  let offset = 1;
  while (sequenceNumber - offset >= 1) {
    offsets.push(offset);
    offset *= 2;
  }
  return offsets;
}

/**
 * Compute the optimal skip-list verification path from fromSeq to toSeq.
 * Returns an array of sequence numbers to check, enabling O(log n) range verification.
 */
export function computeSkipVerificationPath(fromSeq: number, toSeq: number): number[] {
  if (fromSeq >= toSeq) return [fromSeq];

  const path: number[] = [toSeq];
  let current = toSeq;

  while (current > fromSeq) {
    // Find the largest power-of-2 offset that doesn't overshoot fromSeq
    const offsets = computeSkipOffsets(current);
    let jumped = false;
    for (let i = offsets.length - 1; i >= 0; i--) {
      const target = current - offsets[i];
      if (target >= fromSeq) {
        current = target;
        path.push(current);
        jumped = true;
        break;
      }
    }
    if (!jumped) break;
  }

  return path.reverse();
}

/**
 * Compute HMAC-SHA256 signature for webhook payloads
 */
export function computeWebhookSignature(payload: string, secret: string): string {
  const hmac = createHash('sha256');
  hmac.update(secret);
  hmac.update(payload);
  return 'sha256=' + hmac.digest('hex');
}

/**
 * Verify a webhook signature using timing-safe comparison
 */
export function verifyWebhookSignature(
  payload: string,
  signature: string,
  secret: string
): boolean {
  const expected = computeWebhookSignature(payload, secret);

  // Timing-safe comparison to prevent timing attacks
  if (signature.length !== expected.length) {
    return false;
  }

  let result = 0;
  for (let i = 0; i < signature.length; i++) {
    result |= signature.charCodeAt(i) ^ expected.charCodeAt(i);
  }
  return result === 0;
}

