 59→function toISOString(date: string | Date | undefined): string | undefined {
 60→  if (!date) return undefined;
 61→  if (date instanceof Date) return date.toISOString();
 62→  return date;
 63→}
 64→
 65→export class LogSeal {
 66→  private apiKey: string;
 67→  private baseUrl: string;
 68→  private batchSize: number;
 69→  private flushInterval: number;
 70→  private queue: EmitEventInput[];
 71→  private timer: ReturnType<typeof setInterval> | null;
 72→  private retryConfig: RetryConfig;
 73→
 74→  public readonly events: EventsAPI;
 75→  public readonly organizations: OrganizationsAPI;
 76→  public readonly schemas: SchemasAPI;
 77→  public readonly viewerTokens: ViewerTokensAPI;
 78→  public readonly webhooks: WebhooksAPI;
 79→  public readonly exports: ExportsAPI;
 80→
 81→  constructor(config: LogSealConfig) {
 82→    if (!config.apiKey) {
 83→      throw new Error('API key is required');
 84→    }
 85→
 86→    this.apiKey = config.apiKey;
 87→    this.baseUrl = config.baseUrl ?? 'https://api.logseal.dev';
 88→    this.batchSize = config.batchSize ?? 100;
 89→    this.flushInterval = config.flushIntervalMs ?? 5000;
 90→    this.queue = [];
 91→    this.timer = null;
 92→    this.retryConfig = {
 93→      maxRetries: config.maxRetries ?? 3,
 94→      baseDelayMs: 1000,
 95→      maxDelayMs: 30000,
 96→    };
 97→
 98→    // Initialize sub-APIs
 99→    this.events = new EventsAPI(this);
100→    this.organizations = new OrganizationsAPI(this);
101→    this.schemas = new SchemasAPI(this);
102→    this.viewerTokens = new ViewerTokensAPI(this);
103→    this.webhooks = new WebhooksAPI(this);
104→    this.exports = new ExportsAPI(this);
105→
106→    // Start the flush timer
107→    this.startFlushTimer();
108→  }
109→
110→  /**
111→   * Emit an event (queued for batching)
112→   */
113→  async emit(event: EmitEventInput): Promise<{ status: 'queued' }> {
114→    this.validateEvent(event);
115→    this.queue.push(event);
116→
117→    if (this.queue.length >= this.batchSize) {
118→      await this.flush();
119→    }
120→
121→    return { status: 'queued' };
122→  }
123→
124→  /**
125→   * Emit an event and wait for server confirmation
126→   */
127→  async emitSync(event: EmitEventInput): Promise<EmitEventResponse> {
128→    this.validateEvent(event);
129→    return this.request<EmitEventResponse>('POST', '/v1/events', this.formatEvent(event));
130→  }
131→
132→  /**
133→   * Flush all queued events
134→   */
135→  async flush(): Promise<{ sent: number }> {
136→    if (this.queue.length === 0) {
137→      return { sent: 0 };
138→    }
139→
140→    const events = [...this.queue];
141→    this.queue = [];
142→
143→    const response = await this.request<BatchEmitResponse>('POST', '/v1/events/batch', {
144→      events: events.map((e) => this.formatEvent(e)),
145→    });
146→
147→    return { sent: response.accepted };
148→  }
149→
150→  /**
151→   * Graceful shutdown - flushes remaining events
152→   */
153→  async shutdown(): Promise<void> {
154→    if (this.timer) {
155→      clearInterval(this.timer);
156→      this.timer = null;
157→    }
158→    await this.flush();
159→  }
160→
161→  /**
162→   * Create Express middleware that automatically emits audit events for HTTP requests.
163→   */
164→  express(config: ExpressMiddlewareConfig): ExpressMiddlewareReturn {
165→    return createExpressMiddleware(this.emit.bind(this), config);
166→  }
167→
168→  /**
169→   * Create a Fastify plugin that automatically emits audit events for HTTP requests.
170→   */
171→  fastify(config: FastifyMiddlewareConfig): FastifyPluginReturn {
172→    return createFastifyMiddleware(this.emit.bind(this), config);
173→  }
174→
175→  /**
176→   * Create Hono middleware that automatically emits audit events for HTTP requests.
177→   */
178→  hono(config: HonoMiddlewareConfig): HonoMiddlewareReturn {
179→    return createHonoMiddleware(this.emit.bind(this), config);
180→  }
181→
182→  // Internal methods
183→
184→  private startFlushTimer(): void {
185→    this.timer = setInterval(() => {
186→      this.flush().catch((err) => {
187→        console.error('LogSeal: Failed to flush events:', err.message);
188→      });
189→    }, this.flushInterval);
190→
191→    // Don't prevent process exit
192→    if (this.timer.unref) {
193→      this.timer.unref();
194→    }
195→  }
196→
197→  private validateEvent(event: EmitEventInput): void {
198→    if (!event.action) {
199→      throw new LogSealError({
200→        type: 'validation_error',
201→        code: 'missing_required_field',
202→        message: "The 'action' field is required.",
203→        param: 'action',
204→      });
205→    }
206→    if (!event.actor?.id) {
207→      throw new LogSealError({
208→        type: 'validation_error',
209→        code: 'missing_required_field',
210→        message: "The 'actor.id' field is required.",
211→        param: 'actor.id',
212→      });
213→    }
214→    if (!event.organizationId) {
215→      throw new LogSealError({
216→        type: 'validation_error',
217→        code: 'missing_required_field',
218→        message: "The 'organizationId' field is required.",
219→        param: 'organizationId',
220→      });
221→    }
222→  }
223→
224→  private formatEvent(event: EmitEventInput): Record<string, unknown> {
225→    return {
226→      action: event.action,
227→      organization_id: event.organizationId,
228→      actor: {
229→        id: event.actor.id,
230→        type: event.actor.type,
231→        name: event.actor.name,
232→        email: event.actor.email,
233→        metadata: event.actor.metadata,
234→      },
235→      targets: event.targets?.map((t) => ({
236→        type: t.type,
237→        id: t.id,
238→        name: t.name,
239→        metadata: t.metadata,
240→      })),
241→      metadata: event.metadata,
242→      context: event.context
243→        ? {
244→            ip_address: event.context.ipAddress,
245→            user_agent: event.context.userAgent,
246→            request_id: event.context.requestId,
247→          }
248→        : undefined,
249→      occurred_at: toISOString(event.occurredAt),
250→      idempotency_key: event.idempotencyKey,
251→    };
252→  }
253→
254→  /** @internal */
255→  async request<T>(
256→    method: string,
257→    path: string,
258→    body?: unknown,
259→    retryCount = 0
260→  ): Promise<T> {
261→    const url = `${this.baseUrl}${path}`;
262→
263→    const response = await fetch(url, {
264→      method,
