  1→import { createHash } from 'crypto';
  2→
  3→/**
  4→ * Compute SHA-256 hash of a string
  5→ */
  6→export function sha256(input: string): string {
  7→  return createHash('sha256').update(input).digest('hex');
  8→}
  9→
 10→/**
 11→ * Canonicalize an object for hashing (deterministic JSON with sorted keys)
 12→ */
 13→export function canonicalize(data: Record<string, unknown>): string {
 14→  return JSON.stringify(data, Object.keys(data).sort());
 15→}
 16→
 17→/**
 18→ * Data structure for computing event hash
 19→ */
 20→export interface EventForHashing {
 21→  action: string;
 22→  actor: Record<string, unknown>;
 23→  targets: Record<string, unknown>[];
 24→  metadata: Record<string, unknown>;
 25→  occurred_at: string;
 26→  organization_id: string;
 27→  sequence_number: number;
 28→}
 29→
 30→/**
 31→ * Compute the hash chain hash for an audit event
 32→ * This links each event to its predecessor, creating a tamper-evident chain
 33→ */
 34→export function computeEventHash(
 35→  previousHash: string | null,
 36→  eventData: EventForHashing
 37→): string {
 38→  const canonical = canonicalize(eventData as unknown as Record<string, unknown>);
 39→  const input = (previousHash ?? 'GENESIS') + ':' + canonical;
 40→  return sha256(input);
 41→}
 42→
 43→/**
 44→ * Compute skip-list offsets for a given sequence number.
 45→ * Returns offsets [1, 2, 4, 8, ...] where seq - offset >= 1.
 46→ */
 47→export function computeSkipOffsets(sequenceNumber: number): number[] {
 48→  const offsets: number[] = [];
 49→  let offset = 1;
 50→  while (sequenceNumber - offset >= 1) {
 51→    offsets.push(offset);
 52→    offset *= 2;
 53→  }
 54→  return offsets;
 55→}
 56→
 57→/**
 58→ * Compute the optimal skip-list verification path from fromSeq to toSeq.
 59→ * Returns an array of sequence numbers to check, enabling O(log n) range verification.
 60→ */
 61→export function computeSkipVerificationPath(fromSeq: number, toSeq: number): number[] {
 62→  if (fromSeq >= toSeq) return [fromSeq];
 63→
 64→  const path: number[] = [toSeq];
 65→  let current = toSeq;
 66→
 67→  while (current > fromSeq) {
 68→    // Find the largest power-of-2 offset that doesn't overshoot fromSeq
 69→    const offsets = computeSkipOffsets(current);
 70→    let jumped = false;
 71→    for (let i = offsets.length - 1; i >= 0; i--) {
 72→      const target = current - offsets[i];
 73→      if (target >= fromSeq) {
 74→        current = target;
 75→        path.push(current);
 76→        jumped = true;
 77→        break;
 78→      }
 79→    }
 80→    if (!jumped) break;
 81→  }
 82→
 83→  return path.reverse();
 84→}
 85→
 86→/**
 87→ * Compute HMAC-SHA256 signature for webhook payloads
 88→ */
 89→export function computeWebhookSignature(payload: string, secret: string): string {
 90→  const hmac = createHash('sha256');
 91→  hmac.update(secret);
 92→  hmac.update(payload);
 93→  return 'sha256=' + hmac.digest('hex');
 94→}
 95→
 96→/**
 97→ * Verify a webhook signature using timing-safe comparison
 98→ */
 99→export function verifyWebhookSignature(
100→  payload: string,
101→  signature: string,
102→  secret: string
103→): boolean {
104→  const expected = computeWebhookSignature(payload, secret);
105→
106→  // Timing-safe comparison to prevent timing attacks
107→  if (signature.length !== expected.length) {
108→    return false;
109→  }
110→
111→  let result = 0;
112→  for (let i = 0; i < signature.length; i++) {
113→    result |= signature.charCodeAt(i) ^ expected.charCodeAt(i);
114→  }
115→  return result === 0;
116→}
