import { eq } from 'drizzle-orm';
import { createDb, type Database } from '../index.js';
import { dataConnections } from '../schema/index.js';
import { PostgresDataStore } from './postgres.js';
import type { DataStore } from './interface.js';

const HEALTH_CHECK_INTERVAL_MS = 60_000; // 1 minute
const MAX_FAILURES_BEFORE_UNHEALTHY = 3;

interface ManagedConnection {
  dataStore: DataStore;
  db: Database;
  failureCount: number;
  schemaInitialized: boolean;
}

export interface DecryptFn {
  (data: { ciphertext: string; iv: string; authTag: string }): string;
}

/**
 * DataStoreManager — resolves accountId to the correct DataStore instance.
 * Maintains a pool of customer DataStore connections for BYOD accounts.
 */
export class DataStoreManager {
  private connections = new Map<string, ManagedConnection>();
  private healthCheckTimer: ReturnType<typeof setInterval> | null = null;
  private defaultDataStore: DataStore;

  constructor(
    private mainDb: Database,
    private decryptFn: DecryptFn,
    defaultDataStore?: DataStore
  ) {
    this.defaultDataStore = defaultDataStore ?? new PostgresDataStore(mainDb);
  }

  /**
   * Get the DataStore for an account.
   * If the account has a BYOD connection, returns a customer-specific DataStore.
   * Otherwise returns the default (main DB) DataStore.
   */
  async getDataStore(accountId: string): Promise<DataStore> {
    // Check if we already have a cached connection
    const cached = this.connections.get(accountId);
    if (cached) {
      return cached.dataStore;
    }

    // Look up data_connections for this account
    const [connection] = await this.mainDb
      .select()
      .from(dataConnections)
      .where(eq(dataConnections.accountId, accountId))
      .limit(1);

    if (!connection || connection.status === 'disabled') {
      return this.defaultDataStore;
    }

    // Decrypt the connection string and create a new DataStore
    const connectionString = this.decryptFn({
      ciphertext: connection.encryptedConnectionString,
      iv: connection.iv,
      authTag: connection.authTag,
    });

    const db = createDb(connectionString);
    const dataStore = new PostgresDataStore(db);

    // Initialize schema on first connection
    await dataStore.setupSchema();

    this.connections.set(accountId, { dataStore, db, failureCount: 0, schemaInitialized: true });

    return dataStore;
  }

  /**
   * Get the default DataStore (main DB).
   */
  getDefaultDataStore(): DataStore {
    return this.defaultDataStore;
  }

  /**
   * Check if an account has a BYOD connection configured.
   */
  async hasByodConnection(accountId: string): Promise<boolean> {
    const [connection] = await this.mainDb
      .select({ id: dataConnections.id })
      .from(dataConnections)
      .where(eq(dataConnections.accountId, accountId))
      .limit(1);
    return !!connection;
  }

  /**
   * Invalidate a cached connection (e.g., when connection is updated/deleted).
   */
  evictConnection(accountId: string): void {
    this.connections.delete(accountId);
  }

  /**
   * Run a single health-check pass over all active connections.
   */
  async runHealthChecks(): Promise<void> {
    for (const [accountId, conn] of this.connections) {
      try {
        const healthy = await conn.dataStore.healthCheck();
        if (healthy) {
          conn.failureCount = 0;
        } else {
          conn.failureCount++;
        }
      } catch {
        conn.failureCount++;
      }

      if (conn.failureCount >= MAX_FAILURES_BEFORE_UNHEALTHY) {
        // Mark as unhealthy in DB
        await this.mainDb
          .update(dataConnections)
          .set({ status: 'unhealthy', lastHealthCheck: new Date() })
          .where(eq(dataConnections.accountId, accountId));
      } else {
        await this.mainDb
          .update(dataConnections)
          .set({ status: 'active', lastHealthCheck: new Date() })
          .where(eq(dataConnections.accountId, accountId));
      }
    }
  }

  /**
   * Start periodic health checks for all active connections.
   */
  startHealthChecks(): void {
    if (this.healthCheckTimer) return;

    this.healthCheckTimer = setInterval(() => {
      this.runHealthChecks();
    }, HEALTH_CHECK_INTERVAL_MS);
  }

  /**
   * Stop health checks and close all connections.
   */
  async close(): Promise<void> {
    if (this.healthCheckTimer) {
      clearInterval(this.healthCheckTimer);
      this.healthCheckTimer = null;
    }
    for (const [, conn] of this.connections) {
      await conn.dataStore.close();
    }
    this.connections.clear();
  }
}

