import { describe, vi, afterEach } from 'vitest';
import { test, expect } from '../../fixtures.js';
import { DataStoreManager } from '@logseal/database/datastore';
import { dataConnections, eq } from '@logseal/database';
import {
  createTestPlan,
} from '../../helpers.js';
import { subscriptions } from '@logseal/database';
import type { DataStore } from '@logseal/database/datastore';

/**
 * Creates a mock DataStore that can be toggled between healthy/unhealthy.
 */
function createMockDataStore(healthy = true) {
  let isHealthy = healthy;
  const store: DataStore = {
    insertEvent: vi.fn(),
    getEventById: vi.fn(),
    getEvents: vi.fn(),
    getLastEventForChain: vi.fn(),
    getDistinctActions: vi.fn(),
    getEventsByIdempotencyKey: vi.fn(),
    getChainBatch: vi.fn(),
    getEventBySequenceNumber: vi.fn(),
    getEventsBySequenceNumbers: vi.fn(),
    getFullEventBatch: vi.fn(),
    insertOrganization: vi.fn(),
    getOrganizationByExternalId: vi.fn(),
    getOrganizationById: vi.fn(),
    getOrganizations: vi.fn(),
    getOrganizationsByExternalIds: vi.fn(),
    updateOrganization: vi.fn(),
    deleteOrganization: vi.fn(),
    setupSchema: vi.fn(),
    healthCheck: vi.fn(async () => isHealthy),
    close: vi.fn(),
  };
  return {
    store,
    setHealthy: (h: boolean) => { isHealthy = h; },
  };
}

describe('DataStoreManager health checks', () => {
  afterEach(() => {
    vi.useRealTimers();
  });

  test('startHealthChecks is idempotent — calling twice does not create two intervals', async ({ db }) => {
    const manager = new DataStoreManager(db, () => 'dummy');

    manager.startHealthChecks();
    manager.startHealthChecks(); // second call should be a no-op

    // If it weren't idempotent, close() would only clear one timer.
    // We verify no error and the manager closes cleanly.
    await manager.close();
  });

  test('marks connection unhealthy after 3 consecutive failures', async ({
    db,
    testAccount,
  }) => {
    // Set up a business plan with byod
    const plan = await createTestPlan(db, {
      name: 'Business HC',
      slug: `business-hc-${Date.now()}`,
      entitlements: {
        eventsPerMonth: -1,
        organizations: -1,
        apiKeys: -1,
        webhooks: -1,
        exports: -1,
        retentionDays: 1825,
        features: ['byod'],
      },
    });

    await db
      .update(subscriptions)
      .set({ planId: plan.id })
      .where(eq(subscriptions.accountId, testAccount.account.id));

    // Insert a data_connection row directly
    await db.insert(dataConnections).values({
      accountId: testAccount.account.id,
      encryptedConnectionString: 'fake',
      iv: 'fake',
      authTag: 'fake',
      status: 'active',
    });

    // Create a mock DataStore that always fails
    const { store: failingStore } = createMockDataStore(false);
    (failingStore.healthCheck as ReturnType<typeof vi.fn>).mockRejectedValue(new Error('connection refused'));

    // Create manager with a custom default store (won't matter since we inject directly)
    const manager = new DataStoreManager(db, () => 'dummy');

    // Inject the mock connection into the manager's internal map
    const connections = (manager as any).connections as Map<string, any>;
    connections.set(testAccount.account.id, {
      dataStore: failingStore,
      db: null,
      failureCount: 0,
      schemaInitialized: true,
    });

    // Run 3 consecutive health check passes (simulates 3 intervals)
    for (let i = 0; i < 3; i++) {
      await manager.runHealthChecks();
    }

    // Check that the DB row was updated to unhealthy
    const [row] = await db
      .select()
      .from(dataConnections)
      .where(eq(dataConnections.accountId, testAccount.account.id))
      .limit(1);

    expect(row.status).toBe('unhealthy');
    expect(row.lastHealthCheck).not.toBeNull();

    await manager.close();
  });

  test('successful check resets failure count and marks active', async ({
    db,
    testAccount,
  }) => {
    const plan = await createTestPlan(db, {
      name: 'Business Reset',
      slug: `business-reset-${Date.now()}`,
      entitlements: {
        eventsPerMonth: -1,
        organizations: -1,
        apiKeys: -1,
        webhooks: -1,
        exports: -1,
        retentionDays: 1825,
        features: ['byod'],
      },
    });

    await db
      .update(subscriptions)
      .set({ planId: plan.id })
      .where(eq(subscriptions.accountId, testAccount.account.id));

    await db.insert(dataConnections).values({
      accountId: testAccount.account.id,
      encryptedConnectionString: 'fake',
      iv: 'fake',
      authTag: 'fake',
      status: 'active',
    });

    const { store: mockStore, setHealthy } = createMockDataStore(false);
    (mockStore.healthCheck as ReturnType<typeof vi.fn>).mockRejectedValue(new Error('down'));

    const manager = new DataStoreManager(db, () => 'dummy');
    const connections = (manager as any).connections as Map<string, any>;
    connections.set(testAccount.account.id, {
      dataStore: mockStore,
      db: null,
      failureCount: 0,
      schemaInitialized: true,
    });

    // 2 failures (not yet unhealthy)
    await manager.runHealthChecks();
    await manager.runHealthChecks();

    // Now recover — make healthCheck return true
    (mockStore.healthCheck as ReturnType<typeof vi.fn>).mockResolvedValue(true);
    setHealthy(true);

    await manager.runHealthChecks();

    // Should be active, failure count reset
    const [row] = await db
      .select()
      .from(dataConnections)
      .where(eq(dataConnections.accountId, testAccount.account.id))
      .limit(1);

    expect(row.status).toBe('active');

    const conn = connections.get(testAccount.account.id);
    expect(conn.failureCount).toBe(0);

    await manager.close();
  });

  test('close() stops the health check timer', async ({ db }) => {
    vi.useFakeTimers();

    const manager = new DataStoreManager(db, () => 'dummy');
    manager.startHealthChecks();

    await manager.close();

    // The private timer should be null after close
    expect((manager as any).healthCheckTimer).toBeNull();
    // connections map should be cleared
    expect((manager as any).connections.size).toBe(0);
  });
});

