/**
 * Get the DataStore for an account.
 * If the account has a BYOD connection, returns a customer-specific DataStore.
 * Otherwise returns the default (main DB) DataStore.
 */
async getDataStore(accountId: string): Promise<DataStore> {
  // Check if we already have a cached connection
  const cached = this.connections.get(accountId);
  if (cached) {
    return cached.dataStore;
  }

  // Look up data_connections for this account
  const [connection] = await this.mainDb
    .select()
    .from(dataConnections)
    .where(eq(dataConnections.accountId, accountId))
    .limit(1);

  if (!connection || connection.status === 'disabled') {
    return this.defaultDataStore;
  }

  // Decrypt the connection string and create a new DataStore
  const connectionString = this.decryptFn({
    ciphertext: connection.encryptedConnectionString,
    iv: connection.iv,
    authTag: connection.authTag,
  });

  const db = createDb(connectionString);
  const dataStore = new PostgresDataStore(db);

  // Initialize schema on first connection
  await dataStore.setupSchema();

  this.connections.set(accountId, { dataStore, db, failureCount: 0, schemaInitialized: true });

  return dataStore;
}

