import { describe } from 'vitest';
import { test, expect } from '../../fixtures.js';
import { createTestOrganization, createTestEvent } from '../../helpers.js';
import { DataStoreManager, PostgresDataStore } from '@logseal/database/datastore';
import { dataConnections } from '@logseal/database';
import { encrypt, decrypt } from '@logseal/utils';

describe('BYOD DataStore routing', () => {
  test('without BYOD: DataStoreManager returns default DataStore', async ({
    db,
    testAccount,
  }) => {
    const manager = new DataStoreManager(db, decrypt);

    const store = await manager.getDataStore(testAccount.account.id);

    // Should be a PostgresDataStore (the default)
    expect(store).toBeInstanceOf(PostgresDataStore);

    // Should be the same as the default
    expect(store).toBe(manager.getDefaultDataStore());

    await manager.close();
  });

  test('with BYOD configured: DataStoreManager returns customer DataStore', async ({
    db,
    testAccount,
  }) => {
    // Insert a data_connection record pointing at the SAME test DB
    // (In production this would point to the customer's own DB)
    const databaseUrl = process.env.DATABASE_URL!;
    const encrypted = encrypt(databaseUrl);

    await db.insert(dataConnections).values({
      accountId: testAccount.account.id,
      encryptedConnectionString: encrypted.ciphertext,
      iv: encrypted.iv,
      authTag: encrypted.authTag,
      status: 'active',
    });

    const manager = new DataStoreManager(db, decrypt);

    const store = await manager.getDataStore(testAccount.account.id);

    // Should be a PostgresDataStore, but NOT the default one
    expect(store).toBeInstanceOf(PostgresDataStore);
    expect(store).not.toBe(manager.getDefaultDataStore());

    await manager.close();
  });

  test('DataStore health check works', async ({
    db,
    testAccount,
  }) => {
    const manager = new DataStoreManager(db, decrypt);
    const store = await manager.getDataStore(testAccount.account.id);

    const healthy = await store.healthCheck();
    expect(healthy).toBe(true);

    await manager.close();
  });

  test('DataStore can insert and retrieve events', async ({
    db,
    testAccount,
  }) => {
    const manager = new DataStoreManager(db, decrypt);
    const store = manager.getDefaultDataStore();

    const org = await createTestOrganization(db, testAccount.account.id, {
      externalId: `byod-route-test-${Date.now()}`,
      environment: 'test',
    });

    const event = await createTestEvent(db, testAccount.account.id, org.id, {
      action: 'byod.test',
      sequenceNumber: 1,
      previousHash: null,
    });

    // Read back via DataStore
    const retrieved = await store.getEventById(event.id, testAccount.account.id, 'test');

    expect(retrieved).toBeDefined();
    expect(retrieved!.id).toBe(event.id);
    expect(retrieved!.action).toBe('byod.test');

    await manager.close();
  });

  test('DataStore chain tip returns latest event', async ({
    db,
    testAccount,
  }) => {
    const manager = new DataStoreManager(db, decrypt);
    const store = manager.getDefaultDataStore();

    const org = await createTestOrganization(db, testAccount.account.id, {
      externalId: `byod-chain-${Date.now()}`,
      environment: 'test',
    });

    const event1 = await createTestEvent(db, testAccount.account.id, org.id, {
      action: 'chain.first',
      sequenceNumber: 1,
      previousHash: null,
    });

    const event2 = await createTestEvent(db, testAccount.account.id, org.id, {
      action: 'chain.second',
      sequenceNumber: 2,
      previousHash: event1.eventHash,
    });

    const tip = await store.getLastEventForChain(org.id, 'test');

    expect(tip).toBeDefined();
    expect(tip!.eventHash).toBe(event2.eventHash);
    expect(tip!.sequenceNumber).toBe(2);

    await manager.close();
  });

  test('disabled BYOD connection falls back to default DataStore', async ({
    db,
    testAccount,
  }) => {
    const databaseUrl = process.env.DATABASE_URL!;
    const encrypted = encrypt(databaseUrl);

    await db.insert(dataConnections).values({
      accountId: testAccount.account.id,
      encryptedConnectionString: encrypted.ciphertext,
      iv: encrypted.iv,
      authTag: encrypted.authTag,
      status: 'disabled',
    });

    const manager = new DataStoreManager(db, decrypt);
    const store = await manager.getDataStore(testAccount.account.id);

    // Disabled connection should fall back to default
    expect(store).toBe(manager.getDefaultDataStore());

    await manager.close();
  });

  test('DataStore eviction clears cached connection', async ({
    db,
    testAccount,
  }) => {
    const databaseUrl = process.env.DATABASE_URL!;
    const encrypted = encrypt(databaseUrl);

    await db.insert(dataConnections).values({
      accountId: testAccount.account.id,
      encryptedConnectionString: encrypted.ciphertext,
      iv: encrypted.iv,
      authTag: encrypted.authTag,
      status: 'active',
    });

    const manager = new DataStoreManager(db, decrypt);

    // Get once — will be cached
    const store1 = await manager.getDataStore(testAccount.account.id);
    expect(store1).not.toBe(manager.getDefaultDataStore());

    // Evict
    manager.evictConnection(testAccount.account.id);

    // Get again — should create a new connection
    const store2 = await manager.getDataStore(testAccount.account.id);
    expect(store2).not.toBe(store1); // Different instance

    await manager.close();
  });

  test('hasByodConnection correctly reports connection presence', async ({
    db,
    testAccount,
  }) => {
    const manager = new DataStoreManager(db, decrypt);

    // No connection yet
    expect(await manager.hasByodConnection(testAccount.account.id)).toBe(false);

    // Add connection
    const databaseUrl = process.env.DATABASE_URL!;
    const encrypted = encrypt(databaseUrl);

    await db.insert(dataConnections).values({
      accountId: testAccount.account.id,
      encryptedConnectionString: encrypted.ciphertext,
      iv: encrypted.iv,
      authTag: encrypted.authTag,
      status: 'active',
    });

    expect(await manager.hasByodConnection(testAccount.account.id)).toBe(true);

    await manager.close();
  });
});

