      expect(url).toBe('https://api.logseal.dev/v1/events/evt_123');
      expect(options.method).toBe('GET');

      await client.shutdown();
    });

    it('organizations.create() sends correct POST request', async () => {
      const fetchMock = mockFetch({
        json: () =>
          Promise.resolve({
            id: 'org_123',
