  1→import { FastifyPluginAsync } from 'fastify';
  2→import { z } from 'zod';
  3→import { eq } from 'drizzle-orm';
  4→import { accounts } from '@logseal/database';
  5→import { errors, sha256 } from '@logseal/utils';
  6→import { verifyPassword } from '../utils/password.js';
  7→import {
  8→  encryptTotpSecret,
  9→  decryptTotpSecret,
 10→  generateTotpSecret,
 11→  generateOtpauthUri,
 12→  verifyTotpCode,
 13→  generateBackupCodes,
 14→  hashBackupCodes,
 15→  verifyBackupCode,
 16→} from '../utils/totp.js';
 17→import { completeTwoFactorVerification, SESSION_COOKIE_NAME } from '../utils/sessions.js';
 18→
 19→const verifySetupSchema = z.object({
 20→  code: z.string().length(6),
 21→});
 22→
 23→const disableSchema = z.object({
 24→  code: z.string().min(1),
 25→  password: z.string().min(1),
 26→});
 27→
 28→const challengeSchema = z.object({
 29→  code: z.string().min(1),
 30→  is_backup_code: z.boolean().optional().default(false),
 31→});
 32→
 33→export const twoFactorRoutes: FastifyPluginAsync = async (fastify) => {
 34→  // POST /auth/2fa/setup — Generate secret + otpauth URI
 35→  fastify.post('/2fa/setup', async (request, reply) => {
 36→    if (!request.session) {
 37→      throw errors.sessionExpired();
 38→    }
 39→
 40→    const [account] = await fastify.db
 41→      .select()
 42→      .from(accounts)
 43→      .where(eq(accounts.id, request.session.accountId))
 44→      .limit(1);
 45→
 46→    if (!account) {
 47→      throw errors.sessionExpired();
 48→    }
 49→
 50→    if (account.totpEnabled) {
 51→      throw errors.twoFactorAlreadyEnabled();
 52→    }
 53→
 54→    const secret = generateTotpSecret();
 55→    const otpauthUri = generateOtpauthUri(secret, account.email);
 56→    const encryptedSecret = encryptTotpSecret(secret);
 57→
 58→    // Store encrypted secret (not yet enabled)
 59→    await fastify.db
 60→      .update(accounts)
 61→      .set({ totpSecret: encryptedSecret, updatedAt: new Date() })
 62→      .where(eq(accounts.id, account.id));
 63→
 64→    return reply.send({
 65→      secret,
 66→      otpauth_uri: otpauthUri,
 67→      object: 'two_factor_setup',
 68→    });
 69→  });
 70→
 71→  // POST /auth/2fa/verify-setup — Verify TOTP code and enable 2FA
 72→  fastify.post('/2fa/verify-setup', async (request, reply) => {
 73→    if (!request.session) {
 74→      throw errors.sessionExpired();
 75→    }
 76→
 77→    const input = verifySetupSchema.parse(request.body);
 78→
 79→    const [account] = await fastify.db
 80→      .select()
 81→      .from(accounts)
 82→      .where(eq(accounts.id, request.session.accountId))
 83→      .limit(1);
 84→
 85→    if (!account) {
 86→      throw errors.sessionExpired();
 87→    }
 88→
 89→    if (account.totpEnabled) {
 90→      throw errors.twoFactorAlreadyEnabled();
 91→    }
 92→
 93→    if (!account.totpSecret) {
 94→      throw errors.twoFactorNotEnabled();
 95→    }
 96→
 97→    const secret = decryptTotpSecret(account.totpSecret);
 98→    const valid = verifyTotpCode(secret, input.code);
 99→
100→    if (!valid) {
101→      throw errors.invalidTwoFactorCode();
102→    }
103→
104→    // Generate backup codes
105→    const backupCodes = generateBackupCodes(8);
106→    const hashedCodes = await hashBackupCodes(backupCodes);
107→
108→    // Enable 2FA
109→    await fastify.db
110→      .update(accounts)
111→      .set({
112→        totpEnabled: true,
113→        backupCodes: JSON.stringify(hashedCodes),
114→        totpEnabledAt: new Date(),
115→        updatedAt: new Date(),
116→      })
117→      .where(eq(accounts.id, account.id));
118→
119→    return reply.send({
120→      backup_codes: backupCodes,
121→      object: 'two_factor_verify_setup',
122→    });
123→  });
124→
125→  // POST /auth/2fa/disable — Disable 2FA (requires TOTP/backup code + password)
126→  fastify.post('/2fa/disable', async (request, reply) => {
127→    if (!request.session) {
128→      throw errors.sessionExpired();
129→    }
130→
131→    const input = disableSchema.parse(request.body);
132→
133→    const [account] = await fastify.db
134→      .select()
135→      .from(accounts)
136→      .where(eq(accounts.id, request.session.accountId))
137→      .limit(1);
138→
139→    if (!account) {
140→      throw errors.sessionExpired();
141→    }
142→
143→    if (!account.totpEnabled) {
144→      throw errors.twoFactorNotEnabled();
145→    }
146→
147→    // Verify password
148→    if (!account.passwordHash) {
149→      throw errors.invalidCredentials();
150→    }
151→    const validPassword = await verifyPassword(account.passwordHash, input.password);
152→    if (!validPassword) {
153→      throw errors.invalidCredentials();
154→    }
155→
156→    // Verify TOTP code or backup code
157→    // TOTP codes are always 6 digits; anything else is a backup code
158→    let verified = false;
159→    if (/^\d{6}$/.test(input.code)) {
160→      const secret = decryptTotpSecret(account.totpSecret!);
161→      verified = verifyTotpCode(secret, input.code);
162→    }
163→
164→    if (!verified) {
165→      // Try as backup code
166→      const hashedCodes: string[] = JSON.parse(account.backupCodes || '[]');
167→      const backupResult = await verifyBackupCode(input.code, hashedCodes);
168→      if (!backupResult.valid) {
169→        throw errors.invalidTwoFactorCode();
170→      }
171→    }
172→
173→    // Clear all 2FA fields
174→    await fastify.db
175→      .update(accounts)
176→      .set({
177→        totpSecret: null,
178→        totpEnabled: false,
179→        backupCodes: null,
180→        totpEnabledAt: null,
181→        updatedAt: new Date(),
182→      })
183→      .where(eq(accounts.id, account.id));
184→
185→    return reply.send({ success: true });
186→  });
187→
188→  // POST /auth/2fa/challenge — Verify 2FA during login
189→  fastify.post('/2fa/challenge', async (request, reply) => {
190→    if (!request.session) {
191→      throw errors.sessionExpired();
192→    }
193→
194→    if (!request.session.twoFactorPending) {
195→      return reply.send({ success: true });
196→    }
197→
198→    const input = challengeSchema.parse(request.body);
199→
200→    const [account] = await fastify.db
201→      .select()
202→      .from(accounts)
203→      .where(eq(accounts.id, request.session.accountId))
204→      .limit(1);
205→
206→    if (!account || !account.totpEnabled || !account.totpSecret) {
207→      throw errors.sessionExpired();
208→    }
209→
210→    if (input.is_backup_code) {
211→      // Verify backup code
212→      const hashedCodes: string[] = JSON.parse(account.backupCodes || '[]');
213→      const result = await verifyBackupCode(input.code, hashedCodes);
214→      if (!result.valid) {
215→        throw errors.invalidTwoFactorCode();
216→      }
217→
218→      // Consume the used backup code
219→      hashedCodes.splice(result.index, 1);
220→      await fastify.db
221→        .update(accounts)
222→        .set({ backupCodes: JSON.stringify(hashedCodes), updatedAt: new Date() })
223→        .where(eq(accounts.id, account.id));
224→    } else {
225→      // Verify TOTP code
226→      const secret = decryptTotpSecret(account.totpSecret);
227→      const valid = verifyTotpCode(secret, input.code);
228→      if (!valid) {
229→        throw errors.invalidTwoFactorCode();
230→      }
231→    }
232→
233→    // Complete 2FA verification — get tokenHash from cookie
234→    const sessionToken = request.cookies?.[SESSION_COOKIE_NAME];
235→    if (!sessionToken) {
236→      throw errors.sessionExpired();
237→    }
238→    const tokenHash = sha256(sessionToken);
239→
240→    await completeTwoFactorVerification(
241→      fastify.db,
242→      fastify.redis,
243→      request.session.sessionId,
244→      tokenHash
245→    );
246→
247→    return reply.send({ success: true });
248→  });
249→};
