  1→import type { FastifyPluginAsync } from 'fastify';
  2→import fp from 'fastify-plugin';
  3→import { eq, and, isNull, gt } from 'drizzle-orm';
  4→import { apiKeys, viewerTokens, accounts } from '@logseal/database';
  5→import { sha256, errors, getEnvironmentFromKey } from '@logseal/utils';
  6→import { validateSession, SESSION_COOKIE_NAME } from '../utils/sessions.js';
  7→
  8→// Routes that don't require authentication
  9→const PUBLIC_ROUTES = [
 10→  '/health',
 11→  '/auth/signup',
 12→  '/auth/login',
 13→  '/auth/verify-email',
 14→  '/auth/forgot-password',
 15→  '/auth/reset-password',
 16→  '/billing/webhooks',
 17→  '/billing/plans',
 18→];
 19→
 20→// Routes accessible during 2FA-pending state
 21→const TWO_FACTOR_PENDING_ROUTES = [
 22→  '/auth/2fa/challenge',
 23→  '/auth/logout',
 24→];
 25→
 26→const authPluginImpl: FastifyPluginAsync = async (fastify) => {
 27→  // Add timing to all requests
 28→  fastify.addHook('onRequest', async (request) => {
 29→    request.startTime = Date.now();
 30→  });
 31→
 32→  // Auth hook for protected routes
 33→  fastify.addHook('preHandler', async (request, _reply) => {
 34→    // Skip auth for public routes and docs
 35→    const pathname = request.url.split('?')[0];
 36→    if (PUBLIC_ROUTES.some((route) => pathname === route || pathname.startsWith('/docs'))) {
 37→      return;
 38→    }
 39→
 40→    // Check for session cookie first (dashboard auth)
 41→    const sessionToken = request.cookies?.[SESSION_COOKIE_NAME];
 42→    if (sessionToken) {
 43→      await authenticateSession(fastify, request, sessionToken);
 44→
 45→      // Block 2FA-pending sessions from accessing non-2FA routes
 46→      if (
 47→        request.session?.twoFactorPending &&
 48→        !TWO_FACTOR_PENDING_ROUTES.some((route) => pathname === route)
 49→      ) {
 50→        throw errors.twoFactorPending();
 51→      }
 52→
 53→      return;
 54→    }
 55→
 56→    // Check for Authorization header
 57→    const authHeader = request.headers.authorization;
 58→    if (!authHeader || !authHeader.startsWith('Bearer ')) {
 59→      throw errors.missingApiKey();
 60→    }
 61→
 62→    const token = authHeader.slice(7);
 63→
 64→    // Check if it's a viewer token
 65→    if (token.startsWith('vtk_')) {
 66→      await authenticateViewerToken(fastify, request, token);
 67→      return;
 68→    }
 69→
 70→    // Otherwise, it's an API key
 71→    await authenticateApiKey(fastify, request, token);
 72→  });
 73→};
 74→
 75→async function authenticateSession(fastify: any, request: any, token: string) {
 76→  const sessionData = await validateSession(fastify.db, fastify.redis, token);
 77→
 78→  if (!sessionData) {
 79→    throw errors.sessionExpired();
 80→  }
 81→
 82→  // Get account details including status
 83→  const [account] = await fastify.db
 84→    .select({
 85→      id: accounts.id,
 86→      accountStatus: accounts.accountStatus,
 87→      isSuperAdmin: accounts.isSuperAdmin,
 88→    })
 89→    .from(accounts)
 90→    .where(eq(accounts.id, sessionData.accountId))
 91→    .limit(1);
 92→
 93→  if (!account) {
 94→    throw errors.sessionExpired();
 95→  }
 96→
 97→  // For session auth, use the environment from header or default to 'test'
 98→  const environmentHeader = request.headers['x-logseal-environment'];
 99→  const environment =
100→    environmentHeader === 'live' || environmentHeader === 'test' ? environmentHeader : 'test';
101→
102→  request.session = {
103→    sessionId: sessionData.sessionId,
104→    accountId: sessionData.accountId,
105→    accountStatus: account.accountStatus,
106→    isSuperAdmin: account.isSuperAdmin,
107→    twoFactorPending: sessionData.twoFactorPending,
108→  };
109→
110→  // Also set account for compatibility with existing routes
111→  request.account = {
112→    id: account.id,
113→    accountId: account.id,
114→    environment,
115→    keyId: null, // No API key for session auth
116→    accountStatus: account.accountStatus,
117→  };
118→}
119→
120→async function authenticateApiKey(fastify: any, request: any, key: string) {
121→  const environment = getEnvironmentFromKey(key);
122→  if (!environment) {
123→    throw errors.invalidApiKey();
124→  }
125→
126→  const keyHash = sha256(key);
127→
128→  // Check cache first
129→  const cacheKey = `apikey:${keyHash}`;
130→  const cached = await fastify.redis.get(cacheKey);
131→
132→  if (cached) {
133→    request.account = JSON.parse(cached);
134→    return;
135→  }
136→
137→  // Query database - also get account status
138→  const [result] = await fastify.db
139→    .select({
140→      id: apiKeys.id,
141→      accountId: apiKeys.accountId,
142→      environment: apiKeys.environment,
143→      accountStatus: accounts.accountStatus,
144→    })
145→    .from(apiKeys)
146→    .innerJoin(accounts, eq(apiKeys.accountId, accounts.id))
147→    .where(and(eq(apiKeys.keyHash, keyHash), isNull(apiKeys.revokedAt)))
148→    .limit(1);
149→
150→  if (!result) {
151→    throw errors.invalidApiKey();
152→  }
153→
154→  const accountData = {
155→    id: result.accountId,
156→    accountId: result.accountId,
157→    environment: result.environment,
158→    keyId: result.id,
159→    accountStatus: result.accountStatus,
160→  };
161→
162→  // Cache for 5 minutes
163→  await fastify.redis.set(cacheKey, JSON.stringify(accountData), 'EX', 300);
164→
165→  // Update last used timestamp (async, don't wait)
166→  fastify.db
167→    .update(apiKeys)
168→    .set({ lastUsedAt: new Date() })
169→    .where(eq(apiKeys.id, result.id))
170→    .execute()
171→    .catch((err: Error) => fastify.log.error(err, 'Failed to update API key last used'));
172→
173→  request.account = accountData;
174→}
175→
176→async function authenticateViewerToken(fastify: any, request: any, token: string) {
177→  const tokenHash = sha256(token);
178→
179→  const [result] = await fastify.db
180→    .select()
181→    .from(viewerTokens)
182→    .where(and(eq(viewerTokens.tokenHash, tokenHash), gt(viewerTokens.expiresAt, new Date())))
183→    .limit(1);
184→
185→  if (!result) {
186→    throw errors.expiredViewerToken();
187→  }
188→
189→  request.viewerToken = {
190→    organizationId: result.organizationId,
191→    accountId: result.accountId,
192→    environment: result.environment,
193→  };
194→}
195→
196→// Wrap with fastify-plugin to escape encapsulation
197→// This allows the auth hooks to apply to all routes
198→export const authPlugin = fp(authPluginImpl, {
199→  name: 'auth-plugin',
200→});
