 26→const signupSchema = z.object({
 27→  email: z.string().email(),
 28→  password: z.string().min(8),
 29→  company_name: z.string().optional(),
 30→});
 31→
 32→const loginSchema = z.object({
 33→  email: z.string().email(),
 34→  password: z.string(),
 35→});
 36→
 37→const forgotPasswordSchema = z.object({
 38→  email: z.string().email(),
 39→});
 40→
 41→const resetPasswordSchema = z.object({
 42→  token: z.string(),
 43→  password: z.string().min(8),
 44→});
