271→    const [usage] = await fastify.db
272→      .select()
273→      .from(usageRecords)
274→      .where(
275→        and(
276→          eq(usageRecords.accountId, account.id),
277→          eq(usageRecords.environment, environment),
278→          gt(usageRecords.periodEnd, new Date()),
279→        )
280→      )
281→      .limit(1);
282→
283→    const entitlements = subscription?.plan?.entitlements || {
284→      eventsPerMonth: 0,
285→      organizations: 0,
286→      apiKeys: 0,
287→      webhooks: 0,
288→      exports: 0,
289→      retentionDays: 0,
290→      features: [],
291→    };
292→
293→    return reply.send({
294→      user: {
295→        id: account.id,
296→        email: account.email,
297→        company_name: account.companyName,
298→        email_verified: !!account.emailVerifiedAt,
299→        account_status: account.accountStatus,
300→        schema_enforcement: account.schemaEnforcement,
