302→        totp_enabled: account.totpEnabled,
303→        is_super_admin: account.isSuperAdmin,
304→        created_at: account.createdAt.toISOString(),
305→        object: 'auth_user',
306→      },
307→      subscription: subscription
308→        ? {
309→            id: subscription.subscription.id,
310→            account_id: subscription.subscription.accountId,
