440→
441→    // Generate new verification token
442→    const verificationToken = generateVerificationToken();
443→    const tokenHash = sha256(verificationToken);
444→    const expiresAt = new Date(Date.now() + 24 * 60 * 60 * 1000); // 24 hours
445→
446→    await fastify.db.insert(emailVerifications).values({
447→      accountId: account.id,
448→      tokenHash,
