483→        await sendPasswordResetEmail(account.email, resetToken);
484→      } catch (err) {
485→        fastify.log.error(err, 'Failed to send password reset email');
486→      }
487→    }
488→
489→    // Always return success to prevent email enumeration
490→    return reply.send({ success: true });
491→  });
492→
493→  // POST /auth/reset-password
494→  fastify.post('/reset-password', async (request, reply) => {
495→    const input = resetPasswordSchema.parse(request.body);
496→    const tokenHash = sha256(input.token);
497→
498→    // Find valid reset token
499→    const [reset] = await fastify.db
500→      .select()
501→      .from(passwordResets)
502→      .where(
503→        and(
504→          eq(passwordResets.tokenHash, tokenHash),
505→          isNull(passwordResets.usedAt),
506→          gt(passwordResets.expiresAt, new Date())
507→        )
508→      )
509→      .limit(1);
510→
511→    if (!reset) {
512→      throw errors.invalidToken('reset');
513→    }
514→
515→    // Hash new password
516→    const passwordHash = await hashPassword(input.password);
517→
518→    // Update password
519→    await fastify.db
520→      .update(accounts)
521→      .set({ passwordHash, updatedAt: new Date() })
522→      .where(eq(accounts.id, reset.accountId));
523→
524→    // Mark token as used
525→    await fastify.db
526→      .update(passwordResets)
527→      .set({ usedAt: new Date() })
528→      .where(eq(passwordResets.id, reset.id));
529→
530→    // Invalidate all sessions for security
531→    await invalidateAllSessions(fastify.db, fastify.redis, reset.accountId);
532→
533→    return reply.send({ success: true });
534→  });
535→};
